function syncWebmailNavigationUi() {
  syncHeaderAuthUi();
  refreshMobileTileGrid();
  if (isStandaloneDisplayMode()) return;
  const content = window.__lrocBaseContent || {};
  const links = document.querySelector('.side-nav-links');
  if (!links) return;
  const current = document.body.dataset.page || 'home';
  links.innerHTML = getSiteNavItems(content).map(item => `
    <a class="side-nav-link ${isCurrentNavItem(item.href, current) ? 'active' : ''}" href="${escapeHtml(item.href)}">
      <span class="${getUiIconWrapClass(item, 'nav')}" aria-hidden="true">${renderUiIcon(item, 'nav')}</span>
      <span class="side-nav-copy"><span>${escapeHtml(item.label)}</span><small>${escapeHtml(item.summary || '')}</small></span>
    </a>`).join('');
  links.querySelectorAll('a').forEach(link => {
    link.addEventListener('click', () => {
      if (!isDesktopNavLayout()) setSiteNavOpen(false, { persist: false });
    });
  });
}

