function wireGlobalLoginModal() {
  const modal = document.getElementById('globalLoginModal');
  if (!modal) return;
  const closeBtn = document.getElementById('globalLoginModalClose');
  const usernameInput = document.getElementById('globalLoginUsername');
  const passwordInput = document.getElementById('globalLoginPassword');
  const showPasswordToggle = document.getElementById('globalLoginShowPassword');
  const submitBtn = document.getElementById('globalLoginSubmitBtn');
  const forgotBtn = document.getElementById('globalLoginForgotBtn');
  const backToSignInBtn = document.getElementById('globalLoginBackToSignInBtn');
  const sendResetBtn = document.getElementById('globalLoginSendResetBtn');
  const confirmResetBtn = document.getElementById('globalLoginConfirmResetBtn');
  const notice = document.getElementById('globalLoginNotice');
  const forgotPasswordPanel = document.getElementById('globalLoginForgotPasswordPanel');
  const resetCodeInput = document.getElementById('globalLoginResetCode');
  const resetPasswordInput = document.getElementById('globalLoginResetPassword');
  const showResetPasswordToggle = document.getElementById('globalLoginShowResetPassword');
  const resetPasswordConfirmInput = document.getElementById('globalLoginResetPasswordConfirm');
  const newPasswordPanel = document.getElementById('globalLoginNewPasswordPanel');
  const newPasswordInput = document.getElementById('globalLoginNewPassword');
  const showChallengePasswordToggle = document.getElementById('globalLoginShowChallengePassword');
  const newPasswordConfirmInput = document.getElementById('globalLoginNewPasswordConfirm');
  const completeBtn = document.getElementById('globalLoginCompletePasswordBtn');
  let challenge = null;

  function normaliseUsername(value) {
    return String(value || '').trim().toLowerCase();
  }

  function showNotice(message) {
    const text = String(message || '').trim();
    if (!notice) return;
    notice.textContent = text;
    notice.classList.toggle('hidden', !text);
  }

  function hideNotice() {
    showNotice('');
  }

  function showSignInPanel() {
    forgotPasswordPanel?.classList.add('hidden');
    newPasswordPanel?.classList.add('hidden');
    backToSignInBtn?.classList.add('hidden');
    forgotBtn?.classList.remove('hidden');
    hideNotice();
  }

  function showForgotPasswordPanel() {
    forgotPasswordPanel?.classList.remove('hidden');
    newPasswordPanel?.classList.add('hidden');
    backToSignInBtn?.classList.remove('hidden');
    forgotBtn?.classList.add('hidden');
    hideNotice();
    window.setTimeout(() => usernameInput?.focus(), 0);
  }

  function close() {
    modal.classList.add('hidden');
    document.body.classList.remove('modal-open');
  }
  function open() {
    modal.classList.remove('hidden');
    document.body.classList.add('modal-open');
    window.setTimeout(() => usernameInput?.focus(), 0);
  }

  closeBtn?.addEventListener('click', close);
  modal.addEventListener('click', (event) => {
    if (event.target === modal) close();
  });
  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape' && !modal.classList.contains('hidden')) close();
  });

  window.addEventListener('lroc:open-login-modal', (event) => {
    const returnTo = event?.detail?.returnTo || window.location.href;
    try { window.lrocAuth?.saveReturnTo?.(returnTo); } catch {}
    challenge = null;
    showSignInPanel();
    if (resetCodeInput) resetCodeInput.value = '';
    if (resetPasswordInput) resetPasswordInput.value = '';
    if (resetPasswordConfirmInput) resetPasswordConfirmInput.value = '';
    if (newPasswordInput) newPasswordInput.value = '';
    if (newPasswordConfirmInput) newPasswordConfirmInput.value = '';
    if (showPasswordToggle) { showPasswordToggle.checked = false; if (passwordInput) passwordInput.type = 'password'; }
    if (showResetPasswordToggle) { showResetPasswordToggle.checked = false; if (resetPasswordInput) resetPasswordInput.type = 'password'; if (resetPasswordConfirmInput) resetPasswordConfirmInput.type = 'password'; }
    if (showChallengePasswordToggle) { showChallengePasswordToggle.checked = false; if (newPasswordInput) newPasswordInput.type = 'password'; if (newPasswordConfirmInput) newPasswordConfirmInput.type = 'password'; }
    hideNotice();
    open();
  });

  usernameInput?.addEventListener('blur', () => {
    if (usernameInput) usernameInput.value = normaliseUsername(usernameInput.value);
  });

  showPasswordToggle?.addEventListener('change', () => {
    if (passwordInput) passwordInput.type = showPasswordToggle.checked ? 'text' : 'password';
  });
  showResetPasswordToggle?.addEventListener('change', () => {
    if (resetPasswordInput) resetPasswordInput.type = showResetPasswordToggle.checked ? 'text' : 'password';
    if (resetPasswordConfirmInput) resetPasswordConfirmInput.type = showResetPasswordToggle.checked ? 'text' : 'password';
  });
  showChallengePasswordToggle?.addEventListener('change', () => {
    if (newPasswordInput) newPasswordInput.type = showChallengePasswordToggle.checked ? 'text' : 'password';
    if (newPasswordConfirmInput) newPasswordConfirmInput.type = showChallengePasswordToggle.checked ? 'text' : 'password';
  });

  forgotBtn?.addEventListener('click', () => {
    if (!normaliseUsername(usernameInput?.value || '')) {
      showNotice('Enter your member email address first, then reset your password.');
      usernameInput?.focus();
      return;
    }
    showForgotPasswordPanel();
    hideNotice();
  });

  backToSignInBtn?.addEventListener('click', () => {
    showSignInPanel();
    hideNotice();
  });

  sendResetBtn?.addEventListener('click', async () => {
    const username = normaliseUsername(usernameInput?.value || '');
    if (!username) {
      showNotice('Enter your member email address first.');
      usernameInput?.focus();
      return;
    }
    const original = sendResetBtn.textContent;
    sendResetBtn.disabled = true;
    sendResetBtn.textContent = 'Sending…';
    try {
      await window.lrocAuth.forgotPassword(username);
      showForgotPasswordPanel();
      showNotice('Reset code sent. Check your email, then enter the code and your new password.');
      resetCodeInput?.focus();
    } catch (err) {
      showNotice(`Could not start password reset: ${err.message}`);
    } finally {
      sendResetBtn.disabled = false;
      sendResetBtn.textContent = original;
    }
  });

  confirmResetBtn?.addEventListener('click', async () => {
    const username = normaliseUsername(usernameInput?.value || '');
    const code = (resetCodeInput?.value || '').trim();
    const nextPassword = resetPasswordInput?.value || '';
    const confirmPassword = resetPasswordConfirmInput?.value || '';
    if (!username || !code || !nextPassword) {
      showNotice('Enter your email address, reset code, and new password.');
      return;
    }
    if (nextPassword !== confirmPassword) {
      showNotice('The new passwords do not match.');
      return;
    }
    const original = confirmResetBtn.textContent;
    confirmResetBtn.disabled = true;
    confirmResetBtn.textContent = 'Saving…';
    try {
      await window.lrocAuth.confirmForgotPassword(username, code, nextPassword);
      showSignInPanel();
      if (passwordInput) passwordInput.value = '';
      showNotice('Password updated. Sign in with your new password.');
      passwordInput?.focus();
    } catch (err) {
      showNotice(`Could not reset your password: ${err.message}`);
    } finally {
      confirmResetBtn.disabled = false;
      confirmResetBtn.textContent = original;
    }
  });

  submitBtn?.addEventListener('click', async () => {
    const username = normaliseUsername(usernameInput?.value || '');
    const password = passwordInput?.value || '';
    if (!username || !password) {
      showNotice('Enter your email address and password.');
      return;
    }
    const original = submitBtn.textContent;
    submitBtn.disabled = true;
    submitBtn.textContent = 'Signing in…';
    try {
      const result = await window.lrocAuth.signIn(username, password);
      if (result?.challengeName === 'NEW_PASSWORD_REQUIRED') {
        challenge = result;
        if (newPasswordPanel) newPasswordPanel.classList.remove('hidden');
        hideNotice();
        return;
      }
      const nav = await window.lrocAuth?.redirectAfterLogin?.(window.location.href);
      if (!nav?.redirected) window.location.reload();
    } catch (err) {
      showNotice(`Could not sign in: ${err.message}`);
    } finally {
      submitBtn.disabled = false;
      submitBtn.textContent = original;
    }
  });

  completeBtn?.addEventListener('click', async () => {
    const nextPassword = newPasswordInput?.value || '';
    const confirmPassword = newPasswordConfirmInput?.value || '';
    if (!challenge?.username || !challenge?.session) {
      showNotice('Please sign in again to restart the password change.');
      return;
    }
    if (!nextPassword) {
      showNotice('Enter your new password.');
      return;
    }
    if (nextPassword !== confirmPassword) {
      showNotice('The new passwords do not match.');
      return;
    }
    const original = completeBtn.textContent;
    completeBtn.disabled = true;
    completeBtn.textContent = 'Saving…';
    try {
      await window.lrocAuth.completeNewPassword(challenge.username, nextPassword, challenge.session);
      const nav = await window.lrocAuth?.redirectAfterLogin?.(window.location.href);
      if (!nav?.redirected) window.location.reload();
    } catch (err) {
      showNotice(`Could not set your new password: ${err.message}`);
    } finally {
      completeBtn.disabled = false;
      completeBtn.textContent = original;
    }
  });
}

