async function wireAdminEmailPage() {
  const audienceEl = document.getElementById('adminEmailAudience');
  const subjectEl = document.getElementById('adminEmailSubject');
  const fromPositionEl = document.getElementById('adminEmailFromPosition');
  const messageEl = document.getElementById('adminEmailMessage');
  const testToEl = document.getElementById('adminEmailTestTo');
  const previewBtn = document.getElementById('adminEmailPreviewBtn');
  const sendTestBtn = document.getElementById('adminEmailSendTestBtn');
  const sendBulkBtn = document.getElementById('adminEmailSendBulkBtn');
  const suppressEmailEl = document.getElementById('adminEmailSuppressAddress');
  const suppressReasonEl = document.getElementById('adminEmailSuppressReason');
  const suppressBtn = document.getElementById('adminEmailSuppressBtn');
  const clearBtn = document.getElementById('adminEmailClearSuppressionBtn');
  const notice = document.getElementById('adminEmailNotice');
  const previewBody = document.getElementById('adminEmailPreviewBody');
  if (!audienceEl || !previewBody) return;

  async function loadFromPositions() {
    if (!fromPositionEl) return;
    try {
      const data = await memberApiFetch('/admin/email/positions', { method: 'GET' });
      const current = fromPositionEl.value || '';
      const options = ['<option value="">Use my email address</option>'];
      (data.items || []).forEach(item => {
        const email = item.email_address || '';
        if (!email) return;
        options.push(`<option value="${escapeHtml(item.position_id || '')}">${escapeHtml(item.position_name || 'Position')} &lt;${escapeHtml(email)}&gt;</option>`);
      });
      fromPositionEl.innerHTML = options.join('');
      fromPositionEl.value = current;
    } catch (err) {
      console.warn('Could not load email positions', err);
    }
  }

  function adminEmailPayload(extra = {}) {
    return {
      audience: audienceEl?.value || 'active',
      from_position_id: fromPositionEl?.value || '',
      subject: subjectEl?.value || '',
      message: messageEl?.value || '',
      ...extra
    };
  }

  function setNotice(text) {
    if (notice) notice.textContent = text || '';
  }
  function renderRows(data) {
    const rows = [];
    (data.sendable || []).forEach(item => rows.push(`<tr><td>${escapeHtml(item.email || '')}</td><td>${escapeHtml(item.name || '')}</td><td>${escapeHtml(item.callsign || '')}</td><td>Sendable</td></tr>`));
    (data.skipped || []).forEach(item => rows.push(`<tr><td>${escapeHtml(item.email || '')}</td><td>${escapeHtml(item.name || '')}</td><td>${escapeHtml(item.reason || '')}</td><td>Skipped</td></tr>`));
    previewBody.innerHTML = rows.length ? rows.join('') : '<tr><td colspan="4" class="muted">No recipients matched.</td></tr>';
  }
  async function refreshPreview() {
    setNotice('Loading audience preview…');
    const data = await memberApiFetch('/admin/email/audience', { method: 'POST', body: JSON.stringify({ audience: audienceEl.value, preview: 150 }) });
    renderRows(data);
    setNotice(`${data.sendable_count || 0} sendable recipient(s), ${data.skipped_count || 0} skipped due to suppression.`);
    return data;
  }

  previewBtn?.addEventListener('click', async () => {
    try { await refreshPreview(); } catch (err) { setNotice(`Could not load audience: ${err.message}`); }
  });
  sendTestBtn?.addEventListener('click', async () => {
    const original = sendTestBtn.textContent;
    sendTestBtn.disabled = true;
    sendTestBtn.textContent = 'Sending…';
    try {
      const data = await memberApiFetch('/admin/email/send-test', { method: 'POST', body: JSON.stringify(adminEmailPayload({ to: testToEl?.value || '' })) });
      setNotice(data.message || 'Test email queued.');
    } catch (err) {
      setNotice(`Could not send test: ${err.message}`);
    } finally {
      sendTestBtn.disabled = false;
      sendTestBtn.textContent = original;
    }
  });
  sendBulkBtn?.addEventListener('click', async () => {
    let data;
    try { data = await refreshPreview(); } catch (err) { setNotice(`Could not load audience: ${err.message}`); return; }
    const count = Number(data.sendable_count || 0);
    if (!count) { setNotice('No sendable recipients matched this audience.'); return; }
    const ok = window.prompt(`Type SEND to send this email to ${count} recipient(s). Suppressed addresses will be skipped.`);
    if (String(ok || '').trim().toUpperCase() !== 'SEND') return;
    const original = sendBulkBtn.textContent;
    sendBulkBtn.disabled = true;
    sendBulkBtn.textContent = 'Sending…';
    try {
      const result = await memberApiFetch('/admin/email/send-bulk', { method: 'POST', body: JSON.stringify(adminEmailPayload({ confirm: 'SEND' })) });
      setNotice(result.message || `Bulk email queued to ${result.sent || 0} recipient(s).`);
      await refreshPreview();
    } catch (err) {
      setNotice(`Could not send bulk email: ${err.message}`);
    } finally {
      sendBulkBtn.disabled = false;
      sendBulkBtn.textContent = original;
    }
  });
  suppressBtn?.addEventListener('click', async () => {
    try {
      const data = await memberApiFetch('/admin/email/suppress', { method: 'POST', body: JSON.stringify({ email: suppressEmailEl?.value || '', reason: suppressReasonEl?.value || 'manual' }) });
      setNotice(data.message || 'Address suppressed.');
      await refreshPreview();
    } catch (err) { setNotice(`Could not suppress address: ${err.message}`); }
  });
  clearBtn?.addEventListener('click', async () => {
    try {
      const data = await memberApiFetch('/admin/email/clear-suppression', { method: 'POST', body: JSON.stringify({ email: suppressEmailEl?.value || '' }) });
      setNotice(data.message || 'Suppression cleared.');
      await refreshPreview();
    } catch (err) { setNotice(`Could not clear suppression: ${err.message}`); }
  });

  await loadFromPositions();
  try { await refreshPreview(); } catch (err) { setNotice(`Could not load audience: ${err.message}`); }
}

