function field(label, input) { return `<div class="field"><label>${label}</label>${input}</div>`; }
function textInput(name, value='') { return `<input name="${name}" value="${escapeHtml(value)}">`; }
function textArea(name, value='') { return `<textarea name="${name}">${escapeHtml(value)}</textarea>`; }
function escapeHtml(str) {
  return String(str ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function formatMultilineText(value) {
  return escapeHtml(value).replace(/\r\n|\r|\n/g, '<br>');
}
function normaliseDisplayUrl(url) {
  const text = String(url || '').trim();
  if (!text) return '';
  return /^https?:\/\//i.test(text) ? text : `https://${text}`;
}
function trimUrlTrailingPunctuation(url) {
  let clean = String(url || '');
  let trailing = '';
  while (/[),.;:!?]$/.test(clean)) {
    const last = clean.slice(-1);
    clean = clean.slice(0, -1);
    trailing = last + trailing;
  }
  return { clean, trailing };
}
function formatTextWithClickableUrls(value) {
  const text = String(value ?? '');
  const urlPattern = /(https?:\/\/[^\s<>()]+|www\.[^\s<>()]+)/gi;
  let html = '';
  let lastIndex = 0;
  text.replace(urlPattern, (match, _url, offset) => {
    html += escapeHtml(text.slice(lastIndex, offset));
    const { clean, trailing } = trimUrlTrailingPunctuation(match);
    const href = normaliseDisplayUrl(clean);
    html += `<a href="${escapeHtml(href)}" target="_blank" rel="noopener noreferrer">${escapeHtml(clean)}</a>${escapeHtml(trailing)}`;
    lastIndex = offset + match.length;
    return match;
  });
  html += escapeHtml(text.slice(lastIndex));
  return html.replace(/\r\n|\r|\n/g, '<br>');
}
function multilineClass(extra = '') {
  return `multiline-text${extra ? ` ${extra}` : ''}`;
}
function eventAdminSlug(value, fallback = 'event') {
  const slug = String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 64).replace(/-+$/g, '');
  return slug || fallback;
}
function defaultCalendarEventId(row, idx = 0) {
  const datePart = String(row?.date || 'event').replace(/[^0-9a-z]/gi, '') || 'event';
  const titlePart = eventAdminSlug(row?.event || `event-${idx + 1}`, `event-${idx + 1}`);
  return eventAdminSlug(`${datePart}-${titlePart}`, `event-${idx + 1}`);
}
function ensureAdminCalendarEventIds(content) {
  const rows = content?.pages?.events?.calendarRows;
  if (!Array.isArray(rows)) return content;
  const used = new Set();
  rows.forEach((row, idx) => {
    if (!row || typeof row !== 'object') return;
    let eventId = eventAdminSlug(row.event_id || defaultCalendarEventId(row, idx), `event-${idx + 1}`);
    const baseId = eventId;
    let suffix = 2;
    while (used.has(eventId)) {
      eventId = `${baseId}-${suffix}`;
      suffix += 1;
    }
    used.add(eventId);
    row.event_id = eventId;
  });
  return content;
}

const LANDROVER_PART_FIELDS = [
  'part_number', 'canonical_part_number', 'description', 'component', 'model_family', 'year_range',
  'applicability', 'position', 'vin_family_keys', 'verified_response', 'notes', 'source_url', 'supersedes', 'superseded_by',
  'equivalent_numbers', 'keywords', 'last_verified'
];
const LANDROVER_PART_LONG_FIELDS = new Set(['applicability', 'verified_response', 'notes', 'equivalent_numbers', 'keywords', 'vin_family_keys']);
const LANDROVER_PART_LIST_FIELDS = new Set(['supersedes', 'superseded_by', 'equivalent_numbers', 'keywords', 'vin_family_keys']);
const LANDROVER_PART_LABELS = {
  part_number: 'Part number', canonical_part_number: 'Canonical/current part number', description: 'Description',
  component: 'Component', model_family: 'Model/family', year_range: 'Year range', applicability: 'Applicability',
  position: 'Position/axle/end', vin_family_keys: 'VIN family keys (first 7 chars)', verified_response: 'Verified response', notes: 'Admin notes', source_url: 'Source URL',
  supersedes: 'Supersedes / older numbers', superseded_by: 'Superseded by / newer numbers',
  equivalent_numbers: 'Equivalent/cross-reference numbers', keywords: 'Lookup keywords', last_verified: 'Last verified'
};
function blankLandRoverPartRecord() {
  return { part_number: '', canonical_part_number: '', description: '', component: '', model_family: '', year_range: '', applicability: '', position: '', vin_family_keys: [], verified_response: '', notes: '', source_url: '', supersedes: [], superseded_by: [], equivalent_numbers: [], keywords: [], published: true, last_verified: new Date().toISOString().slice(0, 10) };
}
function landRoverPartTextValue(record, key) {
  const value = record?.[key];
  if (LANDROVER_PART_LIST_FIELDS.has(key)) return Array.isArray(value) ? value.join('\n') : String(value || '');
  return String(value || '');
}
function normaliseAdminUrl(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^[a-z][a-z0-9+.-]*:\/\//i.test(text)) return text;
  if (/^[\w.-]+\.[a-z]{2,}(\/.*)?$/i.test(text)) return `https://${text}`;
  return text;
}
function renderLandRoverPartsAdmin() {
  return `<div class="editor-section landrover-parts-admin">
    <h2 class="page-banner">Land Rover parts</h2>
    <div class="notice"><strong>Verified parts knowledge only.</strong><div style="margin-top:8px">Vehicle Help can quote exact part numbers only from this table. Use supersedes/superseded by to allow old numbers to fall back or forward to the verified canonical/current number. For VIN-specific matching, add one or more first-7-character VIN family keys such as SALLDHM.</div></div>
    <div class="auth-actions" style="margin-top:14px">
      <button class="button" id="landroverPartsRefreshBtn" type="button">Load parts</button>
      <button class="button secondary" id="landroverPartsAddBtn" type="button">Add part</button>
    </div>
    <div id="landroverPartsNotice" class="muted" style="margin-top:12px">Load verified parts to edit them.</div>
    <div id="landroverPartsList" class="stack" style="margin-top:16px"></div>
  </div>`;
}
async function wireLandRoverPartsAdmin() {
  const list = document.getElementById('landroverPartsList');
  const notice = document.getElementById('landroverPartsNotice');
  const refreshBtn = document.getElementById('landroverPartsRefreshBtn');
  const addBtn = document.getElementById('landroverPartsAddBtn');
  if (!list || !refreshBtn) return;
  let records = [];
  let expandedPartIndex = null;
  const setNotice = (text) => { if (notice) notice.textContent = text || ''; };
  const parseListValue = (value, key = '') => {
    const text = String(value || '');
    const splitter = key === 'equivalent_numbers' ? /[\n;|]+/ : /[\n,;]+/;
    return text.split(splitter).map(x => x.trim()).filter(Boolean);
  };
  const recordFromCard = (card) => {
    const record = {};
    card.querySelectorAll('[data-part-field]').forEach(input => {
      const key = input.dataset.partField;
      if (LANDROVER_PART_LIST_FIELDS.has(key)) record[key] = parseListValue(input.value, key);
      else record[key] = key === 'source_url' ? normaliseAdminUrl(input.value) : input.value;
    });
    record.published = card.querySelector('[data-part-published]')?.checked !== false;
    return record;
  };
  function fieldInput(record, idx, key) {
    const id = `lrPart_${idx}_${key}`;
    const value = landRoverPartTextValue(record, key);
    const control = LANDROVER_PART_LONG_FIELDS.has(key)
      ? `<textarea id="${id}" data-part-field="${key}" rows="3">${escapeHtml(value)}</textarea>`
      : `<input id="${id}" data-part-field="${key}" value="${escapeHtml(value)}" ${key === 'source_url' ? 'inputmode="url" placeholder="https://..."' : ''}>`;
    return `<div class="field ${LANDROVER_PART_LONG_FIELDS.has(key) ? 'wide-field' : ''}"><label for="${id}">${escapeHtml(LANDROVER_PART_LABELS[key] || key)}</label>${control}</div>`;
  }
  function partSummary(record) {
    const bits = [record.component, record.description, record.model_family, record.year_range, record.position]
      .map(x => String(x || '').trim()).filter(Boolean);
    return bits.join(' • ') || 'Verified Land Rover part';
  }
  function collapsedPartCard(record, idx) {
    const published = record.published === false ? 'Unpublished' : 'Published';
    const canonical = record.canonical_part_number && record.canonical_part_number !== record.part_number ? ` • Current: ${escapeHtml(record.canonical_part_number)}` : '';
    const keywords = Array.isArray(record.keywords) && record.keywords.length ? `<div class="muted small-text">Keywords: ${escapeHtml(record.keywords.slice(0, 6).join(', '))}</div>` : '';
    return `<article class="card card-pad landrover-part-card collapsed" data-part-index="${idx}">
      <div class="space-between gap-wrap landrover-part-summary">
        <div><h3 style="margin:0">${escapeHtml(record.part_number || `Part ${idx + 1}`)}${canonical}</h3><div class="muted" style="margin-top:4px">${escapeHtml(partSummary(record))}</div>${keywords}</div>
        <div class="auth-actions"><span class="pill">${escapeHtml(published)}</span><button class="button secondary" data-part-edit type="button">Edit</button></div>
      </div>
    </article>`;
  }
  function expandedPartCard(record, idx) {
    return `<article class="card card-pad landrover-part-card expanded" data-part-index="${idx}">
      <div class="space-between gap-wrap landrover-part-summary">
        <div><h3 style="margin:0">${escapeHtml(record.part_number || `Part ${idx + 1}`)}</h3><div class="muted" style="margin-top:4px">${escapeHtml(partSummary(record))}</div></div>
        <div class="auth-actions"><label class="pill"><input type="checkbox" data-part-published ${record.published === false ? '' : 'checked'}> Published</label><button class="button" data-part-save type="button">Save</button><button class="button ghost" data-part-cancel type="button">Cancel</button><button class="button ghost" data-part-delete type="button">Delete</button></div>
      </div>
      <div class="form-grid compact-grid landrover-part-form" style="margin-top:14px">${LANDROVER_PART_FIELDS.map(key => fieldInput(record, idx, key)).join('')}</div>
    </article>`;
  }
  function render() {
    list.innerHTML = records.map((record, idx) => idx === expandedPartIndex ? expandedPartCard(record, idx) : collapsedPartCard(record, idx)).join('') || '<div class="notice"><strong>No verified parts yet.</strong><div style="margin-top:8px">Add the first part number record.</div></div>';
    list.querySelectorAll('[data-part-edit]').forEach(btn => btn.addEventListener('click', () => {
      const card = btn.closest('[data-part-index]');
      expandedPartIndex = Number(card.dataset.partIndex);
      render();
    }));
    list.querySelectorAll('[data-part-cancel]').forEach(btn => btn.addEventListener('click', () => {
      expandedPartIndex = null;
      render();
    }));
    list.querySelectorAll('[data-part-save]').forEach(btn => btn.addEventListener('click', async () => {
      const card = btn.closest('[data-part-index]');
      const oldText = btn.textContent;
      try {
        btn.disabled = true; btn.textContent = 'Saving…';
        const record = recordFromCard(card);
        const data = await memberApiFetch('/admin/landrover-parts', { method: 'POST', body: JSON.stringify({ item: record }) });
        records[Number(card.dataset.partIndex)] = data.item || record;
        setNotice(`Saved ${records[Number(card.dataset.partIndex)].part_number}.`);
        expandedPartIndex = null;
        await load();
      } catch (err) { setNotice(`Could not save part: ${err.message}`); }
      finally { btn.disabled = false; btn.textContent = oldText; }
    }));
    list.querySelectorAll('[data-part-delete]').forEach(btn => btn.addEventListener('click', async () => {
      const card = btn.closest('[data-part-index]');
      const record = recordFromCard(card);
      if (!record.part_number || !confirm(`Delete verified part ${record.part_number}?`)) return;
      try {
        await memberApiFetch('/admin/landrover-parts/delete', { method: 'POST', body: JSON.stringify({ part_number: record.part_number }) });
        setNotice(`Deleted ${record.part_number}.`);
        expandedPartIndex = null;
        await load();
      } catch (err) { setNotice(`Could not delete part: ${err.message}`); }
    }));
  }
  async function load() {
    setNotice('Loading verified Land Rover parts…');
    const data = await memberApiFetch('/admin/landrover-parts');
    records = Array.isArray(data.items) ? data.items : [];
    render();
    setNotice(`${records.length} verified part record(s) loaded.`);
  }
  refreshBtn.addEventListener('click', () => load().catch(err => setNotice(`Could not load parts: ${err.message}`)));
  addBtn?.addEventListener('click', () => { records.unshift(blankLandRoverPartRecord()); expandedPartIndex = 0; render(); setNotice('New unsaved part record added.'); });
  await load().catch(err => setNotice(`Could not load parts: ${err.message}`));
}


function renderExpoMicrositeAdmin() {
  const pages = [
    ['index','Home'], ['visitor-info','Visitors'], ['exhibitors','Exhibitors'], ['caterers','Caterers'], ['tickets','Tickets'],
    ['camping','Camping'], ['sponsors','Sponsors / Traders'], ['location','Location'], ['downloads','Downloads'], ['contact','Contact']
  ];
  return `<div class="editor-section expo-admin-section">
    <h2 class="page-banner">Expo microsite</h2>
    <p class="muted">Manage the Expo microsite content published to <code>/expo/content.json</code>. The page layout stays in the repo, but the live wording, page intro blocks, cards and download links can be updated here.</p>
    <div class="notice"><strong>Content model:</strong> shared event details update all Expo pages. Page content lets you manage each public Expo page without editing code.</div>
    <h3>Shared event details</h3>
    <div class="form-grid compact-grid">
      <div class="field"><label>Event name</label><input id="expoAdminEventName"></div>
      <div class="field"><label>Hero title</label><input id="expoAdminHeroTitle"></div>
      <div class="field" style="grid-column:1 / -1"><label>Hero lead</label><textarea id="expoAdminHeroLead" rows="4"></textarea></div>
      <div class="field"><label>Event date</label><input id="expoAdminEventDate" placeholder="Sunday 19 July 2026"></div>
      <div class="field"><label>Event time</label><input id="expoAdminEventTime" placeholder="9:00 AM – 4:00 PM"></div>
      <div class="field"><label>Venue name</label><input id="expoAdminVenueName"></div>
      <div class="field"><label>Venue address</label><input id="expoAdminVenueAddress"></div>
      <div class="field"><label>Venue latitude</label><input id="expoAdminVenueLatitude" placeholder="-33.609232"></div>
      <div class="field"><label>Venue longitude</label><input id="expoAdminVenueLongitude" placeholder="150.784358"></div>
      <div class="field"><label>Ticket summary</label><input id="expoAdminTicketSummary"></div>
      <div class="field"><label>Contact name</label><input id="expoAdminContactName"></div>
      <div class="field"><label>Contact email</label><input id="expoAdminContactEmail" type="email"></div>
      <div class="field" style="grid-column:1 / -1"><label>Ticket placeholder message</label><textarea id="expoAdminTicketStatus" rows="3"></textarea></div>
    </div>
    <hr>
    <h3>Page content</h3>
    <div class="form-grid compact-grid">
      <div class="field"><label>Page</label><select id="expoAdminPageSelect">${pages.map(([id,label]) => `<option value="${id}">${label}</option>`).join('')}</select></div>
      <div class="field"><label>Page label</label><input id="expoAdminPageLabel"></div>
      <div class="field"><label>Eyebrow</label><input id="expoAdminPageEyebrow"></div>
      <div class="field"><label>Page title</label><input id="expoAdminPageTitle"></div>
      <div class="field" style="grid-column:1 / -1"><label>Lead / hero text</label><textarea id="expoAdminPageLead" rows="3"></textarea></div>
      <div class="field" style="grid-column:1 / -1"><label>Main editable page body</label><textarea id="expoAdminPageBody" rows="5"></textarea></div>
      <div class="field" style="grid-column:1 / -1"><label>Cards / callouts</label><textarea id="expoAdminPageCards" rows="7" placeholder="One per line: icon | title | text | link label | url"></textarea><small class="muted">Example: 🚙 | Vehicle displays | Bring your Land Rover and meet other owners | Exhibitor info | exhibitors.html</small></div>
      <div class="field" style="grid-column:1 / -1"><label>Download / link list</label><textarea id="expoAdminPageDownloads" rows="6" placeholder="One per line: label | url | note"></textarea><small class="muted">Use this for PDF forms, flyers, external EOI forms or placeholder download links.</small></div>
    </div>
    <div class="auth-actions" style="margin-top:14px">
      <button class="button secondary" id="expoAdminLoadBtn" type="button">Load Expo content</button>
      <button class="button" id="expoAdminPublishBtn" type="button">Publish Expo content</button>
      <a class="button ghost" href="expo/index.html" target="_blank" rel="noopener">Preview Expo site</a>
    </div>
    <div id="expoAdminNotice" class="notice" style="margin-top:14px">Load the current Expo microsite content before publishing changes.</div>
  </div>`;
}

