function magazineNormalisePageTemplateForEditor(template = {}) {
  const t = { ...template };
  if (String(t.templateId || '') === 'event_calendar_next_four_months') {
    t.name = 'Event calendar - selected months';
    t.description = 'Magazine-style event calendar generated from the editor-selected number of upcoming months.';
  }
  if (String(t.templateId || '') === 'calendar_list') {
    t.name = 'Event calendar - list';
    t.description = 'Generated calendar list using the selected number of upcoming club-event months for this issue.';
  }
  return t;
}
function magazinePageTemplates() {
  const templates = magazineState.bootstrap?.pageTemplates;
  const list = Array.isArray(templates) && templates.length ? templates : magazineFallbackPageTemplates();
  return list.filter(t => !['front_cover','back_cover_ad'].includes(String(t.templateId || ''))).map(magazineNormalisePageTemplateForEditor);
}
function magazinePageTypes() {
  const types = magazineState.bootstrap?.pageTypes;
  const allowed = Array.isArray(types) && types.length ? types : ['editorial','article','trip_report','photo_gallery','event_calendar','committee_list','classifieds','advertisement','external_contribution','mixed_content','filler'];
  return allowed.filter(type => !['front_cover','back_cover_ad'].includes(String(type || '')));
}
function magazinePageTypeOptions(selected = '') {
  return magazinePageTypes().map(type => `<option value="${escapeHtml(type)}" ${type === selected ? 'selected' : ''}>${escapeHtml(type.replace(/_/g,' '))}</option>`).join('');
}
function magazinePageTemplateOptions(selected = '') {
  return magazinePageTemplates().map(t => `<option value="${escapeHtml(t.templateId || '')}" ${t.templateId === selected ? 'selected' : ''}>${escapeHtml(t.name || t.templateId || '')}</option>`).join('');
}
function magazineTemplateDescription(templateId = '') {
  const t = magazinePageTemplates().find(x => String(x.templateId || '') === String(templateId || ''));
  return t?.description || 'Template geometry will drive later drag/drop slots and rendered proofs.';
}

function mag3437SlotIsRetiredNote(slot = {}) {
  const id = String(slot.slotId || '').toLowerCase();
  const label = String(slot.slotLabel || '').toLowerCase();
  return id === 'sidebar' || id === 'advert_notes' || label.includes('sidebar / pull quote / advert note');
}
function mag3437FilterRetiredNoteSlots(slots = []) {
  return (Array.isArray(slots) ? slots : []).filter(slot => !mag3437SlotIsRetiredNote(slot));
}

