    const cut = paraBreak >= 0 && paraBreak < 260 ? paraBreak + 2 : (sentenceBreak >= 0 && sentenceBreak < 180 ? sentenceBreak + 2 : 0);
    if (cut > 0) slice = slice.slice(cut);
