  return `${item.subtitle && renderMode !== 'lead_excerpt' ? `<p class="muted mag-content-subtitle">${escapeHtml(item.subtitle)}</p>` : ''}<div class="${escapeHtml(cls)}"${articleStyle}>${bodyHtml}</div>${flowNote}${shownWarning}<small>${escapeHtml(placement)}</small>`;
