      mcePageContentHeightPx: value.mcePageContentHeightPx ?? def.mcePageContentHeightPx ?? 0,
      mcePageFooterHeightPx: value.mcePageFooterHeightPx ?? def.mcePageFooterHeightPx ?? 0,
      mcePageWidthPx: value.mcePageWidthPx ?? def.mcePageWidthPx ?? 0,
      mcePaginationMode: value.mcePaginationMode || def.mcePaginationMode || '',
      mcePaginationDiagnostics: value.mcePaginationDiagnostics || def.mcePaginationDiagnostics || null,
