      leadCharacterLimit: Number(row.querySelector('[data-mag-slot-lead-limit]')?.value || def.leadCharacterLimit || 0) || undefined,
      skipLeadCharacters: Number(row.querySelector('[data-mag-slot-lead-limit]')?.value || def.skipLeadCharacters || def.leadCharacterLimit || 0) || undefined,
