async function magazineSaveCurrentAsTemplate(page = {}) {
  const name = window.prompt('Save current template as:', 'LROC custom template');
  if (!name || !name.trim()) return;
  const payload = {
    name: name.trim(),
    description: `Custom template saved from ${document.getElementById('magPageEditorTemplate')?.value || page.templateId || 'current page'}`,
    pageType: document.getElementById('magPageEditorType')?.value || page.pageType || 'mixed_content',
    pageTypes: [document.getElementById('magPageEditorType')?.value || page.pageType || 'mixed_content'],
    slots: magazineCurrentTemplateSlotDefinitions(page)
  };
  const data = await memberApiFetch('/member/magazine/templates', { method: 'POST', body: JSON.stringify(payload) });
  magazineState.bootstrap = { ...(magazineState.bootstrap || {}), pageTemplates: data.templates || magazineState.bootstrap?.pageTemplates || [] };
  const template = data.template || {};
  const select = document.getElementById('magPageEditorTemplate');
  if (select && template.templateId) {
    select.innerHTML = magazinePageTemplateOptions(template.templateId);
    select.value = template.templateId;
  }
  magazineRefreshInteriorPreviewFromEditor(page);
  showToast(`Saved custom template: ${template.name || name.trim()}`);
}
async function magazineSyncCalendarShortDescriptions(layoutSlots = []) {
  const updates = [];
  (layoutSlots || []).forEach(slot => {
    if (!Array.isArray(slot.calendarEvents)) return;
    slot.calendarEvents.forEach(event => {
      const eventId = String(event.event_id || event.eventId || '').trim();
      if (!eventId) return;
      updates.push({ event_id: eventId, short_description: String(event.description || '').trim() });
    });
  });
  if (!updates.length) return;
  await memberApiFetch('/admin/events/short-descriptions', { method: 'POST', body: JSON.stringify({ items: updates }) });
}

async function magazineSavePageSlotLayout(pageNumber, options = {}) {
  if (!magazineState.selectedIssueId) throw new Error('Open an issue first.');
  const n = Number(pageNumber || magazineState.selectedPageNumber || 0);
  if (!n) throw new Error('No page selected.');
  const layoutSlots = magazineReadSlotLayoutFromEditor();
  const payload = {
    issueId: magazineState.selectedIssueId,
    pageNumber: n,
    pageType: document.getElementById('magPageEditorType')?.value || '',
    templateId: document.getElementById('magPageEditorTemplate')?.value || '',
    locked: Boolean(document.getElementById('magPageEditorLocked')?.checked),
    notes: document.getElementById('magPageEditorNotes')?.value || '',
    layoutSlots
  };
  const editor = document.querySelector('#magazinePagePreviewPanel .magazine-page-editor-card');
  const editorScrollTop = editor ? editor.scrollTop : 0;
  const selectedSlotId = magazineState.selectedSlotId || '';
  let calendarSyncWarning = '';
  try {
    await magazineSyncCalendarShortDescriptions(layoutSlots);
  } catch (err) {
    calendarSyncWarning = ` Calendar event-record blurbs were not updated: ${err.message}`;
  }
  const data = await memberApiFetch('/member/magazine/flatplan/page', { method: 'POST', body: JSON.stringify(payload) });
  magazineState.selectedFlatplan = data.flatplan || magazineState.selectedFlatplan;
  magazineState.selectedSlotId = selectedSlotId;
  const current = magazinePageFromSelectedState();
  magazineRefreshInteriorPreviewFromEditor(current);
  if (editor) editor.scrollTop = editorScrollTop;
  if (selectedSlotId) magazineSetSelectedSlot(selectedSlotId);
  if (!options?.silent) showToast(`Saved page ${n} settings and layout.${calendarSyncWarning}`, { kind: calendarSyncWarning ? 'warning' : 'success' });
}

function mag323AutosaveStatus(message = 'Autosave on', kind = '') {
  const el = document.getElementById('mag323AutosaveStatus');
  if (!el) return;
  el.textContent = message;
  el.className = `muted small-text mag323-autosave-status ${kind || ''}`.trim();
}
function mag323QueuePageAutosave(pageNumber = 0, reason = 'change') {
  const n = Number(pageNumber || magazineState.selectedPageNumber || 0);
  if (!n || !magazineState.selectedIssueId) return;
  clearTimeout(magazineState.mag323AutosaveTimer);
  mag323AutosaveStatus('Saving…', 'saving');
  magazineState.mag323AutosaveTimer = setTimeout(async () => {
    const seq = (magazineState.mag323AutosaveSeq || 0) + 1;
    magazineState.mag323AutosaveSeq = seq;
    try {
      await magazineSavePageSlotLayout(n, { silent: true, autosave: true, reason });
      if (magazineState.mag323AutosaveSeq === seq) mag323AutosaveStatus('Autosaved', 'saved');
    } catch (err) {
      if (magazineState.mag323AutosaveSeq === seq) mag323AutosaveStatus(`Autosave failed: ${err.message}`, 'warning');
      showToast(`Autosave failed: ${err.message}`, { kind: 'warning' });
    }
  }, 900);
}

