function magazineCoverLayoutForPage(page = {}, issue = {}) {
  const layout = { ...magazineCoverLayoutDefaults(issue), ...(page.coverLayout || {}) };
  // v3.5.7 migration: the old single bottom banner text becomes the new top row.
  // The existing siteUrl now lives in the lower-left cell of the bottom bar.
  if (!String(layout.bottomBannerText || '').trim() && String(page.coverLayout?.bottomBannerHighlightText || '').trim()) {
    layout.bottomBannerText = page.coverLayout.bottomBannerHighlightText;
  }
  if (layout.facebookUrl == null) layout.facebookUrl = '';
  return layout;
}
function magazineCoverLogoStyle(layout = {}) {
  const width = Math.max(5, Math.min(60, Number(layout.logoWidthPercent || 22)));
  const maxHeight = Math.max(6, Math.min(60, Number(layout.logoMaxHeightPercent || 24)));
  const opacity = Math.max(10, Math.min(100, Number(layout.logoOpacityPercent || 100)));
  const position = String(layout.logoPosition || 'custom');
  const bits = [`width:${width}%`, `max-height:${maxHeight}%`, `opacity:${opacity / 100}`];
  const top = Math.max(0, Math.min(90, Number(layout.logoTopPercent ?? 3)));
  const right = Math.max(0, Math.min(90, Number(layout.logoRightPercent ?? (layout.logoLeftPercent != null ? Math.max(0, 100 - Number(layout.logoLeftPercent || 73) - width) : 5))));
  if (position === 'top-left') bits.push(`top:${top}%`, 'left:5%');
  else if (position === 'top-right') bits.push(`top:${top}%`, `right:${right}%`);
  else if (position === 'bottom-left') bits.push('bottom:5%', 'left:7%');
  else if (position === 'bottom-right') bits.push('bottom:5%', `right:${right}%`);
  else {
    bits.push(`top:${top}%`);
    bits.push(`right:${right}%`);
  }
  return bits.join(';');
}


function magazineCoverGuidesHtml(layout = {}) {
  if (!layout.showGuides) return '';
  return '<div class="mag-cover-guides" aria-hidden="true"><span class="mag-cover-guide-bleed"></span><span class="mag-cover-guide-trim"></span><span class="mag-cover-guide-safe"></span><span class="mag-cover-guide-centre-v"></span><span class="mag-cover-guide-centre-h"></span><span class="mag-cover-guide-third-v1"></span><span class="mag-cover-guide-third-v2"></span><span class="mag-cover-guide-third-h1"></span><span class="mag-cover-guide-third-h2"></span></div>';
}

function magazineCoverRulersHtml(layout = {}) {
  if (!layout.showRulers && !layout.showTopRuler) return '';
  const marks = Array.from({ length: 11 }, (_, i) => i * 10);
  const vertical = layout.showRulers ? `<div class="mag-cover-ruler-vertical left" aria-hidden="true">${marks.map(v => `<span style="top:${v}%"><b>${v}</b></span>`).join('')}</div><div class="mag-cover-ruler-vertical right" aria-hidden="true">${marks.map(v => `<span style="top:${v}%"><b>${v}</b></span>`).join('')}</div>` : '';
  const top = layout.showTopRuler ? `<div class="mag-cover-ruler-horizontal top" aria-hidden="true">${marks.map(v => `<span style="left:${v}%"><b>L${v}</b></span>`).join('')}</div>` : '';
  const bottom = layout.showTopRuler ? `<div class="mag-cover-ruler-horizontal bottom" aria-hidden="true">${marks.map(v => `<span style="left:${v}%"><b>R${100 - v}</b></span>`).join('')}</div>` : '';
  return `<div class="mag-cover-rulers" aria-hidden="true">${top}${bottom}${vertical}</div>`;
}
