    minimal: { ...base, lrocPointSize: 92, lrocTopPercent: 5, lrocLeftPercent: 5, lrocWidthPercent: 48, lrocLetterSpacing: '-0.02em', subtitleEnabled: false, subtitleText: '', logoWidthPercent: 14, logoTopPercent: 5, logoRightPercent: 6, logoMaxHeightPercent: 16, issueTopPercent: 22, issueLeftPercent: 5, issuePointSize: 18, topBannerEnabled: false, bottomBannerEnabled: false, showGuides: true },
