function magazineApplyCoverLayoutToControls(layout = {}) {
  Object.entries(magazineCoverControlMap()).forEach(([id, key]) => {
    if (Object.prototype.hasOwnProperty.call(layout, key)) magazineSetInputValue(id, layout[key]);
  });
}
function magazineCloneCoverLayout(layout = {}) {
  try { return JSON.parse(JSON.stringify(layout || {})); }
  catch (_) { return { ...(layout || {}) }; }
}
function magazineCoverLayoutsEqual(a = {}, b = {}) {
  return JSON.stringify(a || {}) === JSON.stringify(b || {});
}
function magazineUpdateCoverUndoButton() {
  const btn = document.getElementById('magazineUndoCoverLayoutBtn');
  if (!btn) return;
  const count = Array.isArray(magazineState.coverLayoutUndoStack) ? magazineState.coverLayoutUndoStack.length : 0;
  btn.disabled = count < 1;
  btn.textContent = count > 1 ? `Revert cover layout (${count} steps)` : 'Revert cover layout';
}
function magazinePushCoverUndoSnapshot(layout = null) {
  const snapshot = magazineCloneCoverLayout(layout || magazineReadCoverLayoutFromControls());
  if (!Array.isArray(magazineState.coverLayoutUndoStack)) magazineState.coverLayoutUndoStack = [];
  const stack = magazineState.coverLayoutUndoStack;
  if (stack.length && magazineCoverLayoutsEqual(stack[stack.length - 1], snapshot)) return;
  stack.push(snapshot);
  while (stack.length > 8) stack.shift();
  magazineUpdateCoverUndoButton();
}
function magazineUndoCoverLayout(page = {}, issue = magazineState.selectedIssue || {}) {
  const stack = Array.isArray(magazineState.coverLayoutUndoStack) ? magazineState.coverLayoutUndoStack : [];
  const previous = stack.pop();
  if (!previous) {
    showToast('No previous cover layout to revert to.', { kind: 'warning' });
    magazineUpdateCoverUndoButton();
    return;
  }
  magazineApplyCoverLayoutToControls(previous);
  magazineRefreshCoverPreviewFromControls(page, issue);
  magazineUpdateCoverUndoButton();
  showToast('Reverted to previous cover layout. Click Save cover layers to persist it.');
}
function magazineMoveCoverNumericControl(inputId, step, page = {}, issue = magazineState.selectedIssue || {}) {
  const input = document.getElementById(inputId);
  if (!input) return;
  magazinePushCoverUndoSnapshot();
  const current = Number(input.value || 0);
  const min = Number(input.min || 0);
  const max = Number(input.max || 100);
  const next = Math.max(min, Math.min(max, current + Number(step || 0)));
  input.value = String(next);
  magazineRefreshCoverPreviewFromControls(page, issue);
}

function magazineCoverCompositeHtml(asset, layout = {}, label = 'Cover preview') {
  if (!asset?.viewUrl || !String(asset.mimeType || '').toLowerCase().startsWith('image/')) {
    return magazineAssetPreviewHtml(asset, label);
  }
  const showFallbackUrl = !layout.bottomBannerEnabled && String(layout.siteUrl || '').trim();
  return `<figure class="magazine-cover-composite ${layout.showRulers || layout.showTopRuler ? 'has-rulers' : ''}">
    <div class="mag-cover-stage">
      ${magazineCoverRulersHtml(layout)}
      <img src="${escapeHtml(asset.viewUrl)}" alt="${escapeHtml(label)}">
      ${magazineCoverGuidesHtml(layout)}
      ${layout.logoEnabled && layout.logoUrl ? `<img class="mag-cover-logo ${escapeHtml(layout.logoPosition || 'custom')}" src="${escapeHtml(layout.logoUrl)}" alt="Club logo" style="${magazineCoverLogoStyle(layout)}">` : ''}
      ${layout.topBannerEnabled && layout.topBannerText ? `<div class="mag-cover-banner top" style="${magazineCoverTopBannerStyle(layout)}">${escapeHtml(layout.topBannerText)}</div>` : ''}
      <div class="mag-cover-title" style="font-family:${escapeHtml(layout.lrocFontFamily || 'Arial Black, Arial, sans-serif')};font-size:${Math.max(24, Math.min(190, Number(layout.lrocPointSize || 132)))}pt;top:${Math.max(0, Math.min(80, Number(layout.lrocTopPercent ?? 2)))}%;left:${Math.max(0, Math.min(90, Number(layout.lrocLeftPercent ?? 3)))}%;width:${Math.max(20, Math.min(96, Number(layout.lrocWidthPercent || 66)))}%;letter-spacing:${escapeHtml(layout.lrocLetterSpacing || '-0.03em')};color:${escapeHtml(layout.lrocColor || '#2d3130')};-webkit-text-stroke:1.2px ${escapeHtml(layout.lrocOutlineColor || '#eef5ef')};text-shadow:0 2px 0 ${escapeHtml(layout.lrocOutlineColor || '#eef5ef')},0 8px 22px rgba(0,0,0,.58);">${escapeHtml(layout.lrocName || 'LROC')}</div>
      ${layout.subtitleEnabled !== false && layout.subtitleText ? `<div class="mag-cover-subtitle" style="font-family:${escapeHtml(layout.subtitleFontFamily || 'Arial Black, Arial, sans-serif')};font-size:${Math.max(12, Math.min(100, Number(layout.subtitlePointSize || 38)))}pt;top:${Math.max(0, Math.min(85, Number(layout.subtitleTopPercent ?? 22)))}%;right:${Math.max(0, Math.min(90, Number(layout.subtitleRightPercent ?? (layout.subtitleLeftPercent != null ? Math.max(0, 100 - Number(layout.subtitleLeftPercent || 55) - 20) : 21))))}%;color:${escapeHtml(layout.subtitleColor || '#2d3130')};-webkit-text-stroke:.9px ${escapeHtml(layout.subtitleOutlineColor || '#eef5ef')};text-shadow:0 2px 0 ${escapeHtml(layout.subtitleOutlineColor || '#eef5ef')},0 8px 20px rgba(0,0,0,.58);">${escapeHtml(layout.subtitleText || 'NEWS')}</div>` : ''}
      ${magazineCoverBottomBannerHtml(layout)}
      <div class="mag-cover-issue" style="top:${Math.max(0, Math.min(90, Number(layout.issueTopPercent ?? 31)))}%;left:${Math.max(0, Math.min(90, Number(layout.issueLeftPercent ?? 3)))}%;font-size:${Math.max(8, Math.min(72, Number(layout.issuePointSize || 24)))}pt;color:${escapeHtml(layout.issueColor || '#dce8df')};">${escapeHtml(layout.issueLabel || '')}</div>
      ${showFallbackUrl ? `<div class="mag-cover-url" style="color:${escapeHtml(layout.urlColor || '#ffffff')};">${escapeHtml(layout.siteUrl || '')}</div>` : ''}
    </div>
  </figure>`;
}

