    contactPct: mag331ReadNumber('magAdvertBuilderContactPct', 16, 42, 26),
    paddingPct: mag331ReadNumber('magAdvertBuilderPaddingPct', 2, 7, 4.2),
    gapPct: mag331ReadNumber('magAdvertBuilderGapPct', 1, 5, 3.2),
