    businessFontSize: Number(document.getElementById('magAdvertBuilderBusinessFontSize')?.value || 0),
    headlineFontSize: Number(document.getElementById('magAdvertBuilderHeadlineFontSize')?.value || 0),
    bodyFontSize: Number(document.getElementById('magAdvertBuilderBodyFontSize')?.value || 0),
    contactFontSize: Number(document.getElementById('magAdvertBuilderContactFontSize')?.value || 0),
