  mag331SetText('magAdvertBuilderImagePctLabel', `${values.imagePct}%`);
  mag331SetText('magAdvertBuilderImageWidthPctLabel', `${values.imageWidthPct}%`);
  mag331SetText('magAdvertBuilderContactPctLabel', `${values.contactPct}%`);
