function mag331ExistingSourceImageForHash(hash = '') {
  const h = String(hash || '').trim();
  if (!h) return null;
  return (magazineState.assets || []).find(asset => !magazineAssetIsInternalMetadata(asset) && !mag337AssetHiddenFromGallery(asset) && !asset.isAdvertRender && String(asset.contentHash || '') === h && magazineAssetIsImage(asset)) || null;
}

async function mag331LoadImageFromUrl(url = '', options = {}) {
  if (!url) return null;
  return new Promise((resolve, reject) => {
    const img = new Image();
    if (options.crossOrigin !== false) img.crossOrigin = 'anonymous';
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error('Could not load the advert source image.'));
    img.src = url;
  });
}
function mag331BlobToDataUrl(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ''));
    reader.onerror = () => reject(new Error('Could not read the image data.'));
    reader.readAsDataURL(blob);
  });
}
function mag331CanvasToBlob(canvas, mimeType = 'image/jpeg', quality = 0.92) {
  return new Promise((resolve, reject) => {
    canvas.toBlob(blob => blob ? resolve(blob) : reject(new Error('Could not prepare the advert source image.')), mimeType, quality);
  });
}
async function mag331PrepareAdvertSourceImageBlob(file) {
  if (!file) return null;
  const originalType = String(file.type || '').toLowerCase();
  const keepOriginal = originalType === 'image/png' && file.size <= 2.5 * 1024 * 1024;
  if (keepOriginal) return { blob: file, mimeType: file.type || 'image/png', fileName: file.name, normalised: false };
  let img = magazineAdvertBuilderState.imageElement;
  if (!img) {
    const url = URL.createObjectURL(file);
    try { img = await mag331LoadImageFromUrl(url, { crossOrigin: false }); }
    finally { URL.revokeObjectURL(url); }
  }
  const maxDim = 2400;
  const scale = Math.min(1, maxDim / Math.max(img.naturalWidth || img.width || maxDim, img.naturalHeight || img.height || maxDim));
  const canvas = document.createElement('canvas');
  canvas.width = Math.max(1, Math.round((img.naturalWidth || img.width || maxDim) * scale));
  canvas.height = Math.max(1, Math.round((img.naturalHeight || img.height || maxDim) * scale));
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
  const blob = await mag331CanvasToBlob(canvas, 'image/jpeg', 0.92);
  const base = mag331SafeFileSlug(String(file.name || 'advert-source-image').replace(/\.[^.]+$/, ''));
  return { blob, mimeType: 'image/jpeg', fileName: `${base || 'advert-source-image'}-source.jpg`, normalised: true };
}
async function mag331LoadAdvertSourceImageAsset(assetId = '', hash = '') {
  const requestedId = String(assetId || '').trim();
  const requestedHash = String(hash || '').trim();
  let sourceAsset = requestedId ? mag331FindAssetById(requestedId) : null;
  if (!sourceAsset && requestedHash) sourceAsset = mag331ExistingSourceImageForHash(requestedHash);
  const loadId = String(sourceAsset?.assetId || requestedId || '').trim();
  let lastError = null;

  const dataUrl = String(sourceAsset?.editorDataUrl || sourceAsset?.dataUrl || '').trim();
  if (dataUrl) {
    const img = await mag331LoadImageFromUrl(dataUrl, { crossOrigin: false });
    magazineAdvertBuilderState.sourceImageAssetId = sourceAsset.assetId || requestedId;
    magazineAdvertBuilderState.sourceImageHash = sourceAsset.contentHash || requestedHash || magazineAdvertBuilderState.sourceImageHash || '';
    magazineAdvertBuilderState.sourceImageTainted = false;
    return { image: img, asset: sourceAsset, method: 'asset-list-data-url' };
  }

  if (loadId || requestedHash) {
    try {
      const query = loadId ? `assetId=${encodeURIComponent(loadId)}` : `contentHash=${encodeURIComponent(requestedHash)}`;
      const data = await memberApiFetch(`/member/magazine/assets/file-data?${query}`, { method: 'GET' });
      const img = await mag331LoadImageFromUrl(data.dataUrl || '', { crossOrigin: false });
      if (data.contentHash && !magazineAdvertBuilderState.sourceImageHash) magazineAdvertBuilderState.sourceImageHash = data.contentHash;
      if (data.assetId) magazineAdvertBuilderState.sourceImageAssetId = data.assetId;
      magazineAdvertBuilderState.sourceImageTainted = false;
      return { image: img, asset: sourceAsset || data, method: 'data-url' };
    } catch (err) {
      lastError = err;
    }
  }

  if (sourceAsset?.viewUrl) {
    try {
      const response = await fetch(sourceAsset.viewUrl, { method: 'GET', mode: 'cors' });
      if (!response.ok) throw new Error(`Source image fetch failed with ${response.status}`);
      const blob = await response.blob();
      const objectUrl = URL.createObjectURL(blob);
      const img = await mag331LoadImageFromUrl(objectUrl, { crossOrigin: false });
      if (magazineAdvertBuilderState.imageObjectUrl) URL.revokeObjectURL(magazineAdvertBuilderState.imageObjectUrl);
      magazineAdvertBuilderState.imageObjectUrl = objectUrl;
      magazineAdvertBuilderState.sourceImageAssetId = sourceAsset.assetId || requestedId;
      magazineAdvertBuilderState.sourceImageHash = sourceAsset.contentHash || requestedHash || magazineAdvertBuilderState.sourceImageHash || '';
      magazineAdvertBuilderState.sourceImageTainted = false;
      return { image: img, asset: sourceAsset, method: 'signed-url-blob' };
    } catch (err) {
      lastError = err;
    }
    try {
      const img = await mag331LoadImageFromUrl(sourceAsset.viewUrl, { crossOrigin: false });
      magazineAdvertBuilderState.sourceImageAssetId = sourceAsset.assetId || requestedId;
      magazineAdvertBuilderState.sourceImageHash = sourceAsset.contentHash || requestedHash || magazineAdvertBuilderState.sourceImageHash || '';
      magazineAdvertBuilderState.sourceImageTainted = true;
      return { image: img, asset: sourceAsset, method: 'signed-url-preview-only' };
    } catch (err) {
      lastError = err;
    }
  }
  if (lastError) throw lastError;
  return null;
}

function mag331FindAdvertSourceImageForAsset(asset = {}, values = {}) {
  const directId = String(values.sourceImageAssetId || asset.sourceImageAssetId || '').trim();
  if (directId) {
    const direct = mag331FindAssetById(directId);
    if (direct && magazineAssetIsImage(direct)) return direct;
  }
  const h = String(values.sourceImageContentHash || asset.sourceImageContentHash || '').trim();
  if (h) {
    const hashed = mag331ExistingSourceImageForHash(h) || (magazineState.assets || []).find(candidate => magazineAssetIsImage(candidate) && !candidate.isAdvertRender && String(candidate.contentHash || '') === h);
    if (hashed) return hashed;
  }
  return null;
}
