    borderWidth: layout.borderWidth ?? mag331NumberFromAsset(asset, 'borderWidth', 4),
    businessFontSize: fonts.businessFontSize || asset.businessFontSize || MAG331_FONT_FIELDS.business.defaultSize,
    headlineFontSize: fonts.headlineFontSize || asset.headlineFontSize || MAG331_FONT_FIELDS.headline.defaultSize,
    bodyFontSize: fonts.bodyFontSize || asset.bodyFontSize || MAG331_FONT_FIELDS.body.defaultSize,
