function mag331NextAdvertVersionNumber(designId = '') {
  const versions = mag331AdvertVersionsForDesign(designId);
  return versions.reduce((max, asset) => Math.max(max, mag331AdvertVersionNumber(asset)), 0) + 1;
}
function mag331AdvertLibraryItems() {
  const adverts = (magazineState.assets || []).filter(asset => !magazineAssetIsInternalMetadata(asset) && magazineAssetIsAdvert(asset));
  const sorted = adverts.slice().sort((a, b) => {
    const da = mag331AdvertDesignId(a);
    const db = mag331AdvertDesignId(b);
    if (da !== db) return String(magazineAssetDisplayTitle(a)).localeCompare(String(magazineAssetDisplayTitle(b)));
    return mag331AdvertVersionNumber(b) - mag331AdvertVersionNumber(a);
  });
  if (magazineState.showAllAdvertVersions) return sorted;
  const byDesign = new Map();
  sorted.forEach(asset => {
    const key = mag331AdvertDesignId(asset) || asset.assetId;
    const current = byDesign.get(key);
    if (!current || asset.isCurrentAdvertVersion || mag331AdvertVersionNumber(asset) > mag331AdvertVersionNumber(current)) byDesign.set(key, asset);
  });
  return Array.from(byDesign.values()).sort((a, b) => String(magazineAssetDisplayTitle(a)).localeCompare(String(magazineAssetDisplayTitle(b))));
}
async function mag331EnsureBuilderSourceImageAsset(values = {}) {
  const existingId = magazineAdvertBuilderState.sourceImageAssetId;
  const file = magazineAdvertBuilderState.sourceImageFile;
  if (existingId && !file) return existingId;
  if (!file && magazineAdvertBuilderState.sourceImageHash) {
    const existingByHash = mag331ExistingSourceImageForHash(magazineAdvertBuilderState.sourceImageHash);
    if (existingByHash?.assetId) {
      magazineAdvertBuilderState.sourceImageAssetId = existingByHash.assetId;
      return existingByHash.assetId;
    }
  }
  if (!file) return '';
  const prepared = await mag331PrepareAdvertSourceImageBlob(file);
  const uploadBlob = prepared?.blob || file;
  const uploadMime = prepared?.mimeType || file.type || 'application/octet-stream';
  const uploadName = prepared?.fileName || file.name;
  const hash = await mag331Sha256Hex(uploadBlob);
  magazineAdvertBuilderState.sourceImageHash = hash;
  const existing = mag331ExistingSourceImageForHash(hash);
  if (existing?.assetId) {
    magazineAdvertBuilderState.sourceImageAssetId = existing.assetId;
    mag331BuilderSourceImageStatus(`Reusing existing source image from Assets Register: ${magazineAssetDisplayTitle(existing)}`);
    return existing.assetId;
  }
  const title = values.title || values.advertiserName || values.headline || file.name || 'Advert source image';
  mag331BuilderSourceImageStatus('Saving source image to Assets Register…');
  const metadata = {
    fileName: uploadName,
    mimeType: uploadMime,
    fileSizeBytes: uploadBlob.size,
    issueId: magazineState.selectedIssueId || 'unassigned',
    assetType: 'advert_source_image',
    materialType: 'image',
    title: `Source image — ${title}`,
    displayName: `Source image — ${title}`,
    contentHash: hash,
    originalFileName: file.name,
    notes: prepared?.normalised ? `Working copy normalised from ${file.name} for advert editing.` : '',
    source: 'advert_builder_source_image',
    status: 'available'
  };
  const prep = await memberApiFetch('/member/magazine/assets/upload-url', { method: 'POST', body: JSON.stringify(metadata) });
  if (prep.reuseAsset && prep.existingAsset?.assetId) {
    if (prep.existingAsset) magazineState.assets = [prep.existingAsset, ...(magazineState.assets || []).filter(asset => asset.assetId !== prep.existingAsset.assetId)];
    magazineAdvertBuilderState.sourceImageAssetId = prep.existingAsset.assetId;
    mag331BuilderSourceImageStatus(`Reusing existing source image from Assets Register: ${magazineAssetDisplayTitle(prep.existingAsset)}`);
    return prep.existingAsset.assetId;
  }
  const put = await fetch(prep.uploadUrl, { method: 'PUT', headers: { 'Content-Type': metadata.mimeType }, body: uploadBlob });
  if (!put.ok) throw new Error(`S3 source image upload failed with ${put.status}`);
  const data = await memberApiFetch('/member/magazine/assets/confirm-upload', { method: 'POST', body: JSON.stringify({ ...metadata, assetId: prep.assetId, key: prep.key, originalSourcePath: prep.key }) });
  if (data.item) magazineState.assets = [data.item, ...(magazineState.assets || []).filter(asset => asset.assetId !== data.item.assetId)];
  magazineAdvertBuilderState.sourceImageAssetId = prep.assetId;
  mag331BuilderSourceImageStatus('Saved source image to the Assets Register.');
  return prep.assetId;
}
function mag331BuildVersionMetadata(values, designId, versionNumber, renderAssetId, renderKey, sourceImageAssetId, metadataAssetId = '', metadataPath = '') {
  return {
    schema: 'lroc.advert.version.v1',
    advertDesignId: designId,
    versionNumber,
    versionLabel: `v${versionNumber}`,
    title: values.title || values.advertiserName || values.headline || 'Created advert',
    advertiserName: values.advertiserName,
    sizeType: values.sizeType,
    orientation: mag331AdvertOrientationFor(values.sizeType),
    layoutTemplate: values.layoutTemplate,
    sourceImageAssetId,
    sourceImageContentHash: magazineAdvertBuilderState.sourceImageHash || '',
    renderAssetId,
    renderS3Key: renderKey,
    baseRenderAssetId: magazineAdvertBuilderState.editingFromRenderAssetId || '',
    metadataAssetId,
    metadataPath,
    createdAt: new Date().toISOString(),
    design: {
      title: values.title || values.advertiserName || values.headline || 'Created advert',
      advertiserName: values.advertiserName,
      expiryDate: values.expiryDate,
      sizeType: values.sizeType,
      orientation: mag331AdvertOrientationFor(values.sizeType),
      layoutTemplate: values.layoutTemplate,
      sourceImageAssetId,
      sourceImageContentHash: magazineAdvertBuilderState.sourceImageHash || '',
      text: { headline: values.headline, bodyText: values.bodyText, contactDetails: values.contactDetails },
      style: { washColor: values.washColor, washStrength: values.washStrength, borderColor: values.borderColor, showInnerBoxes: values.showInnerBoxes },
      layout: { headerPct: values.headerPct, imagePct: values.imagePct, imageWidthPct: values.imageWidthPct, contactPct: values.contactPct, paddingPct: values.paddingPct, gapPct: values.gapPct, borderWidth: values.borderWidth },
      fonts: { businessFontSize: values.businessFontSize, headlineFontSize: values.headlineFontSize, bodyFontSize: values.bodyFontSize, contactFontSize: values.contactFontSize }
    }
  };
}
async function mag331UploadAdvertVersionJson(versionMeta, title, designId, versionNumber) {
  const json = JSON.stringify(versionMeta, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const filename = `${mag331SafeFileSlug(`${title}-metadata-v${versionNumber}`)}.json`;
  const metadata = {
    fileName: filename,
    mimeType: 'application/json',
    fileSizeBytes: blob.size,
    issueId: magazineState.selectedIssueId || 'unassigned',
    assetType: 'advert_version_json',
    materialType: 'metadata',
    title: `${title} metadata v${versionNumber}`,
    displayName: `${title} metadata v${versionNumber}`,
    advertDesignId: designId,
    advertVersionNumber: versionNumber,
    advertVersionLabel: `v${versionNumber}`,
    source: 'advert_builder_version_json',
    status: 'internal'
  };
  const prep = await memberApiFetch('/member/magazine/assets/upload-url', { method: 'POST', body: JSON.stringify(metadata) });
  const put = await fetch(prep.uploadUrl, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: blob });
  if (!put.ok) throw new Error(`S3 version metadata upload failed with ${put.status}`);
  const data = await memberApiFetch('/member/magazine/assets/confirm-upload', { method: 'POST', body: JSON.stringify({ ...metadata, assetId: prep.assetId, key: prep.key, advertVersionMetadataJson: json, advertVersionMetadataPath: prep.key }) });
  if (data.item) magazineState.assets = [data.item, ...(magazineState.assets || []).filter(asset => asset.assetId !== data.item.assetId)];
  return { assetId: prep.assetId, path: prep.key, json };
}
async function mag331UploadGeneratedAdvert(blob) {
  const values = mag331AdvertBuilderValues();
  const title = values.title || values.advertiserName || values.headline || 'Created advert';
  const sizeLabel = magazineAssetSizeLabel({ sizeType: values.sizeType }) || 'advert';
  const designId = magazineAdvertBuilderState.editingDesignId || `advert-design-${mag331UuidPart()}`;
  const versionNumber = mag331NextAdvertVersionNumber(designId);
  const sourceImageAssetId = await mag331EnsureBuilderSourceImageAsset(values);
  const filename = `${mag331SafeFileSlug(`${title}-${sizeLabel}-v${versionNumber}`)}.png`;
  const issueId = magazineState.selectedIssueId || 'unassigned';
  const baseMetadata = {
    fileName: filename,
    displayName: title,
    assetTitle: title,
    advertTitle: title,
    mimeType: 'image/png',
    fileSizeBytes: blob.size,
    issueId,
    assetType: 'advertisement',
    title,
    advertiserName: values.advertiserName,
    headline: values.headline,
    bodyCopy: values.bodyText,
    sizeType: values.sizeType,
    advertSizeType: values.sizeType,
    orientation: mag331AdvertOrientationFor(values.sizeType),
    expiryDate: values.expiryDate,
    layoutTemplate: values.layoutTemplate,
    washColor: values.washColor,
    washStrength: values.washStrength,
    borderColor: values.borderColor,
    showInnerBoxes: values.showInnerBoxes,
    headerPct: values.headerPct,
    imagePct: values.imagePct,
    imageWidthPct: values.imageWidthPct,
    contactPct: values.contactPct,
    paddingPct: values.paddingPct,
    gapPct: values.gapPct,
    borderWidth: values.borderWidth,
    businessFontSize: values.businessFontSize,
    headlineFontSize: values.headlineFontSize,
    bodyFontSize: values.bodyFontSize,
    contactFontSize: values.contactFontSize,
    bodyText: [values.headline, values.bodyText].filter(Boolean).join('\n\n'),
    contactDetails: values.contactDetails,
    notes: values.contactDetails,
    materialType: 'advert',
    status: 'active',
    source: 'advert_builder',
    sourceImageAssetId,
    sourceImageContentHash: magazineAdvertBuilderState.sourceImageHash || '',
    advertDesignId: designId,
    advertVersionNumber: versionNumber,
    advertVersionLabel: `v${versionNumber}`,
    advertVersionSortKey: `${String(versionNumber).padStart(5, '0')}#${new Date().toISOString()}`,
    isAdvertRender: true,
    isCurrentAdvertVersion: true,
    baseRenderAssetId: magazineAdvertBuilderState.editingFromRenderAssetId || ''
  };
  const prep = await memberApiFetch('/member/magazine/assets/upload-url', { method: 'POST', body: JSON.stringify(baseMetadata) });
  const put = await fetch(prep.uploadUrl, { method: 'PUT', headers: { 'Content-Type': 'image/png' }, body: blob });
  if (!put.ok) throw new Error(`S3 upload failed with ${put.status}`);
  let versionMeta = mag331BuildVersionMetadata(values, designId, versionNumber, prep.assetId, prep.key, sourceImageAssetId);
  const jsonInfo = await mag331UploadAdvertVersionJson(versionMeta, title, designId, versionNumber);
  versionMeta = { ...versionMeta, metadataAssetId: jsonInfo.assetId, metadataPath: jsonInfo.path };
  const versionJson = JSON.stringify(versionMeta, null, 2);
  const data = await memberApiFetch('/member/magazine/assets/confirm-upload', { method: 'POST', body: JSON.stringify({ ...baseMetadata, assetId: prep.assetId, key: prep.key, generatedImagePath: prep.key, currentRenderAssetId: prep.assetId, advertVersionMetadataAssetId: jsonInfo.assetId, advertVersionMetadataPath: jsonInfo.path, advertVersionMetadataJson: versionJson }) });
  magazineAdvertBuilderState.editingDesignId = designId;
  magazineAdvertBuilderState.editingFromRenderAssetId = prep.assetId;
  magazineAdvertBuilderState.editingVersionNumber = versionNumber;
  return data;
}

async function magazineSaveCreatedAdvert() {
  mag331RefreshAdvertFitGuardrails();
  if (magazineAdvertBuilderState.fitOverflow) throw new Error('One or more text boxes cannot fit even at the minimum size. Shorten the text or adjust the box sliders before saving.');
  mag331AdvertNotice('Rendering advert PNG…');
  let blob;
  try { blob = await mag331RenderAdvertPreview({ skipGuardrails: true }); }
  catch (err) {
    if (magazineAdvertBuilderState.sourceImageTainted) throw new Error('The saved source image could be previewed but not safely rendered by the browser. Reselect the source image once, then save again.');
    throw err;
  }
  if (!blob) throw new Error('Could not render advert preview.');
  mag331AdvertNotice('Saving generated PNG, editable metadata and source-image links to Advert Library…');
  const values = mag331AdvertBuilderValues();
  const title = values.title || values.advertiserName || values.headline || 'Created advert';
  const data = await mag331UploadGeneratedAdvert(blob);
  mag331AdvertNotice(`Saved “${title}” as the latest advert version. Older versions remain available under Show all versions.`, 'success');
  await magazineLoadAssets();
  magazineSwitchTab('adverts');
}
async function magazineDownloadCreatedAdvert() {
  mag331RefreshAdvertFitGuardrails();
  if (magazineAdvertBuilderState.fitOverflow) throw new Error('One or more text boxes cannot fit even at the minimum size. Shorten the text or adjust the box sliders before downloading.');
  let blob;
  try { blob = await mag331RenderAdvertPreview({ skipGuardrails: true }); }
  catch (err) {
    if (magazineAdvertBuilderState.sourceImageTainted) throw new Error('The saved source image could be previewed but not safely rendered by the browser. Reselect the source image once, then save again.');
    throw err;
  }
  if (!blob) throw new Error('Could not render advert preview.');
  const values = mag331AdvertBuilderValues();
  const title = values.title || values.advertiserName || values.headline || 'created-advert';
  const sizeLabel = magazineAssetSizeLabel({ sizeType: values.sizeType }) || 'advert';
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${mag331SafeFileSlug(`${title}-${sizeLabel}`)}.png`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
  mag331AdvertNotice('PNG downloaded. Save to the library as well if you want to reuse it in an issue.', 'success');
}
function magazineBindAdvertBuilder() {
  const canvas = document.getElementById('magAdvertBuilderCanvas');
  if (!canvas) return;
  ['magAdvertBuilderTitle','magAdvertBuilderAdvertiser','magAdvertBuilderHeadline','magAdvertBuilderBody','magAdvertBuilderContact','magAdvertBuilderSizeType','magAdvertBuilderTemplate','magAdvertBuilderWashColor','magAdvertBuilderWashStrength','magAdvertBuilderBorderColor','magAdvertBuilderInnerBoxes','magAdvertBuilderHeaderPct','magAdvertBuilderImagePct','magAdvertBuilderImageWidthPct','magAdvertBuilderContactPct','magAdvertBuilderPaddingPct','magAdvertBuilderGapPct','magAdvertBuilderBorderWidth','magAdvertBuilderBusinessFontSize','magAdvertBuilderHeadlineFontSize','magAdvertBuilderBodyFontSize','magAdvertBuilderContactFontSize','magAdvertBuilderExpiryDate'].forEach(id => {
    const el = document.getElementById(id);
    if (el) ['input','change'].forEach(evt => el.addEventListener(evt, mag331ScheduleAdvertPreview));
  });
  document.getElementById('magAdvertBuilderImage')?.addEventListener('change', event => {
    const file = event.target.files?.[0];
    if (!file) { mag331BuilderSourceImageStatus('No new image selected. Existing source image will be reused if this is an edit.'); mag331ScheduleAdvertPreview(); return; }
    if (!String(file.type || '').startsWith('image/')) { mag331AdvertNotice('Choose an image file for the visual advert builder.', 'warning'); return; }
    if (magazineAdvertBuilderState.imageObjectUrl) URL.revokeObjectURL(magazineAdvertBuilderState.imageObjectUrl);
    magazineAdvertBuilderState.imageObjectUrl = '';
    magazineAdvertBuilderState.imageElement = null;
    magazineAdvertBuilderState.sourceImageFile = file;
    magazineAdvertBuilderState.sourceImageAssetId = '';
    magazineAdvertBuilderState.sourceImageHash = '';
    magazineAdvertBuilderState.sourceImageTainted = false;
    mag331BuilderSourceImageStatus('New source image selected. It will be saved/reused in the Assets Register when you save the advert.');
    const img = new Image();
    const url = URL.createObjectURL(file);
    magazineAdvertBuilderState.imageObjectUrl = url;
    img.onload = () => { magazineAdvertBuilderState.imageElement = img; mag331ScheduleAdvertPreview(); };
    img.onerror = () => mag331AdvertNotice('Could not read that image file.', 'warning');
    img.src = url;
  });
  document.getElementById('magAdvertBuilderPickAssetBtn')?.addEventListener('click', () => mag337OpenAssetPicker({ title: 'Select advert source image', imagesOnly: true, selectedAssetId: magazineAdvertBuilderState.sourceImageAssetId, onSelect: mag337SelectExistingAdvertSourceAsset }));
  document.getElementById('magAdvertBuilderNewBtn')?.addEventListener('click', () => mag331ResetAdvertBuilder());
  document.getElementById('magAdvertBuilderPreviewBtn')?.addEventListener('click', () => mag331RenderAdvertPreview().then(() => mag331AdvertNotice('Preview updated.', 'success')).catch(err => mag331AdvertNotice(err.message, 'warning')));
  document.getElementById('magAdvertBuilderSaveBtn')?.addEventListener('click', () => magazineSaveCreatedAdvert().catch(err => mag331AdvertNotice(err.message, 'warning')));
  document.getElementById('magAdvertBuilderDownloadBtn')?.addEventListener('click', () => magazineDownloadCreatedAdvert().catch(err => mag331AdvertNotice(err.message, 'warning')));
  mag331RefreshAdvertFitGuardrails();
  mag331RenderAdvertPreview({ skipGuardrails: true }).catch(err => mag331AdvertNotice(err.message, 'warning'));
}

function magazineAdvertPreviewHtml(asset = {}) {
  const sourceNote = magazineAssetIsPdf(asset) ? '<div class="tag warning-tag">PDF source stored</div>' : (magazineAssetIsImage(asset) ? '<div class="tag success-tag">Image advert</div>' : '<div class="tag">Advert asset</div>');
  return `<div class="mag33-advert-preview">${sourceNote}${magazineAssetPreviewHtml(asset, 'Advert preview')}</div>`;
}

function magazineRenderAdvertLibrary() {
  const list = document.getElementById('magazineAdvertList');
  const notice = document.getElementById('magazineAdvertNotice');
  const toggle = document.getElementById('magazineToggleAdvertVersionsBtn');
  if (toggle) toggle.textContent = magazineState.showAllAdvertVersions ? 'Show latest only' : 'Show all versions';
  if (!list && !notice) return;
  const allAdverts = (magazineState.assets || []).filter(asset => !magazineAssetIsInternalMetadata(asset) && magazineAssetIsAdvert(asset));
  const adverts = mag331AdvertLibraryItems();
  const designCount = new Set(allAdverts.map(asset => mag331AdvertDesignId(asset) || asset.assetId)).size;
  if (notice) notice.textContent = allAdverts.length ? `${designCount} advert design${designCount === 1 ? '' : 's'} / ${allAdverts.length} stored version${allAdverts.length === 1 ? '' : 's'}. ${magazineState.showAllAdvertVersions ? 'Showing every version.' : 'Showing latest versions only.'}` : 'No adverts imported yet.';
  if (!list) return;
  if (!adverts.length) {
    list.innerHTML = '<div class="notice"><strong>No adverts in the library yet.</strong><div style="margin-top:8px">Import ready-made image/PDF advert artwork above. Use Create Advert above to make a boxed print advert from an image and wording, or import ready-made artwork.</div></div>';
    return;
  }
  list.innerHTML = '<div class="magazine337-gallery-grid">' + adverts.map(asset => mag337AssetGalleryCardHtml(asset)).join('') + '</div>';
  list.querySelectorAll('[data-mag337-gallery-asset]').forEach(tile => tile.addEventListener('click', () => mag337OpenAssetActionMenu(tile.dataset.mag337GalleryAsset || '')));
}

function magazineUseAsset(assetId, where) {
  if (!magazineState.selectedIssue) { showToast('Open an issue before assigning assets.', { kind: 'warning' }); return; }
  const target = where === 'cover' ? document.getElementById('magDetailCoverAsset') : document.getElementById('magDetailBackCoverAsset');
  const formTarget = where === 'cover' ? document.getElementById('magIssueCoverAsset') : document.getElementById('magIssueBackCoverAsset');
  if (target) target.value = assetId || ''; if (formTarget) formTarget.value = assetId || '';
  magazineSwitchTab('detail');
  showToast(where === 'cover' ? 'Cover asset selected. Save assignments when ready.' : 'Back cover asset selected. Save assignments when ready.');
}
async function magazineLoadAssets() {
  magazineNotice('magazineAssetNotice', 'Loading assets register…');
  const data = await memberApiFetch('/member/magazine/assets', { method: 'GET' });
  magazineState.assets = data.items || [];
  magazineRenderAssets(); magazineRenderAdvertLibrary(); magazineRenderIssueDetail(); magazineRenderComposerPanel();
  magazineNotice('magazineAssetNotice', `${magazineState.assets.length} asset(s) loaded. Max upload ${magazineBytesLabel(data.maxUploadBytes)}.`, 'success');
}
async function magazineUploadAsset() {
  const file = document.getElementById('magAssetFile')?.files?.[0];
  if (!file) { magazineNotice('magazineAssetNotice', 'Choose a file first.', 'warning'); return; }
  const issueId = document.getElementById('magAssetIssueId')?.value || magazineState.selectedIssueId || 'unassigned';
  const assetType = document.getElementById('magAssetType')?.value || 'asset';
  const title = document.getElementById('magAssetTitle')?.value || '';
  const notes = document.getElementById('magAssetNotes')?.value || '';
  magazineNotice('magazineAssetNotice', `Preparing import for ${file.name}…`);
  const reuse = await mag337MaybeReuseExistingImageAsset(file, 'magazineAssetNotice');
  if (reuse?.assetId) {
    document.getElementById('magAssetFile').value = '';
    magazineRenderAssets();
    return;
  }
  const contentHash = reuse?.contentHash || '';
  const metadata = { fileName: file.name, mimeType: file.type || 'application/octet-stream', fileSizeBytes: file.size, issueId, assetType, title, notes, contentHash };
  const prep = await memberApiFetch('/member/magazine/assets/upload-url', { method: 'POST', body: JSON.stringify(metadata) });
  if (prep.reuseAsset && prep.existingAsset?.assetId) {
    magazineState.assets = [prep.existingAsset, ...(magazineState.assets || []).filter(asset => asset.assetId !== prep.existingAsset.assetId)];
    magazineNotice('magazineAssetNotice', `Reusing existing image asset: ${magazineAssetDisplayTitle(prep.existingAsset)}. No duplicate upload was created.`, 'success');
    document.getElementById('magAssetFile').value = '';
    magazineRenderAssets();
    return;
  }
  const put = await fetch(prep.uploadUrl, { method: 'PUT', headers: { 'Content-Type': file.type || 'application/octet-stream' }, body: file });
  if (!put.ok) throw new Error(`S3 upload failed with ${put.status}`);
  await memberApiFetch('/member/magazine/assets/confirm-upload', { method: 'POST', body: JSON.stringify({ ...metadata, assetId: prep.assetId, key: prep.key, materialType: magazineAssetIsAdvert({ assetType }) ? 'advert' : assetType }) });
  magazineNotice('magazineAssetNotice', `Imported ${file.name} as a reusable asset.`, 'success');
  const fileInput = document.getElementById('magAssetFile'); if (fileInput) fileInput.value = '';
  await magazineLoadAssets();
}

function mag3433InferAdvertShapeFromRatio(ratio = 1) {
  const r = Number(ratio || 1);
  if (!Number.isFinite(r) || r <= 0) return { orientation: 'auto', sizeType: 'unknown' };
  if (r > 2.15) return { orientation: 'landscape', sizeType: 'banner_strip' };
  if (r > 1.25) return { orientation: 'landscape', sizeType: 'half_page_landscape' };
  if (r < 0.58) return { orientation: 'portrait', sizeType: 'half_page_portrait' };
  if (r < 0.82) return { orientation: 'portrait', sizeType: 'full_page_portrait' };
  return { orientation: 'square', sizeType: 'quarter_page' };
}
function mag3433AutoSenseAdvertFile(file) {
  if (!file || !String(file.type || '').startsWith('image/')) return;
  const url = URL.createObjectURL(file);
  const img = new Image();
  img.onload = () => {
    try {
      const shape = mag3433InferAdvertShapeFromRatio((img.naturalWidth || 1) / Math.max(1, img.naturalHeight || 1));
      const orientationEl = document.getElementById('magAdvertOrientation');
      const sizeEl = document.getElementById('magAdvertSizeType');
      if (orientationEl && (!orientationEl.value || orientationEl.value === 'auto')) orientationEl.value = shape.orientation;
      if (sizeEl && (!sizeEl.value || sizeEl.value === 'unknown')) sizeEl.value = shape.sizeType;
      magazineNotice('magazineAdvertNotice', `Image advert detected: ${img.naturalWidth}×${img.naturalHeight}. Shape set to ${shape.sizeType.replace(/_/g, ' ')} / ${shape.orientation}.`, 'success');
    } finally {
      URL.revokeObjectURL(url);
    }
  };
  img.onerror = () => URL.revokeObjectURL(url);
  img.src = url;
}

async function magazineUploadAdvert() {
  const file = document.getElementById('magAdvertFile')?.files?.[0];
  if (!file) { magazineNotice('magazineAdvertNotice', 'Choose an advert file first.', 'warning'); return; }
  const mimeType = file.type || (file.name.toLowerCase().endsWith('.pdf') ? 'application/pdf' : 'application/octet-stream');
  if (!(mimeType.startsWith('image/') || mimeType === 'application/pdf')) { magazineNotice('magazineAdvertNotice', 'Advert import currently accepts image files or PDFs.', 'warning'); return; }
  const issueId = magazineState.selectedIssueId || 'unassigned';
  const assetType = mimeType === 'application/pdf' ? 'advert_pdf' : 'advertisement';
  const title = document.getElementById('magAdvertTitle')?.value || file.name;
  const advertiserName = document.getElementById('magAdvertiserName')?.value || '';
  const sizeType = document.getElementById('magAdvertSizeType')?.value || 'unknown';
  const orientation = document.getElementById('magAdvertOrientation')?.value || 'auto';
  const expiryDate = document.getElementById('magAdvertExpiryDate')?.value || '';
  const notes = document.getElementById('magAdvertNotes')?.value || '';
  magazineNotice('magazineAdvertNotice', `Preparing advert import for ${file.name}…`);
  // v3.4.33: Advert Library import treats the selected image as finished
  // advert artwork. Do not reuse a normal image asset by content hash, because
  // the editor deliberately wants an Advert Library item with advert metadata.
  const contentHash = mimeType.startsWith('image/') ? await mag331Sha256Hex(file).catch(() => '') : '';
  const metadata = { fileName: file.name, mimeType, fileSizeBytes: file.size, issueId, assetType, title, advertiserName, sizeType, advertSizeType: sizeType, orientation, expiryDate, notes, contactDetails: notes, materialType: 'advert', status: 'active', source: 'advert_import', contentHash: '' };
  if (contentHash) metadata.sourceContentHash = contentHash;
  const prep = await memberApiFetch('/member/magazine/assets/upload-url', { method: 'POST', body: JSON.stringify(metadata) });
  if (prep.reuseAsset && prep.existingAsset?.assetId) {
    magazineState.assets = [prep.existingAsset, ...(magazineState.assets || []).filter(asset => asset.assetId !== prep.existingAsset.assetId)];
    magazineNotice('magazineAdvertNotice', `Reusing existing image asset: ${magazineAssetDisplayTitle(prep.existingAsset)}. No duplicate advert upload was created.`, 'success');
    ['magAdvertFile','magAdvertTitle','magAdvertiserName','magAdvertExpiryDate','magAdvertNotes'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
    magazineRenderAdvertLibrary();
    return;
  }
  const put = await fetch(prep.uploadUrl, { method: 'PUT', headers: { 'Content-Type': mimeType }, body: file });
  if (!put.ok) throw new Error(`S3 upload failed with ${put.status}`);
  await memberApiFetch('/member/magazine/assets/confirm-upload', { method: 'POST', body: JSON.stringify({ ...metadata, assetId: prep.assetId, key: prep.key }) });
  magazineNotice('magazineAdvertNotice', `Imported advert ${title || file.name}.`, 'success');
  ['magAdvertFile','magAdvertTitle','magAdvertiserName','magAdvertExpiryDate','magAdvertNotes'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  await magazineLoadAssets();
  magazineSwitchTab('adverts');
}
async function magazineLoadInbound() {
  const suffix = magazineState.showAllInbound ? '?all=true&limit=100' : '?limit=100';
  const data = await memberApiFetch(`/member/magazine/inbound${suffix}`, { method: 'GET' });
  const sources = document.getElementById('magazineInboundSources');
  if (sources) sources.innerHTML = (data.sources || []).map(src => `<article class="card card-pad"><div class="eyebrow">${escapeHtml(src.status || 'active')}</div><h3>${escapeHtml(src.address || '')}</h3><p class="muted">${escapeHtml(src.kind || '')}</p></article>`).join('');
  const list = document.getElementById('magazineInboundList');
  if (!list) return;
  const items = data.items || [];
  const toggleHtml = `<div class="auth-actions" style="margin-bottom:12px"><button class="button ghost" id="magazineToggleAllInboundBtn" type="button">${magazineState.showAllInbound ? 'Show pending inbound only' : 'Show all inbound'}</button></div>`;
  list.innerHTML = toggleHtml + (items.length ? items.map(item => {
    const status = item.status || 'stored';
    const statusLabel = magazineInboundStatusLabel(item);
    const tagClass = magazineInboundStatusTagClass(item);
    const convertedNote = item.content_item_id ? `<div class="notice" style="margin-top:10px"><strong>Converted to content item:</strong> ${escapeHtml(item.content_item_id)}<div class="muted small-text" style="margin-top:4px">This source submission has been consumed. The new content item should still be pending/available until you place it in an issue.</div></div>` : '';
    return `<article class="card card-pad"><div class="space-between gap-wrap"><div><h3 style="margin:0">${escapeHtml(item.subject || item.filename || 'Inbound material')}</h3><div class="muted small-text">${escapeHtml(item.kind || '')} • ${escapeHtml(item.filename || '')} • ${escapeHtml(status)} • ${escapeHtml(item.received_at || item.created_at || '')}</div></div><span class="${escapeHtml(tagClass)}">${escapeHtml(statusLabel)}</span></div><div class="small-text muted" style="margin-top:8px">From: ${escapeHtml(item.from || '')}</div><div class="auth-actions" style="margin-top:12px">${item.viewUrl ? `<a class="button secondary" href="${escapeHtml(item.viewUrl)}" target="_blank" rel="noopener">Open source</a>` : ''}${item.canConvert ? `<button class="button" type="button" data-mag-convert-submission="${escapeHtml(item.submission_id || '')}" data-mag-convert-kind="${escapeHtml(item.kind || '')}" data-mag-convert-sk="${escapeHtml(item.sk || '')}" data-mag-convert-title="${escapeHtml(item.subject || item.filename || '')}">Convert to content</button>` : ''}</div>${convertedNote}</article>`;
  }).join('') : `<div class="notice"><strong>No pending inbound magazine material.</strong><div style="margin-top:8px">Send source material to magazinecontent@, vendor material to vendorcontent@, or click Show all to include already converted items.</div></div>`);
  document.getElementById('magazineToggleAllInboundBtn')?.addEventListener('click', () => { magazineState.showAllInbound = !magazineState.showAllInbound; magazineLoadInbound().catch(err => showToast(err.message, { kind: 'warning' })); });
  list.querySelectorAll('[data-mag-convert-submission]').forEach(btn => btn.addEventListener('click', () => magazineConvertInboundSubmission(btn).catch(err => showToast(err.message, { kind: 'warning' }))));
}
async function magazineConvertInboundSubmission(btn) {
  const issueId = magazineState.selectedIssueId || 'unassigned';
  const kind = btn.dataset.magConvertKind || 'magazinecontent';
  const title = btn.dataset.magConvertTitle || '';
  const contentType = kind === 'tripreports' ? 'trip_report' : (kind === 'vendorcontent' ? 'advertisement' : 'article');
  const data = await memberApiFetch('/member/magazine/inbound/convert', { method: 'POST', body: JSON.stringify({ kind, sk: btn.dataset.magConvertSk || '', submissionId: btn.dataset.magConvertSubmission || '', issueId, title, contentType, status: 'pending', publicationStatus: 'pending' }) });
  showToast(`Converted inbound material to ${data.item?.contentItemId || 'content item'}`);
  await Promise.allSettled([magazineLoadInbound(), magazineLoadContent(magazineState.selectedIssueId || '')]);
}

function mag338TinyMceScriptUrl() {
  return 'https://cdn.jsdelivr.net/npm/tinymce@6/tinymce.min.js';
}
function mag338EnsureTinyMce() {
  if (window.tinymce) return Promise.resolve(window.tinymce);
  if (window.mag338TinyMceLoading) return window.mag338TinyMceLoading;
  window.mag338TinyMceLoading = new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = mag338TinyMceScriptUrl();
    script.referrerPolicy = 'origin';
    script.onload = () => window.tinymce ? resolve(window.tinymce) : reject(new Error('TinyMCE loaded but was not available.'));
    script.onerror = () => reject(new Error('Could not load TinyMCE. The plain textarea remains available.'));
    document.head.appendChild(script);
  });
  return window.mag338TinyMceLoading;
}

