function memberApiBaseUrl() {
  return window.LROC_MEMBER_API?.baseUrl || window.LROC_API?.baseUrl || '';
}

async function memberApiFetch(path, options = {}) {
  const baseUrl = memberApiBaseUrl();
  if (!baseUrl) throw new Error('Member API base URL is not configured.');
  const redirectOnUnauthorized = options.redirectOnUnauthorized !== false;
  const requestOptions = { ...options };
  delete requestOptions.redirectOnUnauthorized;
  const token = await window.lrocAuth?.getValidAccessToken?.();
  if (!token) {
    const err = new Error('Please sign in again.');
    err.status = 401;
    if (redirectOnUnauthorized && document.body?.dataset?.page !== 'members') {
      window.lrocAuth?.handleUnauthorized?.(window.location.href);
    }
    throw err;
  }
  const headers = {
    ...(requestOptions.body ? { 'Content-Type': 'application/json' } : {}),
    ...(requestOptions.headers || {}),
    Authorization: `Bearer ${token}`
  };
  const response = await fetch(`${baseUrl}${path}`, {
    ...requestOptions,
    headers
  });
  const text = await response.text();
  let data = {};
  try { data = text ? JSON.parse(text) : {}; } catch {}
  if (!response.ok) {
    const err = new Error(data.message || text || `Request failed with ${response.status}`);
    err.status = response.status;
    err.responseBody = data;
    if (response.status === 401 && redirectOnUnauthorized && document.body?.dataset?.page !== 'members') {
      window.lrocAuth?.handleUnauthorized?.(window.location.href);
    }
    throw err;
  }
  return data;
}


async function lrocMemberImportRollbackDirect(event) {
  event?.preventDefault?.();
  event?.stopPropagation?.();
  if (event) event.__lrocRollbackHandled = true;
  const rollbackBtn = document.getElementById('memberImportRollbackBtn');
  const rollbackBatchInput = document.getElementById('memberRollbackBatchId');
  const rollbackConfirmInput = document.getElementById('memberRollbackConfirm');
  const importNotice = document.getElementById('memberImportNotice');
  const notice = document.getElementById('memberMetaNotice');
  const countNotice = document.getElementById('memberMetaCountNotice');
  const statusTarget = importNotice || notice;
  if (statusTarget) statusTarget.textContent = 'Rollback button clicked. Checking confirmation…';
  if (!rollbackBtn) {
    if (statusTarget) statusTarget.textContent = 'Rollback controls are not available on this page.';
    return;
  }
  if (rollbackBtn.dataset.busy === '1') return;
  const confirmText = String(rollbackConfirmInput?.value || '').trim().toUpperCase();
  if (confirmText !== 'ROLLBACK') {
    if (statusTarget) statusTarget.textContent = 'Type ROLLBACK in the rollback confirm field first.';
    rollbackConfirmInput?.focus?.();
    return;
  }
  const batchId = String(rollbackBatchInput?.value || '').trim();
  if (!batchId) {
    if (statusTarget) statusTarget.textContent = 'Import batch ID is required. Blank/all-member rollback is disabled for data safety.';
    rollbackBatchInput?.focus?.();
    return;
  }
  const msg = `Delete uninvited CSV-import member records from batch ${batchId}?`;
  if (!window.confirm(msg)) {
    if (statusTarget) statusTarget.textContent = 'Rollback cancelled. No member records were deleted.';
    return;
  }
  rollbackBtn.disabled = true;
  rollbackBtn.dataset.busy = '1';
  const original = rollbackBtn.textContent;
  rollbackBtn.textContent = 'Rolling back…';
  if (statusTarget) statusTarget.textContent = 'Starting rollback…';
  try {
    let nextKey = null;
    let complete = false;
    let deleted = 0;
    let skipped = 0;
    let chunks = 0;
    while (!complete) {
      const data = await memberApiFetch('/admin/members/import-rollback', {
        method: 'POST',
        body: JSON.stringify({ batch_id: batchId, confirm: 'ROLLBACK', limit: 25, next_key: nextKey })
      });
      chunks += 1;
      deleted += Number(data.deleted || 0);
      skipped += Number(data.skipped || 0);
      nextKey = data.next_key || null;
      complete = Boolean(data.complete) || !nextKey;
      if (statusTarget) statusTarget.textContent = `Rolling back imports… chunk ${chunks}, deleted ${deleted}, skipped ${skipped}.`;
    }
    if (statusTarget) statusTarget.textContent = `Rollback complete for batch ${batchId}. Deleted ${deleted} uninvited CSV-import member record(s). Skipped ${skipped}.`;
    try {
      const data = await memberApiFetch('/admin/members/count', { method: 'GET' });
      const c = data.counts || {};
      if (countNotice) countNotice.textContent = `DynamoDB member metadata: ${Number(c.total_profiles || 0)} total profile record(s); ${Number(c.with_site_member_id || 0)} with member number; ${Number(c.imported_profiles || 0)} imported; ${Number(c.uninvited_imported || 0)} imported and uninvited; ${Number(c.invited_imported || 0)} imported and invited.`;
    } catch (countErr) {
      if (countNotice) countNotice.textContent = `Rollback finished, but member count refresh failed: ${countErr.message}`;
    }
  } catch (err) {
    if (statusTarget) statusTarget.textContent = `Could not rollback import: ${err.message}`;
  } finally {
    rollbackBtn.dataset.busy = '0';
    rollbackBtn.disabled = false;
    rollbackBtn.textContent = original || 'Rollback uninvited imports';
  }
}

window.lrocMemberImportRollbackDirect = lrocMemberImportRollbackDirect;
window.__lrocMemberImportRollbackClick = lrocMemberImportRollbackDirect;
if (!window.__lrocMemberImportRollbackDelegated) {
  window.__lrocMemberImportRollbackDelegated = true;
  document.addEventListener('click', (event) => {
    const target = event.target?.closest?.('#memberImportRollbackBtn');
    if (!target || event.__lrocRollbackHandled) return;
    lrocMemberImportRollbackDirect(event);
  }, true);
}

function collectFormData() {
  const fd = new FormData();
  document.querySelectorAll('.editor-pane:not(.hidden) input[name], .editor-pane:not(.hidden) textarea[name]').forEach(el => {
    fd.append(el.name, el.value);
  });
  document.querySelectorAll('.editor-pane.hidden input[name], .editor-pane.hidden textarea[name]').forEach(el => {
    fd.append(el.name, el.value);
  });
  return fd;
}

function applyFormToContent(formData, content) {
  const next = structuredClone(content);
  for (const [k,v] of formData.entries()) {
    if (k === 'pages.home.stats') {
      next.pages.home.stats = lines(v).map(line => {
        const [label, value] = splitPipe(line, 2);
        return { label, value };
      });
      continue;
    }
    if (k === 'pages.home.spotlight') {
      next.pages.home.spotlight = lines(v).map(line => {
        const [title, text] = splitPipe(line, 2);
        return { title, text };
      });
      continue;
    }
    if (k === 'pages.events.calendarRows') {
      const existingRows = Array.isArray(content.pages?.events?.calendarRows) ? content.pages.events.calendarRows : [];
      next.pages.events.calendarRows = lines(v).map((line, idx) => {
        const [date, event, details, location, eventId] = splitPipe(line, 5);
        const row = { date, event, details, location };
        const cleanEventId = String(eventId || '').trim();
        if (cleanEventId) row.event_id = cleanEventId;
        else if (existingRows[idx]?.event_id) row.event_id = String(existingRows[idx].event_id);
        if (existingRows[idx]?.details_pdf) row.details_pdf = structuredClone(existingRows[idx].details_pdf);
        return row;
      });
      continue;
    }
    if (k === 'pages.committee.committeeRows') {
      next.pages.committee.committeeRows = lines(v).map(line => {
        const [position, name, profile] = splitPipe(line, 3);
        return { name, position, profile };
      });
      continue;
    }
    if (k === 'pages.events.cards') {
      next.pages.events.cards = lines(v).map(line => {
        const [tag, title, summary, meta1, meta2] = splitPipe(line, 5);
        return { tag, title, summary, meta1, meta2 };
      });
      continue;
    }
    if (k === 'pages.tripGuides.items') {
      try {
        const parsed = JSON.parse(v || '[]');
        next.pages.tripGuides.items = Array.isArray(parsed) ? parsed.map(normaliseTripGuideRecord) : [];
      } catch {
        next.pages.tripGuides.items = [];
      }
      continue;
    }
    if (k === 'pages.training.cards') {
      next.pages.training.cards = lines(v).map(line => {
        const [tag, title, summary] = splitPipe(line, 3);
        return { tag, title, summary };
      });
      continue;
    }
    if (k === 'pages.documents.publicDocs' || k === 'pages.documents.memberDocs') {
      const target = k.endsWith('publicDocs') ? 'publicDocs' : 'memberDocs';
      next.pages.documents[target] = lines(v).map(line => {
        const [name, type, url] = splitPipe(line, 3);
        return { name, type, url };
      });
      continue;
    }
    if (k === 'pages.membership.card') {
      const line = lines(v)[0] || '';
      const [title, price, itemStr] = splitPipe(line, 3);
      const card = { title, price, items: itemStr.split(';').map(s=>s.trim()).filter(Boolean) };
      next.pages.membership.card = card;
      next.pages.membership.cards = [card];
      continue;
    }
    if (k === 'pages.members.features') {
      next.pages.members.features = lines(v);
      continue;
    }
    if (k === 'pages.about.body' || k === 'pages.privacy.body' || k === 'pages.terms.body' || k === 'pages.disclaimer.body' || k === 'pages.historicRegistration.body' || k === 'pages.historicRegistration.whatMembersSubmit') {
      const [,page,prop] = k.split('.');
      next.pages[page][prop] = lines(v);
      continue;
    }
    if (k === 'pages.policies.cards') {
      next.pages.policies.cards = lines(v).map(line => {
        const [tag, title, summary] = splitPipe(line, 3);
        return { tag, title, summary };
      }).filter(card => !isPrivacyPolicyCard(card));
      continue;
    }
    setByPath(next, k, v);
  }
  return next;
}
function lines(v) { return String(v).split('\n').map(s=>s.trim()).filter(Boolean); }
function splitPipe(line, count) {
  const parts = line.split('|').map(s=>s.trim());
  while (parts.length < count) parts.push('');
  return parts.slice(0, count);
}
function setByPath(obj, path, value) {
  const keys = path.split('.');
  let cursor = obj;
  for (let i=0;i<keys.length-1;i++) cursor = cursor[keys[i]];
  cursor[keys[keys.length-1]] = value;
}

