const lrocChimeState = {
  status: null,
  meetingSession: null,
  audioVideo: null,
  joined: false,
  muted: true,
  videoOn: false,
  shareOn: false,
  contentTileId: null,
  contentActive: false,
  screenOnly: false,
  attendeeId: '',
  canControl: false,
  lastControlAt: '',
  pollTimer: null,
  remoteTiles: new Map(),
  attendeeNames: new Map(),
  attendance: null,
  currentMemberInPerson: false,
  guests: [],
  agenda: null,
};

function chimeSetText(id, text, className = '') {
  const el = document.getElementById(id);
  if (!el) return;
  el.className = className || el.className;
  el.textContent = text;
}

function chimeSdkGlobal() {
  const candidates = [
    window.ChimeSDK,
    window.chimeSDK,
    window.amazonChimeSDK,
    window.AmazonChimeSDK,
    window.amazon_chime_sdk_js
  ];
  return candidates.find(sdk => sdk && sdk.ConsoleLogger && sdk.DefaultMeetingSession && sdk.MeetingSessionConfiguration) || null;
}

function ensureChimeSdkLoaded(timeoutMs = 15000) {
  const existing = chimeSdkGlobal();
  if (existing) return Promise.resolve(existing);
  if (window.lrocChimeSdkLoadError) return Promise.reject(new Error(window.lrocChimeSdkLoadError));
  return new Promise((resolve, reject) => {
    const started = Date.now();
    let timer = null;
    const failMessage = () => window.lrocChimeSdkLoadError || 'Amazon Chime SDK did not load. Check browser connectivity/content blockers, then reload this page.';
    const done = () => {
      cleanup();
      const sdk = chimeSdkGlobal();
      if (sdk) resolve(sdk);
      else reject(new Error(failMessage()));
    };
    const failed = event => {
      cleanup();
      reject(new Error(event?.detail?.message || failMessage()));
    };
    const cleanup = () => {
      if (timer) clearTimeout(timer);
      window.removeEventListener('lroc:chime-sdk-loaded', done);
      window.removeEventListener('lroc:chime-sdk-failed', failed);
    };
    window.addEventListener('lroc:chime-sdk-loaded', done, { once: true });
    window.addEventListener('lroc:chime-sdk-failed', failed, { once: true });
    timer = setInterval(() => {
      if (chimeSdkGlobal()) done();
      else if (window.lrocChimeSdkLoadError) failed({ detail: { message: window.lrocChimeSdkLoadError } });
      else if (Date.now() - started >= timeoutMs) { cleanup(); reject(new Error(failMessage())); }
    }, 250);
  });
}


function chimeMeetingTypeLabel(type) {
  const labels = { monthly: 'Monthly meeting', committee: 'Committee meeting', general: 'General meeting', agm: 'Annual General Meeting' };
  return labels[String(type || 'monthly')] || labels.monthly;
}

function chimeMeetingIsFormal(type) {
  return ['committee', 'general', 'agm'].includes(String(type || '').toLowerCase());
}

function chimeMeetingAllowsGuests(type) {
  return !['general', 'agm'].includes(String(type || '').toLowerCase());
}

function chimeGuestPolicyMessage(type) {
  const meetingType = String(type || '').toLowerCase();
  if (meetingType === 'general') return 'Guests are not permitted for General Meetings.';
  if (meetingType === 'agm') return 'Guests are not permitted for Annual General Meetings.';
  return 'Guests can request entry for this meeting type.';
}

function chimeSelectedMeetingType() {
  return String(document.getElementById('chimeMeetingType')?.value || 'monthly');
}

function chimeFormatStatus(data) {
  const meeting = data?.meeting || {};
  if (!data?.enabled) return '<div class="notice warning"><strong>Meetings are not enabled.</strong></div>';
  if (!meeting.active) {
    return `<div class="notice"><strong>No active LROC meeting.</strong><div style="margin-top:8px">${data?.can_launch ? 'You can launch a meeting when ready.' : 'An authorised office bearer needs to launch the meeting first.'}</div></div>`;
  }
  const bits = [];
  if (meeting.title) bits.push(escapeHtml(meeting.title));
  if (meeting.meeting_type_label || meeting.meeting_type) bits.push(escapeHtml(meeting.meeting_type_label || chimeMeetingTypeLabel(meeting.meeting_type)));
  if (meeting.created_by_name) bits.push(`launched by ${escapeHtml(meeting.created_by_name)}`);
  if (meeting.created_at) bits.push(escapeHtml(new Date(meeting.created_at).toLocaleString()));
  return `<div class="notice success"><strong>Meeting active.</strong><div style="margin-top:8px">${bits.join(' • ') || 'Ready to join.'}</div></div>`;
}

function chimeSyncButtons() {
  const data = lrocChimeState.status || {};
  const meeting = data.meeting || {};
  const signedIn = Boolean(window.lrocAuth?.isAuthenticated?.());
  const launchBtn = document.getElementById('chimeLaunchBtn');
  const joinBtn = document.getElementById('chimeJoinBtn');
  const endBtn = document.getElementById('chimeEndBtn');
  const canEnd = Boolean(data.can_end ?? data.can_launch);
  const typeSelect = document.getElementById('chimeMeetingType');
  const modeUpdateBtn = document.getElementById('chimeModeUpdateBtn');
  const activeType = meeting.meeting_type || 'monthly';
  if (typeSelect && document.activeElement !== typeSelect) typeSelect.value = activeType;
  if (typeSelect) typeSelect.disabled = !(signedIn && data.can_launch);
  if (modeUpdateBtn) modeUpdateBtn.classList.toggle('hidden', !(signedIn && data.can_launch && meeting.active));
  if (launchBtn) launchBtn.classList.toggle('hidden', !(signedIn && data.can_launch && !meeting.active));
  if (endBtn) endBtn.classList.toggle('hidden', !(signedIn && canEnd && meeting.active));
  if (joinBtn) {
    joinBtn.disabled = !(signedIn && meeting.active) || lrocChimeState.joined || Boolean(lrocChimeState.currentMemberInPerson && chimeMeetingIsFormal(meeting.meeting_type));
    joinBtn.textContent = lrocChimeState.currentMemberInPerson && chimeMeetingIsFormal(meeting.meeting_type) ? 'In-person companion mode' : 'Join active meeting';
  }
  ['chimeMuteBtn','chimeVideoBtn','chimeShareBtn','chimeLeaveBtn'].forEach(id => {
    const btn = document.getElementById(id);
    if (btn) btn.disabled = !lrocChimeState.joined;
  });
  const muteBtn = document.getElementById('chimeMuteBtn');
  if (muteBtn) muteBtn.textContent = lrocChimeState.muted ? 'Unmute mic' : 'Mute mic';
  const videoBtn = document.getElementById('chimeVideoBtn');
  if (videoBtn) videoBtn.textContent = lrocChimeState.videoOn ? 'Stop camera' : 'Start camera';
  const shareBtn = document.getElementById('chimeShareBtn');
  if (shareBtn) shareBtn.textContent = lrocChimeState.shareOn ? 'Stop sharing' : 'Share screen';
  const fullShareBtn = document.getElementById('chimeFullscreenShareBtn');
  if (fullShareBtn) {
    fullShareBtn.classList.toggle('hidden', !lrocChimeState.contentActive);
    fullShareBtn.disabled = !lrocChimeState.contentActive;
  }
  const screenOnlyBtn = document.getElementById('chimeScreenOnlyBtn');
  if (screenOnlyBtn) {
    screenOnlyBtn.classList.toggle('hidden', !lrocChimeState.contentActive);
    screenOnlyBtn.disabled = !lrocChimeState.contentActive;
    screenOnlyBtn.textContent = lrocChimeState.screenOnly ? 'Show members' : 'Screen only';
  }
  const stageCard = document.getElementById('chimeStageCard');
  if (stageCard) {
    stageCard.classList.toggle('chime-screen-only', Boolean(lrocChimeState.screenOnly && lrocChimeState.contentActive));
    stageCard.classList.toggle('chime-agenda-active', Boolean(lrocChimeState.agenda?.presentation_enabled && lrocChimeState.agenda?.active_item));
  }
  ['chimeChatInput','chimeChatSendBtn'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.disabled = !(lrocChimeState.joined || lrocChimeState.currentMemberInPerson);
  });
  const attendanceController = document.getElementById('chimeAttendanceController');
  if (attendanceController) attendanceController.classList.toggle('hidden', !(signedIn && Boolean(data.can_end || lrocChimeState.canControl) && meeting.active));
  const guestsAllowed = chimeMeetingAllowsGuests(meeting.meeting_type);
  ['chimeGuestNameInput','chimeGuestNotesInput','chimeGuestAddBtn','chimeGuestLobbyRefreshBtn','chimeGuestAdmitAllBtn'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.disabled = !guestsAllowed;
  });
  const guestLobbyCard = document.querySelector('.chime-guest-lobby-card');
  if (guestLobbyCard) guestLobbyCard.classList.toggle('chime-guests-disabled', !guestsAllowed);
  const formal = chimeMeetingIsFormal(meeting.meeting_type);
  const controller = document.getElementById('chimeVoteController');
  if (controller) controller.classList.toggle('hidden', !(formal && signedIn && Boolean(data.can_end || lrocChimeState.canControl) && meeting.active));
}


function chimeUpdateTileLabels() {
  document.getElementById('chimeLocalVideoLabel') && (document.getElementById('chimeLocalVideoLabel').textContent = lrocChimeState.status?.member_name || 'You');
  lrocChimeState.remoteTiles.forEach((wrapper, tileId) => {
    const attendeeId = wrapper.dataset.attendeeId || '';
    const label = wrapper.querySelector('.chime-video-label');
    if (label && attendeeId) label.textContent = lrocChimeState.attendeeNames.get(attendeeId) || 'LROC member';
  });
}

function chimeRenderQuorum(quorum = null) {
  const el = document.getElementById('chimeQuorumPanel');
  if (!el) return;
  if (!quorum || quorum.required === 0) {
    el.className = 'muted';
    el.textContent = quorum?.label || 'No formal quorum required for this meeting mode.';
    return;
  }
  el.className = quorum.met ? 'notice success' : 'notice warning';
  const totalEligible = Number(quorum.total_eligible_for_quorum || quorum.total_eligible_voting_members || 0);
  el.innerHTML = `<strong>${escapeHtml(quorum.label || 'Quorum')}</strong><div style="margin-top:6px">Eligible pool: ${totalEligible} • Required: ${Number(quorum.required || 0)} • Present eligible: ${Number(quorum.present_eligible || 0)} • Online: ${Number(quorum.online_eligible || 0)} • In person: ${Number(quorum.in_person_eligible || 0)} • Non-voting present: ${Number(quorum.non_voting_present || 0)} • Guests: ${Number(quorum.guests_present || 0)}</div><div class="small-text">${quorum.met ? 'Quorum met. You can open formal votes after confirming quorum.' : 'Quorum not yet met.'}</div>`;
  const checkbox = document.getElementById('chimeQuorumConfirmed');
  if (checkbox && quorum.met) checkbox.checked = true;
}

function chimeRenderAttendance(data = {}, canControl = false) {
  const el = document.getElementById('chimeAttendanceList');
  if (!el) return;
  const online = data.attendees || [];
  const inPerson = data.in_person || [];
  const guests = data.guests || [];
  chimeRenderQuorum(data.quorum || null);
  if (!online.length && !inPerson.length && !guests.length) {
    el.className = 'muted';
    el.textContent = 'No attendees recorded yet.';
    return;
  }
  el.className = 'chime-attendance-list';
  const onlineHtml = online.map(a => `
    <div class="chime-attendee-row">
      <div><strong>${escapeHtml(a.member_name || 'LROC member')}</strong><div class="muted small-text">Online${a.voting_eligible ? ' • voting eligible' : ''}${a.joined_at ? ` • ${escapeHtml(new Date(a.joined_at).toLocaleTimeString())}` : ''}</div></div>
      ${canControl && a.attendee_id && a.attendee_id !== lrocChimeState.attendeeId ? `<button class="button tiny secondary chime-mute-other" type="button" data-attendee="${escapeHtml(a.attendee_id)}">Mute</button>` : ''}
    </div>`).join('');
  const inPersonHtml = inPerson.map(a => `
    <div class="chime-attendee-row">
      <div><strong>${escapeHtml(a.member_name || 'LROC member')}</strong><div class="muted small-text">In person${a.member_number ? ` • #${escapeHtml(a.member_number)}` : ''}${a.voting_eligible ? ' • voting eligible' : ' • non-voting'}</div></div>
      ${canControl ? `<button class="button tiny ghost chime-remove-inperson" type="button" data-member="${escapeHtml(a.member_id || '')}" data-attendance="${escapeHtml(a.attendance_id || '')}">Remove</button>` : ''}
    </div>`).join('');
  const guestHtml = guests.map(g => `
    <div class="chime-attendee-row">
      <div><strong>${escapeHtml(g.guest_name || 'Guest')}</strong><div class="muted small-text">Guest${g.notes ? ` • ${escapeHtml(g.notes)}` : ''}</div></div>
      ${canControl ? `<button class="button tiny ghost chime-remove-guest" type="button" data-attendance="${escapeHtml(g.attendance_id || '')}">Remove</button>` : ''}
    </div>`).join('');
  el.innerHTML = `${online.length ? '<h4>Online</h4>' + onlineHtml : ''}${inPerson.length ? '<h4>In person</h4>' + inPersonHtml : ''}${guests.length ? '<h4>Guests</h4>' + guestHtml : ''}`;
  el.querySelectorAll('.chime-mute-other').forEach(btn => btn.addEventListener('click', () => chimeSendMute(btn.dataset.attendee).catch(err => showToast(`Could not mute attendee: ${err.message}`, { kind: 'warning' }))));
  el.querySelectorAll('.chime-remove-inperson').forEach(btn => btn.addEventListener('click', () => chimeRemoveInPerson(btn.dataset.member, btn.dataset.attendance).catch(err => showToast(`Could not remove attendee: ${err.message}`, { kind: 'warning' }))));
  el.querySelectorAll('.chime-remove-guest').forEach(btn => btn.addEventListener('click', () => chimeRemoveGuest(btn.dataset.attendance).catch(err => showToast(`Could not remove guest: ${err.message}`, { kind: 'warning' }))));
}

async function chimeAttendanceAction(payload) {
  const data = await memberApiFetch('/member/chime/attendance', { method: 'POST', body: JSON.stringify(payload) });
  lrocChimeState.attendance = data;
  lrocChimeState.currentMemberInPerson = Boolean(data.current_member_in_person);
  lrocChimeState.canControl = Boolean(data.can_control || lrocChimeState.status?.can_end);
  lrocChimeState.attendeeNames = new Map((data.attendees || []).map(a => [String(a.attendee_id || ''), a.member_name || 'LROC member']));
  chimeRenderAttendance(data, lrocChimeState.canControl);
  chimeUpdateTileLabels();
  chimeSyncButtons();
  return data;
}

async function chimeSearchAttendanceMembers() {
  const input = document.getElementById('chimeAttendanceSearchInput');
  const results = document.getElementById('chimeAttendanceSearchResults');
  const query = String(input?.value || '').trim();
  if (!results) return;
  if (query.length < 2) { results.className = 'muted'; results.textContent = 'Type at least two characters.'; return; }
  results.className = 'muted';
  results.textContent = 'Searching…';
  const data = await memberApiFetch('/member/chime/attendance', { method: 'POST', body: JSON.stringify({ action: 'search_members', query }) });
  const matches = data.matches || [];
  if (!matches.length) { results.textContent = 'No matching members found.'; return; }
  results.className = 'chime-attendance-search-results';
  results.innerHTML = matches.map(m => `<div class="chime-attendee-row"><div><strong>${escapeHtml(m.name || 'Member')}</strong><div class="muted small-text">${m.member_number ? `#${escapeHtml(m.member_number)} • ` : ''}${escapeHtml(m.email || '')}${m.voting_eligible ? ' • voting eligible' : ' • non-voting'}</div></div><button class="button tiny secondary chime-add-inperson" type="button" data-member="${escapeHtml(m.member_id || '')}">Add in person</button></div>`).join('');
  results.querySelectorAll('.chime-add-inperson').forEach(btn => btn.addEventListener('click', () => chimeAddInPerson(btn.dataset.member).catch(err => showToast(`Could not add member: ${err.message}`, { kind: 'warning' }))));
}

async function chimeAddInPerson(memberId) {
  await chimeAttendanceAction({ action: 'add_in_person', member_id: memberId });
  showToast('Member added as in-person attendee.', { kind: 'success' });
}

async function chimeRemoveInPerson(memberId, attendanceId) {
  await chimeAttendanceAction({ action: 'remove_in_person', member_id: memberId, attendance_id: attendanceId });
}

async function chimeAddGuest() {
  const meetingType = lrocChimeState.status?.meeting?.meeting_type || 'monthly';
  if (!chimeMeetingAllowsGuests(meetingType)) { showToast(chimeGuestPolicyMessage(meetingType), { kind: 'warning' }); return; }
  const name = String(document.getElementById('chimeGuestNameInput')?.value || '').trim();
  const notes = String(document.getElementById('chimeGuestNotesInput')?.value || '').trim();
  if (!name) { showToast('Enter a guest name first.', { kind: 'warning' }); return; }
  await chimeAttendanceAction({ action: 'add_guest', guest_name: name, notes });
  document.getElementById('chimeGuestNameInput') && (document.getElementById('chimeGuestNameInput').value = '');
  document.getElementById('chimeGuestNotesInput') && (document.getElementById('chimeGuestNotesInput').value = '');
}

async function chimeRemoveGuest(attendanceId) {
  await chimeAttendanceAction({ action: 'remove_guest', attendance_id: attendanceId });
}

async function chimeStoreQuorumSnapshot() {
  const data = await chimeAttendanceAction({ action: 'confirm_quorum' });
  showToast(data.message || 'Quorum snapshot stored.', { kind: 'success' });
}

async function chimeLoadAttendance() {
  if (!lrocChimeState.status?.meeting?.active) return;
  const data = await memberApiFetch('/member/chime/attendance', { method: 'GET' });
  lrocChimeState.attendance = data;
  lrocChimeState.currentMemberInPerson = Boolean(data.current_member_in_person);
  lrocChimeState.canControl = Boolean(data.can_control || lrocChimeState.status?.can_end);
  lrocChimeState.attendeeNames = new Map((data.attendees || []).map(a => [String(a.attendee_id || ''), a.member_name || 'LROC member']));
  chimeRenderAttendance(data, lrocChimeState.canControl);
  chimeUpdateTileLabels();
  chimeSyncButtons();
}

function chimeRenderGuestLobby(data = {}) {
  const panel = document.getElementById('chimeGuestLobbyList');
  const refreshBtn = document.getElementById('chimeGuestLobbyRefreshBtn');
  const admitAllBtn = document.getElementById('chimeGuestAdmitAllBtn');
  const meeting = data.meeting || lrocChimeState.status?.meeting || {};
  const canControl = Boolean(data.can_control || lrocChimeState.canControl || lrocChimeState.status?.can_end);
  if (refreshBtn) refreshBtn.classList.toggle('hidden', !(canControl && meeting.active));
  if (admitAllBtn) admitAllBtn.classList.toggle('hidden', !(canControl && meeting.active));
  if (!panel) return;
  const guestsAllowed = data.guests_allowed ?? chimeMeetingAllowsGuests(meeting.meeting_type);
  if (!guestsAllowed) {
    panel.className = 'notice warning';
    panel.textContent = data.guest_policy_message || chimeGuestPolicyMessage(meeting.meeting_type);
    if (refreshBtn) refreshBtn.classList.add('hidden');
    if (admitAllBtn) admitAllBtn.classList.add('hidden');
    return;
  }
  if (!(canControl && meeting.active)) {
    panel.className = 'muted';
    panel.textContent = 'Guest lobby appears for authorised meeting controllers during an active meeting.';
    return;
  }
  const guests = data.guests || [];
  lrocChimeState.guests = guests;
  if (!guests.length) {
    panel.className = 'muted';
    panel.textContent = 'No guest requests yet.';
    return;
  }
  panel.className = 'chime-guest-lobby-list';
  panel.innerHTML = guests.map(g => {
    const status = String(g.status || 'waiting');
    const waiting = status === 'waiting';
    const denied = status === 'denied';
    return `<div class="chime-attendee-row chime-guest-row"><div><strong>${escapeHtml(g.guest_name || 'Guest')}</strong><div class="muted small-text">${escapeHtml(status)}${g.guest_email ? ` • ${escapeHtml(g.guest_email)}` : ''}${g.notes ? ` • ${escapeHtml(g.notes)}` : ''}</div></div><div class="auth-actions compact-actions">${waiting || denied ? `<button class="button tiny secondary chime-admit-guest" type="button" data-guest="${escapeHtml(g.guest_id || '')}">Admit</button>` : ''}${waiting ? `<button class="button tiny ghost chime-deny-guest" type="button" data-guest="${escapeHtml(g.guest_id || '')}">Deny</button>` : ''}${!waiting ? `<button class="button tiny ghost chime-reset-guest" type="button" data-guest="${escapeHtml(g.guest_id || '')}">Reset</button>` : ''}</div></div>`;
  }).join('');
  panel.querySelectorAll('.chime-admit-guest').forEach(btn => btn.addEventListener('click', () => chimeGuestLobbyAction('admit', btn.dataset.guest).catch(err => showToast(`Could not admit guest: ${err.message}`, { kind: 'warning' }))));
  panel.querySelectorAll('.chime-deny-guest').forEach(btn => btn.addEventListener('click', () => chimeGuestLobbyAction('deny', btn.dataset.guest).catch(err => showToast(`Could not deny guest: ${err.message}`, { kind: 'warning' }))));
  panel.querySelectorAll('.chime-reset-guest').forEach(btn => btn.addEventListener('click', () => chimeGuestLobbyAction('reset', btn.dataset.guest).catch(err => showToast(`Could not reset guest: ${err.message}`, { kind: 'warning' }))));
}

async function chimeLoadGuestLobby() {
  if (!lrocChimeState.status?.meeting?.active || !(lrocChimeState.canControl || lrocChimeState.status?.can_end)) return;
  const data = await memberApiFetch('/member/chime/guests', { method: 'GET' });
  data.can_control = true;
  chimeRenderGuestLobby(data);
}

async function chimeGuestLobbyAction(action, guestId = '') {
  const meetingType = lrocChimeState.status?.meeting?.meeting_type || 'monthly';
  if (['admit','admit_all','reset'].includes(String(action)) && !chimeMeetingAllowsGuests(meetingType)) { showToast(chimeGuestPolicyMessage(meetingType), { kind: 'warning' }); return; }
  const data = await memberApiFetch('/member/chime/guests', { method: 'POST', body: JSON.stringify({ action, guest_id: guestId }) });
  data.can_control = true;
  chimeRenderGuestLobby(data);
  showToast(data.message || 'Guest lobby updated.', { kind: 'success' });
}

function chimeRenderChat(messages = []) {
  const el = document.getElementById('chimeChatMessages');
  if (!el) return;
  if (!messages.length) {
    el.className = 'chime-chat-messages muted';
    el.textContent = 'No meeting chat messages yet.';
    return;
  }
  el.className = 'chime-chat-messages';
  el.innerHTML = messages.map(m => `<div class="chime-chat-message"><strong>${escapeHtml(m.member_name || 'LROC member')}</strong> <span class="muted small-text">${escapeHtml(m.created_at ? new Date(m.created_at).toLocaleTimeString() : '')}</span>${m.include_in_minutes ? ' <span class="badge small">Flagged for minutes</span>' : ''}<div>${escapeHtml(m.message || '')}</div></div>`).join('');
  el.scrollTop = el.scrollHeight;
}

async function chimeLoadChat() {
  if (!lrocChimeState.joined && !lrocChimeState.status?.meeting?.active) return;
  const data = await memberApiFetch('/member/chime/chat', { method: 'GET' });
  chimeRenderChat(data.messages || []);
}

async function chimeSendChat() {
  const input = document.getElementById('chimeChatInput');
  const text = String(input?.value || '').trim();
  if (!text) return;
  const includeInMinutes = Boolean(document.getElementById('chimeChatMinutesFlag')?.checked);
  await memberApiFetch('/member/chime/chat', { method: 'POST', body: JSON.stringify({ message: text, include_in_minutes: includeInMinutes }) });
  if (input) input.value = '';
  const flag = document.getElementById('chimeChatMinutesFlag');
  if (flag) flag.checked = false;
  await chimeLoadChat();
}

async function chimeSendMute(attendeeId) {
  if (!attendeeId) return;
  await memberApiFetch('/member/chime/control', { method: 'POST', body: JSON.stringify({ action: 'mute', target_attendee_id: attendeeId }) });
  showToast('Mute request sent.', { kind: 'success' });
}

function chimeParseAgendaEditor() {
  const text = String(document.getElementById('chimeAgendaEditor')?.value || '').trim();
  if (!text) return [];
  return text.split(/\n+/).map((line, idx) => {
    const parts = line.split('|').map(x => x.trim());
    const title = parts[0] || `Agenda item ${idx + 1}`;
    const detail = parts[1] || '';
    const votingFlag = String(parts[2] || '').toLowerCase();
    return {
      number: idx + 1,
      title,
      detail,
      voting_enabled: ['vote', 'voting', 'yes', 'y', 'true', '1'].includes(votingFlag),
      vote_title: title,
    };
  });
}

function chimeAgendaEditorText(items = []) {
  return (items || []).map(item => `${item.title || ''}${item.motion_text || item.detail ? ` | ${item.motion_text || item.detail}` : ' | '}${item.voting_enabled ? ' | vote' : ''}`).join('\n');
}

function chimeAgendaButtonVisible(id, visible) {
  const btn = document.getElementById(id);
  if (btn) btn.classList.toggle('hidden', !visible);
  return btn;
}

function chimeAgendaProgressLabel(agenda = {}) {
  const progress = Number(agenda.progress_index || 0);
  const active = Number(agenda.active_index || 0);
  const items = agenda.items || [];
  if (!items.length) return '';
  if (agenda.agenda_finished) return ' • agenda finished';
  if (active !== progress) return ` • viewing item ${active + 1}; resume returns to item ${progress + 1}`;
  return ` • current item ${progress + 1}`;
}

function chimePopulateAgendaJump(items = [], activeIndex = 0, canControl = false) {
  const jump = document.getElementById('chimeAgendaJumpSelect');
  if (!jump) return;
  jump.classList.toggle('hidden', !(canControl && items.length));
  if (!(canControl && items.length)) return;
  const prior = String(activeIndex);
  jump.innerHTML = items.map((item, idx) => `<option value="${idx}" ${idx === activeIndex ? 'selected' : ''}>${idx + 1}. ${escapeHtml(item.title || 'Agenda item')}</option>`).join('');
  jump.value = prior;
}

function chimeRenderAgenda(data = {}) {
  const agenda = data.agenda || data || {};
  lrocChimeState.agenda = agenda;
  const meeting = data.meeting || lrocChimeState.status?.meeting || {};
  const formal = chimeMeetingIsFormal(meeting.meeting_type);
  const canControl = Boolean(data.can_control || lrocChimeState.status?.can_end || lrocChimeState.canControl);
  const viewer = document.getElementById('chimeAgendaViewer');
  const controller = document.getElementById('chimeAgendaController');
  const editor = document.getElementById('chimeAgendaEditor');
  const items = agenda.items || [];
  const active = agenda.active_item || null;
  const activeIndex = Number(agenda.active_index || 0);
  const progressIndex = Number(agenda.progress_index ?? activeIndex);
  const agendaControlsVisible = Boolean(formal && canControl && meeting.active && items.length);
  if (controller) controller.classList.toggle('hidden', !(formal && canControl && meeting.active));
  const prevBtn = chimeAgendaButtonVisible('chimeAgendaPrevBtn', agendaControlsVisible && activeIndex > 0);
  const nextBtn = chimeAgendaButtonVisible('chimeAgendaNextBtn', agendaControlsVisible && activeIndex < items.length - 1);
  const finishBtn = chimeAgendaButtonVisible('chimeAgendaFinishBtn', agendaControlsVisible && activeIndex >= items.length - 1);
  const resumeBtn = chimeAgendaButtonVisible('chimeAgendaResumeBtn', agendaControlsVisible && activeIndex !== progressIndex);
  chimeAgendaButtonVisible('chimeAgendaShowBtn', agendaControlsVisible);
  chimeAgendaButtonVisible('chimeAgendaHideBtn', agendaControlsVisible);
  chimePopulateAgendaJump(items, activeIndex, agendaControlsVisible);
  const showBtn = document.getElementById('chimeAgendaShowBtn');
  const hideBtn = document.getElementById('chimeAgendaHideBtn');
  const reloadBtn = document.getElementById('chimeAgendaReloadBtn');
  if (nextBtn) nextBtn.textContent = 'Next item';
  if (finishBtn) finishBtn.textContent = agenda.agenda_finished ? 'Agenda finished' : 'Finish agenda';
  if (finishBtn) finishBtn.disabled = Boolean(agenda.agenda_finished);
  if (prevBtn) prevBtn.textContent = 'Previous item';
  if (resumeBtn) resumeBtn.textContent = `Resume item ${progressIndex + 1}`;
  if (showBtn) showBtn.textContent = agenda.presentation_enabled ? 'Agenda showing' : 'Show agenda on stage';
  if (showBtn) showBtn.disabled = Boolean(agenda.presentation_enabled);
  if (hideBtn) hideBtn.disabled = !agenda.presentation_enabled;
  if (reloadBtn) reloadBtn.classList.toggle('hidden', !(formal && canControl && meeting.active));
  if (editor && document.activeElement !== editor && !editor.value && items.length) editor.value = chimeAgendaEditorText(items);
  if (viewer) {
    if (!formal) {
      viewer.className = 'muted';
      viewer.textContent = 'Agenda presentation is available for Committee, General, and AGM meeting modes.';
    } else if (!items.length) {
      viewer.className = 'muted';
      viewer.textContent = canControl ? 'No agenda items saved yet. Add items below to present them to attendees.' : 'No agenda has been shown yet.';
    } else {
      viewer.className = 'chime-agenda-viewer';
      viewer.innerHTML = `<strong>${escapeHtml(active?.title || 'Agenda item')}</strong><div class="muted small-text">Item ${activeIndex + 1} of ${items.length}${agenda.presentation_enabled ? ' • showing on stage' : ''}${agenda.source === 'meeting-agenda' ? ' • current Meeting Agenda' : ''}${chimeAgendaProgressLabel(agenda)}</div>${active?.motion_text ? `<p><strong>Motion:</strong> ${escapeHtml(active.motion_text)}</p>` : (active?.detail ? `<p>${escapeHtml(active.detail)}</p>` : '')}${active?.voting_enabled ? '<span class="badge small">Voting enabled for this item</span>' : ''}`;
    }
  }
  chimeRenderAgendaStage(agenda);
  chimeSyncButtons();
}

function chimeRenderAgendaStage(agenda = lrocChimeState.agenda || {}) {
  const stage = document.getElementById('chimeAgendaStage');
  const title = document.getElementById('chimeAgendaStageTitle');
  const detail = document.getElementById('chimeAgendaStageDetail');
  const count = document.getElementById('chimeAgendaStageCount');
  const vote = document.getElementById('chimeAgendaStageVote');
  const items = agenda.items || [];
  const active = agenda.active_item || null;
  const showing = Boolean(agenda.presentation_enabled && active);
  if (stage) stage.classList.toggle('hidden', !showing);
  if (!showing) return;
  if (title) title.textContent = active.title || 'Agenda item';
  if (detail) {
    const motion = String(active.motion_text || active.vote_title || '').trim();
    const background = String(active.detail || '').trim();
    detail.innerHTML = motion
      ? `<div class="chime-motion-label">Motion</div><div class="chime-motion-text">${escapeHtml(motion)}</div>${background && background !== motion ? `<div class="chime-agenda-background"><strong>Background</strong><br>${escapeHtml(background)}</div>` : ''}`
      : escapeHtml(background || '');
  }
  if (count) {
    const activeIndex = Number(agenda.active_index || 0);
    const progressIndex = Number(agenda.progress_index ?? activeIndex);
    count.textContent = `Item ${activeIndex + 1} of ${items.length}${activeIndex !== progressIndex ? ` • viewing; resume item ${progressIndex + 1}` : ''}`;
  }
  if (vote) vote.textContent = active.voting_enabled ? 'Secret ballot available when opened by the meeting controller.' : 'No vote for this agenda item.';
}

async function chimeLoadAgenda() {
  if (!lrocChimeState.status?.meeting?.active) return;
  const data = await memberApiFetch('/member/chime/agenda', { method: 'GET' });
  chimeRenderAgenda(data);
}

async function chimeSaveAgenda() {
  const items = chimeParseAgendaEditor();
  await memberApiFetch('/member/chime/agenda', { method: 'POST', body: JSON.stringify({ action: 'save', items, presentation_enabled: Boolean(lrocChimeState.agenda?.presentation_enabled) }) });
  await chimeLoadAgenda();
  showToast('Meeting agenda saved.', { kind: 'success' });
}

async function chimeAgendaAction(action) {
  await memberApiFetch('/member/chime/agenda', { method: 'POST', body: JSON.stringify({ action }) });
  await chimeLoadAgenda();
}

async function chimeAgendaSetActive(activeIndex) {
  const index = Number(activeIndex);
  if (!Number.isFinite(index)) return;
  await memberApiFetch('/member/chime/agenda', { method: 'POST', body: JSON.stringify({ action: 'set_active', active_index: index }) });
  await chimeLoadAgenda();
}

async function chimeReloadCurrentMeetingAgenda() {
  await memberApiFetch('/member/chime/agenda', { method: 'POST', body: JSON.stringify({ action: 'reload_current_agenda' }) });
  await chimeLoadAgenda();
  showToast('Current Meeting Agenda loaded into Chime.', { kind: 'success' });
}

function chimeLoadAgendaSample() {
  const editor = document.getElementById('chimeAgendaEditor');
  if (!editor) return;
  editor.value = 'Welcome | Chair opens the meeting\nApologies | Record apologies\nPrevious minutes | Confirm previous minutes | vote\nBusiness arising | Matters from previous meeting\nGeneral business | New items\nClose | Meeting close';
}

async function chimePollControls() {
  if (!lrocChimeState.joined || !lrocChimeState.attendeeId) return;
  const qs = new URLSearchParams({ attendee_id: lrocChimeState.attendeeId });
  if (lrocChimeState.lastControlAt) qs.set('after', lrocChimeState.lastControlAt);
  const data = await memberApiFetch(`/member/chime/control?${qs.toString()}`, { method: 'GET' });
  for (const control of data.controls || []) {
    if (control.created_at) lrocChimeState.lastControlAt = control.created_at;
    if (control.action === 'mute' && lrocChimeState.audioVideo) {
      try { lrocChimeState.audioVideo.realtimeMuteLocalAudio(); } catch {}
      lrocChimeState.muted = true;
      chimeSyncButtons();
      showToast(`You were muted by ${control.created_by_name || 'the meeting controller'}.`, { kind: 'warning', duration: 6000 });
    }
  }
}

function chimeRenderVote(data = {}) {
  const panel = document.getElementById('chimeVotePanel');
  const controller = document.getElementById('chimeVoteController');
  const startBtn = document.getElementById('chimeVoteStartBtn');
  const closeBtn = document.getElementById('chimeVoteCloseBtn');
  const vote = data.vote || null;
  const meeting = data.meeting || lrocChimeState.status?.meeting || {};
  const formal = Boolean(data.voting_enabled ?? chimeMeetingIsFormal(meeting.meeting_type));
  const canControl = Boolean(data.can_control || lrocChimeState.status?.can_end);
  if (controller) controller.classList.toggle('hidden', !(formal && canControl));
  if (startBtn) startBtn.classList.toggle('hidden', Boolean(vote && vote.status === 'open'));
  if (closeBtn) closeBtn.classList.toggle('hidden', !(canControl && vote && vote.status === 'open'));
  if (!panel) return;
  if (!formal) {
    panel.className = 'muted';
    panel.textContent = 'Voting is available only when the meeting mode is Committee, General, or AGM.';
    return;
  }
  if (!vote || vote.status !== 'open') {
    const agendaItem = data.agenda?.active_item;
    panel.className = 'muted';
    if (agendaItem?.voting_enabled) panel.innerHTML = `<strong>${escapeHtml(agendaItem.title || 'Current agenda item')}</strong><p class="muted">Voting is enabled for this agenda item. The meeting controller must open the secret ballot.</p>`;
    else panel.textContent = 'No formal ballot is open.';
    return;
  }
  if (data.member_is_financial === false) {
    panel.className = 'muted';
    panel.innerHTML = `<strong>${escapeHtml(vote.title || 'Secret ballot')}</strong><p class="muted">Only current financial members and life members may vote in formal ballots.</p>`;
    return;
  }
  if (data.member_is_present === false) {
    panel.className = 'muted';
    panel.innerHTML = `<strong>${escapeHtml(vote.title || 'Secret ballot')}</strong><p class="muted">You must be recorded as present online or in person before voting.</p>`;
    return;
  }
  panel.className = '';
  if (data.already_voted) {
    panel.innerHTML = `<strong>${escapeHtml(vote.title || 'Secret ballot')}</strong><p class="muted">Your secret ballot has been recorded.</p>`;
    return;
  }
  panel.innerHTML = `<strong>${escapeHtml(vote.title || 'Secret ballot')}</strong>${vote.description ? `<p class="muted">${escapeHtml(vote.description)}</p>` : ''}<div class="auth-actions">${(vote.options || []).map(opt => `<button class="button secondary chime-vote-cast" type="button" data-choice="${escapeHtml(opt)}">${escapeHtml(opt)}</button>`).join('')}</div><p class="muted small-text">Secret ballot: totals are shown for minutes. Identity is retained only server-side to prevent duplicate voting across devices.</p>`;
  panel.querySelectorAll('.chime-vote-cast').forEach(btn => btn.addEventListener('click', () => chimeCastVote(btn.dataset.choice).catch(err => showToast(`Could not cast vote: ${err.message}`, { kind: 'warning' }))));
}

async function chimeLoadVote() {
  if (!lrocChimeState.status?.meeting?.active) return;
  const data = await memberApiFetch('/member/chime/vote', { method: 'GET' });
  chimeRenderVote(data);
}

async function chimeStartVote() {
  const agendaItem = lrocChimeState.agenda?.active_item || null;
  const agendaVote = agendaItem && agendaItem.voting_enabled ? agendaItem : null;
  const title = String(document.getElementById('chimeVoteTitle')?.value || agendaVote?.vote_title || agendaVote?.title || '').trim();
  const description = String(document.getElementById('chimeVoteDescription')?.value || agendaVote?.motion_text || agendaVote?.detail || '').trim();
  if (!title) { showToast('Enter a ballot title/motion first.', { kind: 'warning' }); return; }
  const quorumConfirmed = Boolean(document.getElementById('chimeQuorumConfirmed')?.checked);
  if (!quorumConfirmed) { showToast('Confirm quorum before opening the ballot.', { kind: 'warning' }); return; }
  await memberApiFetch('/member/chime/vote', { method: 'POST', body: JSON.stringify({ action: 'start', title, description, quorum_confirmed: quorumConfirmed, agenda_item_id: agendaVote?.item_id || '' }) });
  document.getElementById('chimeVoteTitle') && (document.getElementById('chimeVoteTitle').value = '');
  document.getElementById('chimeVoteDescription') && (document.getElementById('chimeVoteDescription').value = '');
  const quorum = document.getElementById('chimeQuorumConfirmed');
  if (quorum) quorum.checked = false;
  await chimeLoadVote();
}

async function chimeCastVote(choice) {
  await memberApiFetch('/member/chime/vote', { method: 'POST', body: JSON.stringify({ action: 'cast', choice }) });
  showToast('Your secret ballot has been recorded.', { kind: 'success' });
  await chimeLoadVote();
}

async function chimeCloseVote() {
  if (!confirm('Close this secret ballot and store totals against the meeting history?')) return;
  const data = await memberApiFetch('/member/chime/vote', { method: 'POST', body: JSON.stringify({ action: 'close' }) });
  const results = data.vote?.results || {};
  showToast(`Ballot closed: ${Object.entries(results).map(([k,v]) => `${k} ${v}`).join(', ')}`, { kind: 'success', duration: 8000 });
  await chimeLoadVote();
}

function chimeStartToolPolling() {
  if (lrocChimeState.pollTimer) clearInterval(lrocChimeState.pollTimer);
  lrocChimeState.pollTimer = setInterval(() => {
    chimeLoadAttendance().catch(() => {});
    chimeLoadChat().catch(() => {});
    chimeLoadVote().catch(() => {});
    chimeLoadAgenda().catch(() => {});
    chimeLoadGuestLobby().catch(() => {});
    chimePollControls().catch(() => {});
  }, 5000);
}

function chimeStopToolPolling() {
  if (lrocChimeState.pollTimer) clearInterval(lrocChimeState.pollTimer);
  lrocChimeState.pollTimer = null;
}

async function chimeLoadStatus() {
  if (!window.lrocAuth?.isAuthenticated?.()) {
    chimeSetText('chimeStatusPanel', 'Sign in to view LROC meeting status.', 'chime-status-panel muted');
    chimeSyncButtons();
    return;
  }
  const data = await memberApiFetch('/member/chime/status', { method: 'GET' });
  lrocChimeState.status = data;
  const panel = document.getElementById('chimeStatusPanel');
  if (panel) panel.innerHTML = chimeFormatStatus(data);
  chimeSyncButtons();
  if (data?.meeting?.active) {
    Promise.allSettled([chimeLoadAttendance(), chimeLoadChat(), chimeLoadVote(), chimeLoadAgenda(), chimeLoadGuestLobby()]).catch(() => {});
    chimeStartToolPolling();
  }
}

async function chimeStartInput(audioVideo, kind) {
  const devices = kind === 'audio' ? await audioVideo.listAudioInputDevices() : await audioVideo.listVideoInputDevices();
  const id = devices?.[0]?.deviceId || null;
  if (!id) return false;
  if (kind === 'audio') {
    if (typeof audioVideo.startAudioInput === 'function') await audioVideo.startAudioInput(id);
    else if (typeof audioVideo.chooseAudioInputDevice === 'function') await audioVideo.chooseAudioInputDevice(id);
    return true;
  }
  if (typeof audioVideo.startVideoInput === 'function') await audioVideo.startVideoInput(id);
  else if (typeof audioVideo.chooseVideoInputDevice === 'function') await audioVideo.chooseVideoInputDevice(id);
  return true;
}


function chimeSetContentTile(tileState) {
  const av = lrocChimeState.audioVideo;
  const stage = document.getElementById('chimeShareStage');
  const video = document.getElementById('chimeShareVideo');
  if (!av || !stage || !video || tileState.tileId == null) return;
  lrocChimeState.contentTileId = String(tileState.tileId);
  lrocChimeState.contentActive = true;
  stage.classList.remove('hidden');
  document.getElementById('chimeStageCard')?.classList.add('chime-content-active');
  stage.dataset.tileId = lrocChimeState.contentTileId;
  av.bindVideoElement(tileState.tileId, video);
  chimeSyncButtons();
}

function chimeClearContentTile(tileId = null) {
  if (tileId != null && lrocChimeState.contentTileId && String(tileId) !== lrocChimeState.contentTileId) return;
  const stage = document.getElementById('chimeShareStage');
  const video = document.getElementById('chimeShareVideo');
  chimeReleaseVideoElement(video);
  if (stage) {
    stage.classList.add('hidden');
    stage.removeAttribute('data-tile-id');
  }
  document.getElementById('chimeStageCard')?.classList.remove('chime-content-active');
  lrocChimeState.contentTileId = null;
  lrocChimeState.contentActive = false;
  lrocChimeState.screenOnly = false;
  chimeSyncButtons();
}

function chimeRequestFullscreen(target) {
  if (!target) return false;
  if (target.requestFullscreen) {
    target.requestFullscreen().catch(err => showToast(`Could not enter full screen: ${err.message}`, { kind: 'warning' }));
    return true;
  }
  if (target.webkitRequestFullscreen) {
    target.webkitRequestFullscreen();
    return true;
  }
  return false;
}

function chimeFullscreenSharedScreen() {
  const target = document.getElementById('chimeStageCard');
  if (!target || !lrocChimeState.contentActive) {
    showToast('No shared screen is currently available.', { kind: 'warning' });
    return;
  }
  target.classList.add('chime-content-active');
  if (!chimeRequestFullscreen(target)) showToast('Full-screen mode is not supported by this browser.', { kind: 'warning' });
}

function chimeToggleScreenOnly() {
  if (!lrocChimeState.contentActive) {
    lrocChimeState.screenOnly = false;
    chimeSyncButtons();
    showToast('No shared screen is currently available.', { kind: 'warning' });
    return;
  }
  lrocChimeState.screenOnly = !lrocChimeState.screenOnly;
  chimeSyncButtons();
}


function chimeWireShareVideoMetrics() {
  const video = document.getElementById('chimeShareVideo');
  const wrap = document.getElementById('chimeShareVideoWrap');
  if (!video || !wrap || video.dataset.metricsWired === '1') return;
  const update = () => {
    const width = Number(video.videoWidth || 0);
    const height = Number(video.videoHeight || 0);
    if (width > 0 && height > 0) {
      wrap.style.setProperty('--share-aspect', `${width} / ${height}`);
      wrap.dataset.orientation = width >= height ? 'landscape' : 'portrait';
    } else {
      wrap.style.removeProperty('--share-aspect');
      delete wrap.dataset.orientation;
    }
  };
  video.addEventListener('loadedmetadata', update);
  video.addEventListener('resize', update);
  video.dataset.metricsWired = '1';
  update();
}

function chimeReleaseVideoElement(video) {
  if (!video) return;
  try { video.pause(); } catch {}
  try { video.removeAttribute('srcObject'); } catch {}
  try { video.srcObject = null; } catch {}
}

function chimeStopMediaResources(audioVideo) {
  if (!audioVideo) return;
  const calls = [
    () => audioVideo.stopContentShare?.(),
    () => audioVideo.stopLocalVideoTile?.(),
    () => audioVideo.stopVideoInput?.(),
    () => audioVideo.stopAudioInput?.(),
  ];
  calls.forEach(fn => {
    try {
      const result = fn();
      if (result && typeof result.catch === 'function') result.catch(() => {});
    } catch {}
  });
}

function chimeExitPresentationFullscreen() {
  const fs = document.fullscreenElement || document.webkitFullscreenElement;
  if (!fs || !fs.closest?.('#chimeStageCard')) return;
  try {
    if (document.exitFullscreen) document.exitFullscreen().catch(() => {});
    else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
  } catch {}
}

function chimeEnsureRemoteTile(tileState) {
  const grid = document.getElementById('chimeVideoGrid');
  if (!grid) return null;
  const tileId = String(tileState.tileId);
  let wrapper = lrocChimeState.remoteTiles.get(tileId);
  if (wrapper) return wrapper.querySelector('video');
  wrapper = document.createElement('div');
  wrapper.className = 'chime-video-tile';
  wrapper.dataset.tileId = tileId;
  wrapper.dataset.attendeeId = tileState.boundAttendeeId || '';
  const video = document.createElement('video');
  video.autoplay = true;
  video.playsInline = true;
  const label = document.createElement('div');
  label.className = 'chime-video-label';
  label.textContent = tileState.isContent ? 'Screen share' : (lrocChimeState.attendeeNames.get(tileState.boundAttendeeId || '') || 'LROC member');
  wrapper.appendChild(video);
  wrapper.appendChild(label);
  grid.appendChild(wrapper);
  lrocChimeState.remoteTiles.set(tileId, wrapper);
  return video;
}

function chimeRemoveRemoteTile(tileId) {
  const key = String(tileId);
  const wrapper = lrocChimeState.remoteTiles.get(key);
  if (wrapper) wrapper.remove();
  lrocChimeState.remoteTiles.delete(key);
}

async function chimeJoinActiveMeeting() {
  const sdk = await ensureChimeSdkLoaded();
  chimeSetText('chimeStageNotice', 'Creating attendee and joining…');
  const data = await memberApiFetch('/member/chime/join', { method: 'POST', body: JSON.stringify({}) });
  const logger = new sdk.ConsoleLogger('LROCChime', sdk.LogLevel.INFO);
  const deviceController = new sdk.DefaultDeviceController(logger);
  const config = new sdk.MeetingSessionConfiguration(data.meeting, data.attendee);
  const session = new sdk.DefaultMeetingSession(config, logger, deviceController);
  const audioVideo = session.audioVideo;
  lrocChimeState.meetingSession = session;
  lrocChimeState.audioVideo = audioVideo;
  lrocChimeState.attendeeId = data.attendee?.Attendee?.AttendeeId || '';
  document.getElementById('chimeLocalVideoLabel') && (document.getElementById('chimeLocalVideoLabel').textContent = data.member_name || 'You');
  audioVideo.bindAudioElement(document.getElementById('chimeMeetingAudio'));
  audioVideo.addObserver({
    audioVideoDidStop: () => {
      chimeStopMediaResources(audioVideo);
      chimeClearContentTile();
      chimeReleaseVideoElement(document.getElementById('chimeLocalVideo'));
      lrocChimeState.joined = false;
      lrocChimeState.videoOn = false;
      lrocChimeState.shareOn = false;
      lrocChimeState.contentActive = false;
      lrocChimeState.screenOnly = false;
      lrocChimeState.muted = true;
      lrocChimeState.attendeeId = '';
      chimeStopToolPolling();
      chimeSetText('chimeStageNotice', 'Meeting audio/video stopped.');
      chimeSyncButtons();
      chimeLoadStatus().catch(() => {});
    },
    videoTileDidUpdate: tileState => {
      if (!tileState.boundAttendeeId || tileState.tileId == null) return;
      if (tileState.isContent) {
        chimeSetContentTile(tileState);
      } else if (tileState.localTile) {
        const video = document.getElementById('chimeLocalVideo');
        if (video) audioVideo.bindVideoElement(tileState.tileId, video);
      } else {
        const video = chimeEnsureRemoteTile(tileState);
        if (video) audioVideo.bindVideoElement(tileState.tileId, video);
      }
    },
    videoTileWasRemoved: tileId => {
      chimeClearContentTile(tileId);
      chimeRemoveRemoteTile(tileId);
    },
  });
  if (typeof audioVideo.addContentShareObserver === 'function') {
    audioVideo.addContentShareObserver({
      contentShareDidStop: () => {
        lrocChimeState.shareOn = false;
        chimeSyncButtons();
      }
    });
  }
  try { await chimeStartInput(audioVideo, 'audio'); } catch (err) { console.warn('Audio input unavailable', err); }
  audioVideo.start();
  try { audioVideo.realtimeMuteLocalAudio(); } catch {}
  lrocChimeState.joined = true;
  lrocChimeState.muted = true;
  chimeSetText('chimeStageNotice', 'Joined. Microphone starts muted; use the controls when ready.');
  chimeSyncButtons();
  await Promise.allSettled([chimeLoadAttendance(), chimeLoadChat(), chimeLoadVote(), chimeLoadGuestLobby()]);
  chimeStartToolPolling();
}

async function chimeToggleMute() {
  const av = lrocChimeState.audioVideo;
  if (!av) return;
  if (lrocChimeState.muted) {
    av.realtimeUnmuteLocalAudio();
    lrocChimeState.muted = false;
  } else {
    av.realtimeMuteLocalAudio();
    lrocChimeState.muted = true;
  }
  chimeSyncButtons();
}

async function chimeToggleVideo() {
  const av = lrocChimeState.audioVideo;
  if (!av) return;
  if (lrocChimeState.videoOn) {
    try { av.stopLocalVideoTile(); } catch {}
    try { if (typeof av.stopVideoInput === 'function') await av.stopVideoInput(); } catch {}
    lrocChimeState.videoOn = false;
  } else {
    await chimeStartInput(av, 'video');
    av.startLocalVideoTile();
    lrocChimeState.videoOn = true;
  }
  chimeSyncButtons();
}

async function chimeToggleShare() {
  const av = lrocChimeState.audioVideo;
  if (!av) return;
  if (lrocChimeState.shareOn) {
    av.stopContentShare();
    lrocChimeState.shareOn = false;
  } else {
    await av.startContentShareFromScreenCapture();
    lrocChimeState.shareOn = true;
  }
  chimeSyncButtons();
}

function chimeLeaveMeeting(message = 'You left the meeting.') {
  const av = lrocChimeState.audioVideo;
  chimeStopMediaResources(av);
  if (av) {
    try { av.stop(); } catch {}
  }
  chimeExitPresentationFullscreen();
  chimeClearContentTile();
  chimeReleaseVideoElement(document.getElementById('chimeLocalVideo'));
  document.querySelectorAll('.chime-video-tile:not(.chime-local-tile)').forEach(el => el.remove());
  lrocChimeState.remoteTiles.clear();
  lrocChimeState.meetingSession = null;
  lrocChimeState.audioVideo = null;
  lrocChimeState.joined = false;
  lrocChimeState.videoOn = false;
  lrocChimeState.shareOn = false;
  lrocChimeState.contentTileId = null;
  lrocChimeState.contentActive = false;
  lrocChimeState.screenOnly = false;
  lrocChimeState.muted = true;
  lrocChimeState.attendeeId = '';
  chimeStopToolPolling();
  chimeSetText('chimeStageNotice', message);
  chimeSyncButtons();
}


async function chimeUpdateMeetingMode() {
  const meetingType = chimeSelectedMeetingType();
  const title = chimeMeetingTypeLabel(meetingType);
  const data = await memberApiFetch('/member/chime/mode', { method: 'POST', body: JSON.stringify({ meeting_type: meetingType, title }) });
  lrocChimeState.status = { ...(lrocChimeState.status || {}), ...data };
  const panel = document.getElementById('chimeStatusPanel');
  if (panel) panel.innerHTML = chimeFormatStatus(lrocChimeState.status);
  chimeSyncButtons();
  await Promise.allSettled([chimeLoadVote(), chimeLoadAgenda()]);
  showToast(data.message || 'Meeting mode updated.', { kind: 'success' });
}

function wireChimeMeetingPage() {
  document.getElementById('chimeLoginBtn')?.addEventListener('click', () => window.lrocAuth?.login?.(window.location.href));
  document.getElementById('chimeRefreshBtn')?.addEventListener('click', () => chimeLoadStatus().catch(err => chimeSetText('chimeStatusPanel', `Could not load meeting status: ${err.message}`, 'chime-status-panel notice warning')));
  document.getElementById('chimeModeUpdateBtn')?.addEventListener('click', () => chimeUpdateMeetingMode().catch(err => showToast(`Could not update meeting mode: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeLaunchBtn')?.addEventListener('click', async () => {
    const btn = document.getElementById('chimeLaunchBtn');
    setButtonBusy(btn, true, 'Launching…');
    try {
      const meetingType = chimeSelectedMeetingType();
      const data = await memberApiFetch('/member/chime/launch', { method: 'POST', body: JSON.stringify({ meeting_type: meetingType, title: chimeMeetingTypeLabel(meetingType) }) });
      showToast(data.message || 'Meeting launched.', { kind: 'success' });
      await chimeLoadStatus();
    } catch (err) {
      showToast(`Could not launch meeting: ${err.message}`, { kind: 'warning', duration: 7000 });
    } finally { setButtonBusy(btn, false); }
  });
  document.getElementById('chimeEndBtn')?.addEventListener('click', async () => {
    if (!confirm('End the active LROC meeting for everyone?')) return;
    const btn = document.getElementById('chimeEndBtn');
    setButtonBusy(btn, true, 'Ending…');
    try {
      chimeLeaveMeeting('Meeting ended. Local camera, microphone, and screen sharing have been stopped.');
      const data = await memberApiFetch('/member/chime/end', { method: 'POST', body: JSON.stringify({}) });
      lrocChimeState.status = { ...(lrocChimeState.status || {}), ...data, meeting: { active: false } };
      const panel = document.getElementById('chimeStatusPanel');
      if (panel) panel.innerHTML = chimeFormatStatus(lrocChimeState.status);
      showToast(data.message || 'Meeting ended.', { kind: 'success' });
      await chimeLoadStatus();
    } catch (err) {
      showToast(`Could not end meeting: ${err.message}`, { kind: 'warning', duration: 7000 });
    } finally { setButtonBusy(btn, false); }
  });
  document.getElementById('chimeJoinBtn')?.addEventListener('click', async () => {
    const btn = document.getElementById('chimeJoinBtn');
    setButtonBusy(btn, true, 'Joining…');
    try { await chimeJoinActiveMeeting(); }
    catch (err) { chimeSetText('chimeStageNotice', `Could not join meeting: ${err.message}`); showToast(`Could not join meeting: ${err.message}`, { kind: 'warning', duration: 7000 }); }
    finally { setButtonBusy(btn, false); chimeSyncButtons(); }
  });
  document.getElementById('chimeMuteBtn')?.addEventListener('click', () => chimeToggleMute().catch(err => showToast(`Microphone control failed: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeVideoBtn')?.addEventListener('click', () => chimeToggleVideo().catch(err => showToast(`Camera control failed: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeShareBtn')?.addEventListener('click', () => chimeToggleShare().catch(err => showToast(`Screen share failed: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeFullscreenShareBtn')?.addEventListener('click', chimeFullscreenSharedScreen);
  document.getElementById('chimeScreenOnlyBtn')?.addEventListener('click', chimeToggleScreenOnly);
  document.getElementById('chimeLeaveBtn')?.addEventListener('click', chimeLeaveMeeting);
  document.getElementById('chimeChatSendBtn')?.addEventListener('click', () => chimeSendChat().catch(err => showToast(`Could not send chat message: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeChatInput')?.addEventListener('keydown', event => { if (event.key === 'Enter') { event.preventDefault(); chimeSendChat().catch(err => showToast(`Could not send chat message: ${err.message}`, { kind: 'warning' })); } });
  document.getElementById('chimeVoteStartBtn')?.addEventListener('click', () => chimeStartVote().catch(err => showToast(`Could not open ballot: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAttendanceSearchBtn')?.addEventListener('click', () => chimeSearchAttendanceMembers().catch(err => showToast(`Could not search members: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAttendanceSearchInput')?.addEventListener('keydown', event => { if (event.key === 'Enter') { event.preventDefault(); chimeSearchAttendanceMembers().catch(err => showToast(`Could not search members: ${err.message}`, { kind: 'warning' })); } });
  document.getElementById('chimeGuestAddBtn')?.addEventListener('click', () => chimeAddGuest().catch(err => showToast(`Could not add guest: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeQuorumSnapshotBtn')?.addEventListener('click', () => chimeStoreQuorumSnapshot().catch(err => showToast(`Could not store quorum snapshot: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeGuestLobbyRefreshBtn')?.addEventListener('click', () => chimeLoadGuestLobby().catch(err => showToast(`Could not load guest lobby: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeGuestAdmitAllBtn')?.addEventListener('click', () => chimeGuestLobbyAction('admit_all').catch(err => showToast(`Could not admit guests: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaSaveBtn')?.addEventListener('click', () => chimeSaveAgenda().catch(err => showToast(`Could not save agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaLoadSampleBtn')?.addEventListener('click', chimeLoadAgendaSample);
  document.getElementById('chimeAgendaPrevBtn')?.addEventListener('click', () => chimeAgendaAction('previous').catch(err => showToast(`Could not update agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaNextBtn')?.addEventListener('click', () => chimeAgendaAction('next').catch(err => showToast(`Could not update agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaFinishBtn')?.addEventListener('click', () => chimeAgendaAction('finish_agenda').catch(err => showToast(`Could not finish agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaResumeBtn')?.addEventListener('click', () => chimeAgendaAction('resume').catch(err => showToast(`Could not resume agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaJumpSelect')?.addEventListener('change', event => chimeAgendaSetActive(event.target.value).catch(err => showToast(`Could not jump agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaShowBtn')?.addEventListener('click', () => chimeAgendaAction('show').catch(err => showToast(`Could not show agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaHideBtn')?.addEventListener('click', () => chimeAgendaAction('hide').catch(err => showToast(`Could not hide agenda: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeAgendaReloadBtn')?.addEventListener('click', () => chimeReloadCurrentMeetingAgenda().catch(err => showToast(`Could not reload agenda: ${err.message}`, { kind: 'warning' }))); 
  document.getElementById('chimeVoteCloseBtn')?.addEventListener('click', () => chimeCloseVote().catch(err => showToast(`Could not close ballot: ${err.message}`, { kind: 'warning' })));
  document.getElementById('chimeFullscreenBtn')?.addEventListener('click', () => {
    const stage = document.getElementById('chimeStageCard');
    if (!chimeRequestFullscreen(stage)) showToast('Full-screen mode is not supported by this browser.', { kind: 'warning' });
  });
  window.addEventListener('beforeunload', () => { if (lrocChimeState.joined) chimeLeaveMeeting(); });
  chimeLoadStatus().then(() => Promise.allSettled([chimeLoadVote(), chimeLoadAttendance(), chimeLoadChat(), chimeLoadAgenda()])).catch(err => chimeSetText('chimeStatusPanel', `Could not load meeting status: ${err.message}`, 'chime-status-panel notice warning'));
}


function renderMaintenanceLogPage() {
  const signedIn = Boolean(window.lrocAuth?.isAuthenticated?.());
  return `
    <section class="section maintenance-log-page">
      <div class="section-head section-intro-head">
        <div class="eyebrow">Member vehicle tool</div>
        <h2>Vehicle Maintenance Log</h2>
        <p>Track servicing, repairs, inspections, costs, odometer readings and next due work for vehicles in your member profile.</p>
      </div>
      ${signedIn ? '' : `<div class="notice warning"><strong>Members only</strong><div style="margin-top:8px">Maintenance logs are a member benefit. Sign in to create and view private records for your vehicles.</div><div class="auth-actions"><button class="button" id="maintenanceLoginBtn" type="button">Member login</button><a class="button secondary" href="membership.html">Join LROC</a></div></div>`}
      <div id="maintenanceLogApp" class="${signedIn ? '' : 'hidden'}">
        <div class="grid-2">
          <article class="card card-pad">
            <div class="section-head" style="margin-bottom:14px"><div><div class="eyebrow">New entry</div><h3 style="margin:0">Record maintenance</h3></div></div>
            <div class="form-grid compact-grid">
              <div class="field"><label for="maintenanceVehicle">Vehicle</label><select id="maintenanceVehicle"><option value="">Loading vehicles…</option></select></div>
              <div class="field"><label for="maintenanceDate">Date</label><input id="maintenanceDate" type="date"></div>
              <div class="field"><label for="maintenanceType">Type</label><select id="maintenanceType"></select></div>
              <div class="field"><label for="maintenanceOdometer">Odometer</label><input id="maintenanceOdometer" inputmode="numeric" placeholder="e.g. 185000 km"></div>
              <div class="field"><label for="maintenanceTitle">Short title</label><input id="maintenanceTitle" maxlength="160" placeholder="Oil and filters"></div>
              <div class="field"><label for="maintenanceProvider">Supplier / mechanic</label><input id="maintenanceProvider" maxlength="160" placeholder="Self, workshop, parts supplier"></div>
              <div class="field"><label for="maintenanceCost">Cost of maintenance <span class="muted">optional</span></label><input id="maintenanceCost" inputmode="decimal" placeholder="e.g. 245.50"></div>
              <div class="field"><label for="maintenanceNextDueDate">Next due date</label><input id="maintenanceNextDueDate" type="date"></div>
              <div class="field"><label for="maintenanceNextDueOdo">Next due odometer</label><input id="maintenanceNextDueOdo" placeholder="e.g. 195000 km"></div>
            </div>
            <div class="field"><label for="maintenanceDescription">Description / work carried out</label><textarea id="maintenanceDescription" rows="5" maxlength="4000" placeholder="What was done, parts replaced, fluids used, torque notes, part numbers, etc."></textarea></div>
            <div class="field"><label for="maintenanceNotes">Notes</label><textarea id="maintenanceNotes" rows="3" maxlength="2000" placeholder="Optional private notes, reminders, lessons learned"></textarea></div>
            <div class="auth-actions"><button class="button" id="maintenanceSaveBtn" type="button">Save entry</button><button class="button ghost" id="maintenanceClearBtn" type="button">Clear</button></div>
            <div id="maintenanceNotice" class="notice" style="margin-top:14px">Loading your vehicles and logs…</div>
          </article>
          <article class="card card-pad">
            <div class="section-head" style="margin-bottom:14px"><div><div class="eyebrow">History</div><h3 style="margin:0">Maintenance history</h3></div><button class="button secondary" id="maintenanceRefreshBtn" type="button">Refresh</button></div>
            <div class="field"><label for="maintenanceFilterVehicle">Filter by vehicle</label><select id="maintenanceFilterVehicle"><option value="">All vehicles</option></select></div>
            <div id="maintenanceLogList" class="maintenance-log-list muted">No logs loaded yet.</div>
          </article>
        </div>
      </div>
    </section>`;
}

const maintenanceLogState = { vehicles: [], types: [], logs: [], editing: '' };

function maintenanceVehicleTitle(vehicle) {
  if (!vehicle) return 'Vehicle';
  return [vehicle.year, vehicle.make, vehicle.model, vehicle.rego_number ? `(${vehicle.rego_number})` : ''].filter(Boolean).join(' ');
}

function maintenanceSetNotice(text, kind = '') {
  const el = document.getElementById('maintenanceNotice');
  if (!el) return;
  el.className = kind ? `notice ${kind}` : 'notice';
  el.textContent = text || '';
}

function maintenancePopulateSelects() {
  const vehicles = maintenanceLogState.vehicles || [];
  const vehicleOptions = vehicles.map(v => `<option value="${escapeHtml(v.vehicle_id || '')}">${escapeHtml(maintenanceVehicleTitle(v))}</option>`).join('');
  const vehicleSelect = document.getElementById('maintenanceVehicle');
  const filterSelect = document.getElementById('maintenanceFilterVehicle');
  if (vehicleSelect) vehicleSelect.innerHTML = vehicleOptions || '<option value="">Add a vehicle in Profile first</option>';
  if (filterSelect) filterSelect.innerHTML = `<option value="">All vehicles</option>${vehicleOptions}`;
  const typeSelect = document.getElementById('maintenanceType');
  if (typeSelect) typeSelect.innerHTML = (maintenanceLogState.types || ['Service','Repair','Other']).map(type => `<option value="${escapeHtml(type)}">${escapeHtml(type)}</option>`).join('');
  const date = document.getElementById('maintenanceDate');
  if (date && !date.value) date.value = new Date().toISOString().slice(0, 10);
}

function maintenanceCollectForm() {
  return {
    log_id: maintenanceLogState.editing || '',
    vehicle_id: document.getElementById('maintenanceVehicle')?.value || '',
    maintenance_date: document.getElementById('maintenanceDate')?.value || '',
    maintenance_type: document.getElementById('maintenanceType')?.value || 'Other',
    odometer: document.getElementById('maintenanceOdometer')?.value || '',
    title: document.getElementById('maintenanceTitle')?.value || '',
    provider: document.getElementById('maintenanceProvider')?.value || '',
    cost: document.getElementById('maintenanceCost')?.value || '',
    next_due_date: document.getElementById('maintenanceNextDueDate')?.value || '',
    next_due_odometer: document.getElementById('maintenanceNextDueOdo')?.value || '',
    description: document.getElementById('maintenanceDescription')?.value || '',
    notes: document.getElementById('maintenanceNotes')?.value || '',
  };
}

function maintenanceClearForm() {
  maintenanceLogState.editing = '';
  ['maintenanceOdometer','maintenanceTitle','maintenanceProvider','maintenanceCost','maintenanceNextDueOdo','maintenanceDescription','maintenanceNotes'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  const due = document.getElementById('maintenanceNextDueDate'); if (due) due.value = '';
  const date = document.getElementById('maintenanceDate'); if (date) date.value = new Date().toISOString().slice(0, 10);
  const btn = document.getElementById('maintenanceSaveBtn'); if (btn) btn.textContent = 'Save entry';
}

function maintenanceEditLog(log) {
  maintenanceLogState.editing = log.log_id || '';
  const set = (id, value) => { const el = document.getElementById(id); if (el) el.value = value || ''; };
  set('maintenanceVehicle', log.vehicle_id); set('maintenanceDate', log.maintenance_date); set('maintenanceType', log.maintenance_type || 'Other'); set('maintenanceOdometer', log.odometer); set('maintenanceTitle', log.title); set('maintenanceProvider', log.provider); set('maintenanceCost', log.cost); set('maintenanceNextDueDate', log.next_due_date); set('maintenanceNextDueOdo', log.next_due_odometer); set('maintenanceDescription', log.description); set('maintenanceNotes', log.notes);
  const btn = document.getElementById('maintenanceSaveBtn'); if (btn) btn.textContent = 'Save changes';
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function maintenanceRenderLogs() {
  const el = document.getElementById('maintenanceLogList');
  if (!el) return;
  const filter = document.getElementById('maintenanceFilterVehicle')?.value || '';
  const logs = (maintenanceLogState.logs || []).filter(log => !filter || log.vehicle_id === filter);
  if (!logs.length) { el.className = 'maintenance-log-list muted'; el.textContent = 'No maintenance entries yet.'; return; }
  el.className = 'maintenance-log-list';
  el.innerHTML = logs.map(log => `<article class="maintenance-log-card">
    <div class="maintenance-log-card-head"><div><strong>${escapeHtml(log.title || log.maintenance_type || 'Maintenance')}</strong><div class="muted small-text">${escapeHtml(log.maintenance_date || '')} • ${escapeHtml(log.vehicle_title || '')}${log.odometer ? ` • ${escapeHtml(log.odometer)}` : ''}</div></div>${log.cost ? `<span class="tag">${escapeHtml(log.currency || 'AUD')} $${escapeHtml(log.cost)}</span>` : ''}</div>
    ${log.description ? `<p class="multiline-text">${formatMultilineText(log.description)}</p>` : ''}
    <div class="muted small-text">${escapeHtml(log.maintenance_type || 'Other')}${log.provider ? ` • ${escapeHtml(log.provider)}` : ''}${log.next_due_date ? ` • next due ${escapeHtml(log.next_due_date)}` : ''}${log.next_due_odometer ? ` • next ${escapeHtml(log.next_due_odometer)}` : ''}</div>
    ${log.notes ? `<p class="muted multiline-text">${formatMultilineText(log.notes)}</p>` : ''}
    <div class="auth-actions"><button class="button tiny secondary" type="button" data-maint-edit="${escapeHtml(log.log_id)}">Edit</button><button class="button tiny ghost" type="button" data-maint-delete="${escapeHtml(log.log_id)}">Delete</button></div>
  </article>`).join('');
  el.querySelectorAll('[data-maint-edit]').forEach(btn => btn.addEventListener('click', () => { const log = maintenanceLogState.logs.find(x => x.log_id === btn.dataset.maintEdit); if (log) maintenanceEditLog(log); }));
  el.querySelectorAll('[data-maint-delete]').forEach(btn => btn.addEventListener('click', () => maintenanceDeleteLog(btn.dataset.maintDelete).catch(err => showToast(`Could not delete entry: ${err.message}`, { kind: 'warning' }))));
}

async function maintenanceLoadLogs() {
  const data = await memberApiFetch('/member/vehicle-maintenance', { method: 'GET' });
  maintenanceLogState.vehicles = data.vehicles || [];
  maintenanceLogState.types = data.types || [];
  maintenanceLogState.logs = data.items || [];
  maintenancePopulateSelects();
  maintenanceRenderLogs();
  maintenanceSetNotice(`${maintenanceLogState.logs.length} maintenance entr${maintenanceLogState.logs.length === 1 ? 'y' : 'ies'} loaded.`, 'success');
}

async function maintenanceSaveLog() {
  const payload = maintenanceCollectForm();
  const data = await memberApiFetch('/member/vehicle-maintenance', { method: 'POST', body: JSON.stringify(payload) });
  showToast(data.message || 'Maintenance log saved.', { kind: 'success' });
  maintenanceClearForm();
  await maintenanceLoadLogs();
}

async function maintenanceDeleteLog(logId) {
  if (!confirm('Delete this maintenance log entry?')) return;
  await memberApiFetch('/member/vehicle-maintenance/delete', { method: 'POST', body: JSON.stringify({ log_id: logId }) });
  showToast('Maintenance log deleted.', { kind: 'success' });
  await maintenanceLoadLogs();
}

function wireMaintenanceLogPage() {
  document.getElementById('maintenanceLoginBtn')?.addEventListener('click', () => window.lrocAuth?.login?.(window.location.href));
  if (!window.lrocAuth?.isAuthenticated?.()) return;
  document.getElementById('maintenanceSaveBtn')?.addEventListener('click', () => maintenanceSaveLog().catch(err => { maintenanceSetNotice(err.message, 'warning'); showToast(`Could not save maintenance log: ${err.message}`, { kind: 'warning' }); }));
  document.getElementById('maintenanceClearBtn')?.addEventListener('click', maintenanceClearForm);
  document.getElementById('maintenanceRefreshBtn')?.addEventListener('click', () => maintenanceLoadLogs().catch(err => maintenanceSetNotice(err.message, 'warning')));
  document.getElementById('maintenanceFilterVehicle')?.addEventListener('change', maintenanceRenderLogs);
  maintenanceLoadLogs().catch(err => maintenanceSetNotice(`Could not load maintenance logs: ${err.message}`, 'warning'));
}

function renderMeetingAgendaPage() {
  const signedIn = Boolean(window.lrocAuth?.isAuthenticated?.());
  return `
    <section class="section meeting-agenda-page">
      <div class="section-head section-intro-head">
        <div class="eyebrow">Meeting Agenda</div>
        <h2>Meeting agendas and minutes</h2>
        <p>Prepare Committee, General Meeting, and Annual General Meeting agendas. Current agendas can be linked into formal Chime meetings.</p>
      </div>
      ${signedIn ? '' : `<div class="notice warning"><strong>Login required</strong><div style="margin-top:8px">Sign in as an LROC member to view meeting agendas and minutes.</div><div class="auth-actions"><button class="button" id="meetingAgendaLoginBtn" type="button">Login</button></div></div>`}
      <div id="meetingAgendaApp" class="${signedIn ? '' : 'hidden'}">
        <div class="card card-pad meeting-agenda-toolbar">
          <div class="form-grid compact-grid">
            <div class="field"><label for="meetingAgendaType">Meeting type</label><select id="meetingAgendaType"><option value="committee">Committee Meeting</option><option value="general">General Meeting</option><option value="agm">Annual General Meeting</option></select></div>
            <div class="field"><label>&nbsp;</label><button class="button secondary" id="meetingAgendaRefreshBtn" type="button">Refresh</button></div>
          </div>
          <div id="meetingAgendaNotice" class="muted" style="margin-top:10px">Loading agenda…</div>
        </div>
        <div class="card card-pad" id="meetingAgendaDetailsCard"></div>
        <div class="card card-pad" id="meetingAgendaItemsCard"></div>
        <div class="card card-pad" id="meetingAgendaSuggestionCard"></div>
        <div class="card card-pad" id="meetingAgendaMinutesCard"></div>
      </div>
    </section>`;
}

const meetingAgendaState = { data: null, type: 'committee', editingItemId: null };

function meetingAgendaCanManage() { return Boolean(meetingAgendaState.data?.permissions?.can_manage); }
function meetingAgendaCanClose() { return Boolean(meetingAgendaState.data?.permissions?.can_close); }
function meetingAgendaItems() {
  return [...(meetingAgendaState.data?.items || [])].sort((a, b) => Number(a.sort_order || 0) - Number(b.sort_order || 0));
}
function meetingAgendaSectionsOptions(selected = '') {
  const sections = meetingAgendaState.data?.sections || [];
  return sections.map(section => `<option value="${escapeHtml(section.id)}" ${section.id === selected ? 'selected' : ''}>${escapeHtml(section.label)}</option>`).join('');
}
function meetingAgendaDateValue(value = '') {
  const text = String(value || '').trim();
  const match = text.match(/^(\d{4}-\d{2}-\d{2})/);
  return match ? match[1] : '';
}

function meetingAgendaTimeValue(value = '') {
  const text = String(value || '').trim();
  const match24 = text.match(/^(\d{1,2}):(\d{2})/);
  if (match24) return `${String(match24[1]).padStart(2, '0')}:${match24[2]}`;
  const match12 = text.match(/^(\d{1,2})(?::(\d{2}))?\s*(am|pm)$/i);
  if (!match12) return '';
  let hour = Number(match12[1]);
  const minute = match12[2] || '00';
  const suffix = match12[3].toLowerCase();
  if (suffix === 'pm' && hour < 12) hour += 12;
  if (suffix === 'am' && hour === 12) hour = 0;
  return `${String(hour).padStart(2, '0')}:${minute}`;
}

function meetingAgendaDisplayDate(value = '') {
  const iso = meetingAgendaDateValue(value);
  if (!iso) return String(value || 'Date not set');
  const [year, month, day] = iso.split('-').map(Number);
  return new Date(year, month - 1, day).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' });
}

function meetingAgendaDisplayTime(value = '') {
  const time = meetingAgendaTimeValue(value);
  if (!time) return String(value || 'Time not set');
  const [hour, minute] = time.split(':').map(Number);
  const d = new Date();
  d.setHours(hour, minute, 0, 0);
  return d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
}
function meetingAgendaSetNotice(text, kind = '') {
  const el = document.getElementById('meetingAgendaNotice');
  if (!el) return;
  el.className = kind ? `notice ${kind}` : 'muted';
  el.textContent = text || '';
}
function renderMeetingAgendaDetails() {
  const card = document.getElementById('meetingAgendaDetailsCard');
  if (!card) return;
  const agenda = meetingAgendaState.data?.agenda || {};
  const canManage = meetingAgendaCanManage();
  if (!agenda.meeting_id) { card.innerHTML = '<p class="muted">No agenda loaded.</p>'; return; }
  if (!canManage) {
    card.innerHTML = `<div class="section-head" style="margin:0 0 12px"><div class="eyebrow">Current agenda</div><h2>${escapeHtml(agenda.title || 'Meeting')}</h2></div>
      <p class="muted">${escapeHtml(meetingAgendaDisplayDate(agenda.scheduled_at))} · ${escapeHtml(meetingAgendaDisplayTime(agenda.start_time))} · ${escapeHtml(agenda.location || 'Location not set')}</p>`;
    return;
  }
  card.innerHTML = `<div class="section-head" style="margin:0 0 12px"><div class="eyebrow">Current agenda</div><h2>Edit meeting details</h2></div>
    <div class="form-grid compact-grid">
      <div class="field"><label>Title</label><input id="meetingAgendaTitle" value="${escapeHtml(agenda.title || '')}"></div>
      <div class="field"><label for="meetingAgendaScheduled">Meeting date</label><input id="meetingAgendaScheduled" type="date" value="${escapeHtml(meetingAgendaDateValue(agenda.scheduled_at || ''))}"></div>
      <div class="field"><label for="meetingAgendaStart">Meeting start time</label><input id="meetingAgendaStart" type="time" value="${escapeHtml(meetingAgendaTimeValue(agenda.start_time || ''))}"></div>
      <div class="field"><label for="meetingAgendaEnd">Meeting end time</label><input id="meetingAgendaEnd" type="time" value="${escapeHtml(meetingAgendaTimeValue(agenda.end_time || ''))}"></div>
      <div class="field"><label>Location</label><input id="meetingAgendaLocation" value="${escapeHtml(agenda.location || '')}"></div>
      <div class="field"><label>Chair</label><input id="meetingAgendaChair" value="${escapeHtml(agenda.chair || '')}"></div>
      <div class="field"><label>Secretary / minute taker</label><input id="meetingAgendaSecretary" value="${escapeHtml(agenda.secretary || '')}"></div>
    </div>
    <div class="auth-actions" style="margin-top:12px"><button class="button" id="meetingAgendaSaveMeetingBtn" type="button">Save meeting details</button><button class="button secondary" id="meetingAgendaPreviewPdfBtn" type="button">Preview PDF</button>${meetingAgendaCanClose() ? '<button class="button danger" id="meetingAgendaFinaliseBtn" type="button">Finalise minutes</button>' : ''}</div>`;
}
function meetingAgendaItemSummary(item) {
  const bits = [];
  if (item.section_id) bits.push(String(item.section_id).replace(/-/g, ' '));
  if (item.voting_enabled) bits.push('Voting item');
  if (item.status) bits.push(`Status: ${item.status}`);
  return bits.join(' • ');
}

function meetingAgendaRenderEditFields(item = {}, isNew = false) {
  return `
    <div class="form-grid agenda-grid">
      <div class="field small-field"><label>No.</label><input data-field="sort_order" value="${escapeHtml(item.sort_order || '')}"></div>
      <div class="field"><label>Section</label><select data-field="section_id">${meetingAgendaSectionsOptions(item.section_id || 'general-business')}</select></div>
      <div class="field"><label>Title</label><input data-field="title" value="${escapeHtml(item.title || '')}" placeholder="Agenda item"></div>
      <div class="field checkbox-field"><label><input type="checkbox" data-field="voting_enabled" ${item.voting_enabled ? 'checked' : ''}> Voting item</label></div>
    </div>
    <div class="form-grid compact-grid">
      <div class="field"><label>Agenda / background</label><textarea rows="3" data-field="agenda_text">${escapeHtml(item.agenda_text || '')}</textarea></div>
      <div class="field"><label>Motion wording</label><textarea rows="3" data-field="motion_text">${escapeHtml(item.motion_text || '')}</textarea></div>
      <div class="field"><label>Minute / outcome</label><textarea rows="3" data-field="minute_text">${escapeHtml(item.minute_text || '')}</textarea></div>
      <div class="field"><label>Action</label><textarea rows="3" data-field="action_text">${escapeHtml(item.action_text || '')}</textarea></div>
      <div class="field"><label>Assigned to</label><input data-field="action_assigned_to" value="${escapeHtml(item.action_assigned_to || '')}"></div>
      <div class="field"><label>Due</label><input data-field="action_due" value="${escapeHtml(item.action_due || '')}"></div>
      <div class="field"><label>Status</label><select data-field="status"><option value="open" ${item.status === 'open' ? 'selected' : ''}>Open</option><option value="deferred" ${item.status === 'deferred' ? 'selected' : ''}>Deferred</option><option value="closed" ${item.status === 'closed' ? 'selected' : ''}>Closed</option></select></div>
    </div>
    <div class="auth-actions">
      <button class="button secondary" type="button" data-save-agenda-item>${isNew ? 'Add item' : 'Save item'}</button>
      <button class="button ghost" type="button" data-cancel-agenda-edit>Cancel</button>
      ${isNew ? '' : '<button class="button ghost" type="button" data-delete-agenda-item>Delete</button>'}
    </div>`;
}

function renderMeetingAgendaItems() {
  const card = document.getElementById('meetingAgendaItemsCard');
  if (!card) return;
  const canManage = meetingAgendaCanManage();
  const rows = meetingAgendaItems();
  const readonlyRows = rows.map(item => `<article class="agenda-readonly-item"><div class="tag">${escapeHtml(String(item.sort_order || ''))}</div><h3>${escapeHtml(item.title || 'Agenda item')}</h3>${item.agenda_text ? `<p class="multiline-text">${formatMultilineText(item.agenda_text)}</p>` : ''}${item.motion_text ? `<p class="multiline-text"><strong>Motion:</strong> ${formatMultilineText(item.motion_text)}</p>` : ''}${item.voting_enabled ? '<span class="tag">Voting enabled</span>' : ''}</article>`).join('') || '<p class="muted">No agenda items yet.</p>';
  if (!canManage) { card.innerHTML = `<h2>Agenda items</h2><div class="meeting-agenda-readonly-list">${readonlyRows}</div>`; return; }
  const editingId = meetingAgendaState.editingItemId;
  const editRows = rows.map(item => {
    const itemId = String(item.item_id || '');
    const open = editingId === itemId;
    return `<article class="meeting-agenda-edit-row ${open ? 'is-editing' : 'is-collapsed'}" data-item-id="${escapeHtml(itemId)}">
      <div class="meeting-agenda-item-summary">
        <div class="meeting-agenda-item-number">${escapeHtml(String(item.sort_order || ''))}</div>
        <div class="meeting-agenda-item-main">
          <h3>${escapeHtml(item.title || 'Agenda item')}</h3>
          <div class="muted small-text">${escapeHtml(meetingAgendaItemSummary(item) || 'Agenda item')}</div>
          ${!open && item.motion_text ? `<p class="muted multiline-text"><strong>Motion:</strong> ${formatMultilineText(item.motion_text)}</p>` : ''}
        </div>
        <div class="meeting-agenda-item-actions">
          ${open ? '' : '<button class="button secondary" type="button" data-edit-agenda-item>Edit</button>'}
        </div>
      </div>
      ${open ? `<div class="meeting-agenda-edit-fields">${meetingAgendaRenderEditFields(item, false)}</div>` : ''}
    </article>`;
  }).join('');
  const adding = editingId === '__new__';
  const addCard = `<article class="meeting-agenda-edit-row ${adding ? 'is-editing' : 'is-collapsed'}" data-item-id="">
    <div class="meeting-agenda-item-summary">
      <div class="meeting-agenda-item-number">+</div>
      <div class="meeting-agenda-item-main"><h3>Add agenda item</h3><div class="muted small-text">Create a new agenda row after the current items.</div></div>
      <div class="meeting-agenda-item-actions">${adding ? '' : '<button class="button" type="button" data-add-agenda-item>Add item</button>'}</div>
    </div>
    ${adding ? `<div class="meeting-agenda-edit-fields">${meetingAgendaRenderEditFields({ sort_order: rows.length + 1, section_id: 'general-business', status: 'open' }, true)}</div>` : ''}
  </article>`;
  card.innerHTML = `<div class="section-head" style="margin:0 0 12px"><div class="eyebrow">Agenda workspace</div><h2>Agenda items</h2><p>Items are collapsed for readability. Open one item at a time to edit, then save it. Voting items are exposed to formal Chime meeting controls.</p></div>
    <div class="meeting-agenda-edit-list">${editRows}${addCard}</div>`;
}

function renderMeetingAgendaSuggestion() {
  const card = document.getElementById('meetingAgendaSuggestionCard');
  if (!card) return;
  const canManage = meetingAgendaCanManage();
  card.innerHTML = `<h2>Agenda suggestions</h2>
    <p class="muted">Members can suggest items for the selected meeting type. Email suggestions can later use ${escapeHtml(meetingAgendaState.data?.suggestion_email || 'meetingagenda@<domain>')}.</p>
    <div class="form-grid compact-grid"><div class="field"><label>Suggestion title</label><input id="meetingAgendaSuggestionTitle"></div><div class="field"><label>Details</label><textarea rows="3" id="meetingAgendaSuggestionDetails"></textarea></div></div>
    <button class="button secondary" id="meetingAgendaSuggestBtn" type="button">Submit suggestion</button>
    ${canManage ? '<div id="meetingAgendaSuggestionsList" style="margin-top:14px"></div>' : ''}`;
}
async function renderMeetingAgendaMinutes() {
  const card = document.getElementById('meetingAgendaMinutesCard');
  if (!card) return;
  try {
    const data = await memberApiFetch(`/member/meeting-agenda/minutes?type=${encodeURIComponent(meetingAgendaState.type)}`);
    const links = (data.items || []).map(item => `<article class="minutes-row"><div><strong>${escapeHtml(item.title || 'Meeting minutes')}</strong><div class="muted">${escapeHtml(item.finalised_at || '')}</div></div><button class="button ghost" type="button" data-download-minutes="${escapeHtml(item.minutes_id || '')}">Download</button></article>`).join('') || '<p class="muted">No finalised minutes yet.</p>';
    card.innerHTML = `<h2>Finalised minutes</h2>${links}`;
  } catch (err) { card.innerHTML = `<h2>Finalised minutes</h2><p class="notice warning">Could not load minutes: ${escapeHtml(err.message)}</p>`; }
}
function meetingAgendaCollectItem(row) {
  const out = { meeting_type: meetingAgendaState.type, item_id: row?.dataset?.itemId || '' };
  row.querySelectorAll('[data-field]').forEach(el => {
    const key = el.dataset.field;
    out[key] = el.type === 'checkbox' ? Boolean(el.checked) : el.value;
  });
  return out;
}
async function meetingAgendaLoad() {
  meetingAgendaSetNotice('Loading agenda…');
  const type = document.getElementById('meetingAgendaType')?.value || meetingAgendaState.type || 'committee';
  if (meetingAgendaState.type !== type) meetingAgendaState.editingItemId = null;
  meetingAgendaState.type = type;
  const data = await memberApiFetch(`/member/meeting-agenda/current?type=${encodeURIComponent(type)}`);
  meetingAgendaState.data = data;
  renderMeetingAgendaDetails();
  renderMeetingAgendaItems();
  renderMeetingAgendaSuggestion();
  await renderMeetingAgendaMinutes();
  meetingAgendaSetNotice(`${data.agenda?.title || 'Agenda'} loaded. ${data.items?.length || 0} item(s).`);
  if (meetingAgendaCanManage()) meetingAgendaLoadSuggestions().catch(() => {});
}
async function meetingAgendaLoadSuggestions() {
  const target = document.getElementById('meetingAgendaSuggestionsList');
  if (!target) return;
  const data = await memberApiFetch(`/member/meeting-agenda/suggestions?type=${encodeURIComponent(meetingAgendaState.type)}`);
  target.innerHTML = (data.items || []).map(item => `<article class="suggestion-row"><strong>${escapeHtml(item.title || '')}</strong><p class="muted multiline-text">${formatMultilineText(item.details || '')}</p><button class="button secondary" type="button" data-add-suggestion="${escapeHtml(item.suggestion_id || '')}">Add to agenda</button><button class="button ghost" type="button" data-dismiss-suggestion="${escapeHtml(item.suggestion_id || '')}">Dismiss</button></article>`).join('') || '<p class="muted">No open suggestions.</p>';
}

async function meetingAgendaPreviewPdf() {
  const data = await memberApiFetch('/member/meeting-agenda/preview-pdf', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type }) });
  if (data.url) window.open(data.url, '_blank', 'noopener');
  showToast(data.message || 'Agenda preview generated.', { kind: 'success' });
}
function wireMeetingAgendaPage() {
  document.getElementById('meetingAgendaLoginBtn')?.addEventListener('click', () => window.lrocAuth?.login?.(window.location.href));
  if (!window.lrocAuth?.isAuthenticated?.()) return;
  document.getElementById('meetingAgendaType')?.addEventListener('change', () => meetingAgendaLoad().catch(err => meetingAgendaSetNotice(`Could not load agenda: ${err.message}`, 'warning')));
  document.getElementById('meetingAgendaRefreshBtn')?.addEventListener('click', () => meetingAgendaLoad().catch(err => meetingAgendaSetNotice(`Could not load agenda: ${err.message}`, 'warning')));
  document.addEventListener('click', async (event) => {
    const saveMeeting = event.target.closest?.('#meetingAgendaSaveMeetingBtn');
    const previewPdf = event.target.closest?.('#meetingAgendaPreviewPdfBtn');
    const finalise = event.target.closest?.('#meetingAgendaFinaliseBtn');
    const editItem = event.target.closest?.('[data-edit-agenda-item]');
    const addItem = event.target.closest?.('[data-add-agenda-item]');
    const cancelEdit = event.target.closest?.('[data-cancel-agenda-edit]');
    const saveItem = event.target.closest?.('[data-save-agenda-item]');
    const deleteItem = event.target.closest?.('[data-delete-agenda-item]');
    const suggest = event.target.closest?.('#meetingAgendaSuggestBtn');
    const addSuggestion = event.target.closest?.('[data-add-suggestion]');
    const dismissSuggestion = event.target.closest?.('[data-dismiss-suggestion]');
    const downloadMinutes = event.target.closest?.('[data-download-minutes]');
    try {
      if (saveMeeting) {
        await memberApiFetch('/member/meeting-agenda/meeting', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, title: document.getElementById('meetingAgendaTitle')?.value || '', scheduled_at: document.getElementById('meetingAgendaScheduled')?.value || '', start_time: document.getElementById('meetingAgendaStart')?.value || '', end_time: document.getElementById('meetingAgendaEnd')?.value || '', location: document.getElementById('meetingAgendaLocation')?.value || '', chair: document.getElementById('meetingAgendaChair')?.value || '', secretary: document.getElementById('meetingAgendaSecretary')?.value || '' }) });
        await meetingAgendaLoad(); showToast('Meeting details saved.');
      } else if (previewPdf) {
        await meetingAgendaPreviewPdf();
      } else if (editItem) {
        const row = editItem.closest('[data-item-id]');
        meetingAgendaState.editingItemId = row?.dataset?.itemId || null;
        renderMeetingAgendaItems();
      } else if (addItem) {
        meetingAgendaState.editingItemId = '__new__';
        renderMeetingAgendaItems();
      } else if (cancelEdit) {
        meetingAgendaState.editingItemId = null;
        renderMeetingAgendaItems();
      } else if (finalise) {
        if (!confirm('Finalise these minutes and create the next current agenda?')) return;
        await memberApiFetch('/member/meeting-agenda/finalise', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type }) });
        await meetingAgendaLoad(); showToast('Minutes finalised.');
      } else if (saveItem) {
        const row = saveItem.closest('[data-item-id]');
        await memberApiFetch('/member/meeting-agenda/items', { method: 'POST', body: JSON.stringify(meetingAgendaCollectItem(row)) });
        meetingAgendaState.editingItemId = null;
        await meetingAgendaLoad(); showToast('Agenda item saved.');
      } else if (deleteItem) {
        const row = deleteItem.closest('[data-item-id]');
        if (!row?.dataset?.itemId || !confirm('Delete this agenda item?')) return;
        await memberApiFetch('/member/meeting-agenda/items/delete', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, item_id: row.dataset.itemId }) });
        meetingAgendaState.editingItemId = null;
        await meetingAgendaLoad(); showToast('Agenda item deleted.');
      } else if (suggest) {
        await memberApiFetch('/member/meeting-agenda/suggestions', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, title: document.getElementById('meetingAgendaSuggestionTitle')?.value || '', details: document.getElementById('meetingAgendaSuggestionDetails')?.value || '' }) });
        document.getElementById('meetingAgendaSuggestionTitle').value = ''; document.getElementById('meetingAgendaSuggestionDetails').value = ''; showToast('Suggestion submitted.'); if (meetingAgendaCanManage()) await meetingAgendaLoadSuggestions();
      } else if (addSuggestion) {
        await memberApiFetch('/member/meeting-agenda/suggestions/add', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, suggestion_id: addSuggestion.dataset.addSuggestion }) });
        await meetingAgendaLoad(); showToast('Suggestion added to agenda.');
      } else if (dismissSuggestion) {
        await memberApiFetch('/member/meeting-agenda/suggestions/dismiss', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, suggestion_id: dismissSuggestion.dataset.dismissSuggestion }) });
        await meetingAgendaLoadSuggestions(); showToast('Suggestion dismissed.');
      } else if (downloadMinutes) {
        const data = await memberApiFetch('/member/meeting-agenda/minutes/download-url', { method: 'POST', body: JSON.stringify({ meeting_type: meetingAgendaState.type, minutes_id: downloadMinutes.dataset.downloadMinutes }) });
        if (data.url) window.open(data.url, '_blank', 'noopener');
      }
    } catch (err) { showToast(err.message || 'Agenda action failed.', { kind: 'warning', duration: 7000 }); }
  });
  meetingAgendaLoad().catch(err => meetingAgendaSetNotice(`Could not load agenda: ${err.message}`, 'warning'));
}

async function mountPage() {
  if (window.lrocAuth?.handleRedirect) {
    try {
      await window.lrocAuth.handleRedirect();
    } catch (err) {
      console.error('Authentication redirect handling failed.', err);
    }
  }
  const base = await loadPublishedContent();
  window.__lrocBaseContent = base;
  const page = document.body.dataset.page;
  const content = shouldUseDraftContent(page) ? getDraftContent(base) : structuredClone(base);
  const app = document.getElementById('app');
  if (isStandaloneDisplayMode()) document.body.classList.add('lroc-standalone');
  else document.body.classList.remove('lroc-standalone');
  app.insertAdjacentHTML('beforebegin', renderHeader(content) + renderDevelopmentSiteBanner());
  let html = '';
  if (page === 'home') html = renderHome(content);
  else if (page === 'events') html = renderTripsEventsPage(content);
  else if (page === 'trips') html = renderTripGuidesPage(content);
  else if (page === 'training') html = renderGenericPage(content, 'training');
  else if (page === 'documents') html = renderGenericPage(content, 'documents');
  else if (page === 'articles') html = renderArticlesPage();
  else if (page === 'magazines') html = renderMagazinesPage();
  else if (page === 'membership') html = renderGenericPage(content, 'membership');
  else if (page === 'members') html = renderGenericPage(content, 'members');
  else if (page === 'about') html = renderGenericPage(content, 'about');
  else if (page === 'committee') html = renderGenericPage(content, 'committee');
  else if (page === 'terms') html = renderGenericPage(content, 'terms');
  else if (page === 'disclaimer') html = renderGenericPage(content, 'disclaimer');
  else if (page === 'privacy') html = renderGenericPage(content, 'privacy');
  else if (page === 'policies') html = renderGenericPage(content, 'policies');
  else if (page === 'contact') html = renderGenericPage(content, 'contact');
  else if (page === 'profile') html = renderProfilePage();
  else if (page === 'vin-check') html = renderVinCheckPage();
  else if (page === 'vehicle-help') html = renderVehicleHelpPage(content);
  else if (page === 'maintenance-log') html = renderMaintenanceLogPage();
  else if (page === 'historic-registration') html = renderHistoricRegistrationPage(content);
  else if (page === 'chat') html = renderChatPage();
  else if (page === 'chime-meeting') html = renderChimeMeetingPage();
  else if (page === 'meeting-agenda') html = renderMeetingAgendaPage();
  else if (page === 'webmail') html = renderWebmailPage();
  else if (page === 'admin') html = renderAdmin(content);
  else if (page === 'magazine-admin') html = renderMagazineProductionPage();
  app.innerHTML = html;
  app.insertAdjacentHTML('afterend', renderFooter(content));
  document.body.insertAdjacentHTML('beforeend', renderGlobalLoginModal());
  document.body.insertAdjacentHTML('beforeend', renderSiteAboutModal(content));

  document.querySelectorAll('a[href="members.html"], a[href="chat.html"], a[href="chime-meeting.html"], a[href="meeting-agenda.html"]').forEach(link => {
    link.addEventListener('click', (event) => {
      if (!window.lrocAuth?.isAuthenticated?.()) {
        event.preventDefault();
        sessionStorage.setItem('lroc_auth_return_to', `${window.location.origin}/${link.getAttribute('href') || 'members.html'}`);
        window.lrocAuth?.login?.();
      }
    });
  });

  wireHeaderAuthControls();
  wireSiteNavDrawer();
  wireSiteAboutModal();
  hydrateProfileAvatarFromMetadata().catch(() => {});
  window.addEventListener('lroc:auth-changed', () => {
    syncHeaderAuthUi();
    syncVinCheckAccessUi();
    if (window.lrocAuth?.isAuthenticated?.()) {
      startSessionMonitor();
      hydrateProfileAvatarFromMetadata({ force: true }).catch(() => {});
      refreshWebmailNavHint().catch(() => {});
    } else {
      sessionStorage.removeItem('lroc_webmail_available');
      stopSessionMonitor();
      syncWebmailNavigationUi();
    }
  });
  startSessionMonitor();
  if (window.__lrocContentLoadWarning) {
    showToast(window.__lrocContentLoadWarning, { kind: 'warning', duration: 7000, dedupeKey: 'content-load-warning' });
  }

  if (page === 'home') wireHomePage();
  if (page === 'admin') wireAdmin(base);
  if (page === 'magazine-admin') wireMagazineProductionPage();
  if (page === 'members' || page === 'chat' || page === 'vin-check' || page === 'chime-meeting' || page === 'meeting-agenda') wireMembersPortal();
  if (page === 'profile') wireProfilePage();
  if (page === 'vin-check') wireVinCheckPage();
  if (page === 'vehicle-help') wireVehicleHelpPage();
  if (page === 'maintenance-log') wireMaintenanceLogPage();
  if (page === 'historic-registration') wireHistoricRegistrationPage();
  if (page === 'articles') wireArticlesPage();
  if (page === 'magazines') wireMagazinesPage();
  if (page === 'events') wireEventsPage();
  if (page === 'webmail') wireWebmailPage();
  if (page === 'chime-meeting') wireChimeMeetingPage();
  if (page === 'meeting-agenda') wireMeetingAgendaPage();
  if (window.lrocAuth?.isAuthenticated?.()) refreshWebmailNavHint().catch(() => {});
}

function wireHomePage() {
  const loginBtn = document.getElementById('mobileDashboardLoginBtn');
  loginBtn?.addEventListener('click', (event) => {
    event.preventDefault();
    window.lrocAuth?.login?.(window.location.href);
  });

  const installSection = document.getElementById('installHelpSection');
  const installModal = document.getElementById('installHelpModal');
  const modalClose = document.getElementById('installHelpModalClose');
  const modalTitle = document.getElementById('installHelpModalTitle');
  const modalMeta = document.getElementById('installHelpModalMeta');
  const modalBody = document.getElementById('installHelpModalBody');
  const modalActions = document.getElementById('installHelpModalActions');
  if (!installSection || !installModal || !modalBody || !modalActions) return;

  const platform = detectClientPlatform();
  const standalone = isStandaloneDisplayMode();
  if (standalone) {
    installSection.classList.add('hidden');
    return;
  }

  const showButtons = Array.from(installSection.querySelectorAll('[data-install-platform]'));
  if (platform === 'ios') {
    showButtons.forEach((button) => button.classList.toggle('hidden', button.dataset.installPlatform !== 'ios'));
  } else if (platform === 'android') {
    showButtons.forEach((button) => button.classList.toggle('hidden', button.dataset.installPlatform !== 'android'));
  } else {
    showButtons.forEach((button) => button.classList.remove('hidden'));
  }

  function closeInstallModal() {
    installModal.classList.add('hidden');
  }

  async function promptAndroidInstall() {
    if (!deferredInstallPromptEvent) return false;
    try {
      await deferredInstallPromptEvent.prompt();
      await deferredInstallPromptEvent.userChoice;
      deferredInstallPromptEvent = null;
      closeInstallModal();
      installSection.classList.add('hidden');
      return true;
    } catch {
      return false;
    }
  }

  function renderInstallModal(platformKey) {
    const isIos = platformKey === 'ios';
    modalTitle.textContent = isIos ? 'Install on iPhone' : 'Install on Android';
    modalMeta.textContent = isIos ? 'Use Safari on iPhone or iPad.' : 'Use Chrome or another Android browser that supports install.';
    modalBody.innerHTML = isIos ? `
      <ol>
        <li>Open https://lroc.vk2ale.com in Safari.</li>
        <li>Tap <strong>Share</strong>.</li>
        <li>Choose <strong>Add to Home Screen</strong>.</li>
        <li>Turn on <strong>Open as Web App</strong> if offered, then tap <strong>Add</strong>.</li>
      </ol>
      <p class="muted">A native App Store version can come later. For now this gives you the best app-like experience on iPhone.</p>` : `
      <ol>
        <li>Open https://lroc.vk2ale.com in Chrome on Android.</li>
        <li>Tap the browser menu.</li>
        <li>Choose <strong>Add to Home screen</strong> or <strong>Install app</strong>.</li>
        <li>Confirm the install prompt.</li>
      </ol>
      <p class="muted">A Play Store version can come later. For now this gives you the quickest app-style install on Android.</p>`;
    modalActions.innerHTML = isIos
      ? '<button class="button secondary" type="button" id="installHelpDoneBtn">Done</button>'
      : `<button class="button secondary" type="button" id="installHelpDoneBtn">Done</button>${deferredInstallPromptEvent ? '<button class="button" type="button" id="installHelpPromptBtn">Try install now</button>' : ''}`;
    installModal.classList.remove('hidden');
    document.getElementById('installHelpDoneBtn')?.addEventListener('click', closeInstallModal, { once: true });
    document.getElementById('installHelpPromptBtn')?.addEventListener('click', () => { promptAndroidInstall(); }, { once: true });
  }

  installSection.querySelectorAll('[data-install-platform]').forEach((button) => {
    button.addEventListener('click', () => renderInstallModal(button.dataset.installPlatform));
  });
  modalClose?.addEventListener('click', closeInstallModal);
  installModal.addEventListener('click', (event) => {
    if (event.target === installModal) closeInstallModal();
  });
  window.addEventListener('lroc:install-prompt-ready', () => {
    if (!isStandaloneDisplayMode()) installSection.classList.remove('hidden');
  });
}


async function wireRolesPositionsAdmin() {
  const posBody = document.getElementById('rolePositionsBody');
  const posNotice = document.getElementById('rolePositionNotice');
  const posId = document.getElementById('rolePositionId');
  const posName = document.getElementById('rolePositionName');
  const posEmail = document.getElementById('rolePositionEmail');
  const posSort = document.getElementById('rolePositionSort');
  const posCommittee = document.getElementById('rolePositionCommittee');
  const posActive = document.getElementById('rolePositionActive');
  const posSave = document.getElementById('rolePositionSaveBtn');
  const posClear = document.getElementById('rolePositionClearBtn');
  const memberSearch = document.getElementById('roleMemberSearch');
  const memberSelect = document.getElementById('roleMemberSelect');
  const memberPosition = document.getElementById('roleMemberPosition');
  const memberStoredRole = document.getElementById('roleMemberStoredRole');
  const memberSave = document.getElementById('roleMemberSaveBtn');
  const memberNotice = document.getElementById('roleMemberNotice');
  if (!posBody && !memberSelect) return;
  let positions = [];
  let members = [];

  const setPosNotice = (text) => { if (posNotice) posNotice.textContent = text || ''; };
  const setMemberNotice = (text) => { if (memberNotice) memberNotice.textContent = text || ''; };
  function clearPositionForm() {
    if (posId) posId.value = '';
    if (posName) posName.value = '';
    if (posEmail) posEmail.value = '';
    if (posSort) posSort.value = '';
    if (posCommittee) posCommittee.checked = true;
    if (posActive) posActive.checked = true;
  }
  function fillPositionForm(item) {
    if (posId) posId.value = item.position_id || '';
    if (posName) posName.value = item.position_name || '';
    if (posEmail) posEmail.value = item.email_address || '';
    if (posSort) posSort.value = item.sort_order || '';
    if (posCommittee) posCommittee.checked = item.is_committee_position !== false;
    if (posActive) posActive.checked = item.active !== false;
  }
  function renderPositions() {
    if (posBody) {
      posBody.innerHTML = positions.length ? positions.map(item => `<tr><td>${escapeHtml(item.position_name || '')}</td><td>${escapeHtml(item.email_address || '')}</td><td>${item.active === false ? 'Inactive' : 'Active'}</td><td><button class="button ghost role-position-edit" type="button" data-id="${escapeHtml(item.position_id || '')}">Edit</button></td></tr>`).join('') : '<tr><td colspan="4" class="muted">No positions configured.</td></tr>';
      posBody.querySelectorAll('.role-position-edit').forEach(btn => btn.addEventListener('click', () => {
        const item = positions.find(p => p.position_id === btn.dataset.id);
        if (item) fillPositionForm(item);
      }));
    }
    if (memberPosition) {
      const current = memberPosition.value || '';
      memberPosition.innerHTML = '<option value="">No club role / position</option>' + positions.filter(p => p.active !== false).map(p => `<option value="${escapeHtml(p.position_id || '')}">${escapeHtml(p.position_name || '')}</option>`).join('');
      memberPosition.value = current;
    }
  }
  async function loadPositions() {
    const data = await memberApiFetch('/admin/positions', { method: 'GET' });
    positions = data.items || [];
    renderPositions();
    setPosNotice(`${positions.length} position(s) loaded.`);
  }
  function rolePositionLabel(item) {
    const roleName = item?.committee_position_name || item?.official_position_name || '';
    const roleId = item?.committee_position_id || item?.official_position_id || '';
    if (roleName) return roleName;
    if (roleId) return String(roleId).replace(/-/g, ' ').replace(/\b\w/g, ch => ch.toUpperCase());
    return '';
  }
  function roleMemberDisplayName(item) {
    const num = item?.member_number || item?.site_member_id || '';
    const role = rolePositionLabel(item);
    const name = item?.name || item?.email || item?.sub || '';
    return `${num ? num + ' — ' : ''}${name}${item?.email ? ' — ' + item.email : ''}${role ? ' — ' + role : ''}`;
  }
  function renderMembers() {
    if (!memberSelect) return;
    memberSelect.innerHTML = '<option value="">Choose a member</option>' + members.map(item => `<option value="${escapeHtml(item.sub || '')}">${escapeHtml(roleMemberDisplayName(item))}</option>`).join('');
  }
  async function loadMembers() {
    const q = memberSearch?.value || '';
    const data = await memberApiFetch(`/admin/member-metadata?q=${encodeURIComponent(q)}`, { method: 'GET' });
    members = data.items || [];
    renderMembers();
    setMemberNotice(`${members.length} member(s) loaded.`);
  }
  function showSelectedMember() {
    const item = members.find(m => m.sub === memberSelect?.value);
    const groups = item?.groups || item?.system_roles || [];
    document.querySelectorAll('.role-member-role').forEach(cb => {
      if (cb.value === 'members') { cb.checked = true; return; }
      cb.checked = Boolean(groups.includes(cb.value));
    });
    const storedPosition = item?.committee_position_id || item?.official_position_id || (Array.isArray(item?.assigned_role_ids) ? item.assigned_role_ids[0] : '') || '';
    if (memberPosition) memberPosition.value = storedPosition;
    const storedRole = rolePositionLabel(item) || 'No club role / position stored on this member metadata record.';
    if (memberStoredRole) memberStoredRole.textContent = storedRole;
    if (item) {
      const systemRoles = (item.system_roles || item.groups || []).filter(Boolean).join(', ') || 'members';
      setMemberNotice(`Selected ${item.name || item.email || 'member'}. Stored club role: ${storedRole}. System roles: ${systemRoles}.`);
    }
  }
  posClear?.addEventListener('click', clearPositionForm);
  posSave?.addEventListener('click', async () => {
    const original = posSave.textContent;
    posSave.disabled = true;
    posSave.textContent = 'Saving…';
    try {
      const payload = {
        position_id: posId?.value || '',
        position_name: posName?.value || '',
        email_address: posEmail?.value || '',
        sort_order: posSort?.value || '',
        is_committee_position: posCommittee?.checked !== false,
        active: posActive?.checked !== false
      };
      const data = await memberApiFetch('/admin/positions', { method: 'POST', body: JSON.stringify(payload) });
      setPosNotice(data.message || 'Position saved.');
      clearPositionForm();
      await loadPositions();
    } catch (err) { setPosNotice(`Could not save position: ${err.message}`); }
    finally { posSave.disabled = false; posSave.textContent = original; }
  });
  memberSearch?.addEventListener('change', loadMembers);
  memberSearch?.addEventListener('keydown', event => { if (event.key === 'Enter') loadMembers(); });
  memberSelect?.addEventListener('change', showSelectedMember);
  memberSave?.addEventListener('click', async () => {
    const sub = memberSelect?.value || '';
    if (!sub) { setMemberNotice('Choose a member first.'); return; }
    const roles = Array.from(document.querySelectorAll('.role-member-role')).filter(cb => cb.checked).map(cb => cb.value);
    const original = memberSave.textContent;
    memberSave.disabled = true;
    memberSave.textContent = 'Saving…';
    try {
      const data = await memberApiFetch('/admin/member-roles', { method: 'POST', body: JSON.stringify({ sub, roles, committee_position_id: memberPosition?.value || '' }) });
      setMemberNotice(data.message || 'Member roles saved.');
      if (data.item) {
        const index = members.findIndex(m => m.sub === sub);
        if (index >= 0) members[index] = { ...members[index], ...data.item };
        else members.push(data.item);
        renderMembers();
      }
      if (memberSelect) memberSelect.value = sub;
      showSelectedMember();
      if (typeof syncWebmailNavVisibility === 'function') syncWebmailNavVisibility();
    } catch (err) { setMemberNotice(`Could not save member roles: ${err.message}`); }
    finally { memberSave.disabled = false; memberSave.textContent = original; }
  });
  try { await loadPositions(); } catch (err) { setPosNotice(`Could not load positions: ${err.message}`); }
  try { await loadMembers(); } catch (err) { setMemberNotice(`Could not load members: ${err.message}`); }
}

function wireAdmin(base) {
  const signInBtn = document.getElementById('adminSignInBtn');
  const signOutBtn = document.getElementById('adminSignOutBtn');
  signInBtn?.addEventListener('click', () => window.lrocAuth?.login?.());
  signOutBtn?.addEventListener('click', () => window.lrocAuth?.logout?.());
  if (!window.lrocAuth?.canAccessAdmin?.()) return;
  const desktopSaveBtn = document.getElementById('saveContentBtn');
  const desktopPublishBtn = document.getElementById('publishContentBtn');
  const desktopNavToggle = document.getElementById('adminDesktopNavToggle');
  const mobileToolbar = document.getElementById('editorMobileToolbar');
  const mobileBackBtn = document.getElementById('editorMobileBackBtn');
  const mobilePublishBtn = document.getElementById('mobilePublishContentBtn');
  const mobileMenu = document.getElementById('editorMobileMenu');
  const editorShell = document.querySelector('.editor-shell');
  const editorSubtitle = document.getElementById('editorMobileSubtitle');
  const isMobileEditor = () => window.matchMedia('(max-width: 980px)').matches;
  let currentEditorKey = '';
  let editorBaseline = '';
  let editorIsDirty = false;

  function currentEditorSnapshot() {
    const formData = collectFormData();
    const next = applyFormToContent(formData, getDraftContent(base));
    return JSON.stringify(next);
  }

  function updateDesktopNavToggle() {
    if (!desktopNavToggle || !editorShell) return;
    const collapsed = editorShell.classList.contains('admin-nav-collapsed');
    desktopNavToggle.textContent = collapsed ? 'Show sections' : 'Hide sections';
    desktopNavToggle.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
  }

  function setDesktopNavCollapsed(collapsed) {
    if (!editorShell) return;
    editorShell.classList.toggle('admin-nav-collapsed', Boolean(collapsed));
    try { localStorage.setItem('lroc-admin-nav-collapsed', collapsed ? '1' : '0'); } catch (err) {}
    updateDesktopNavToggle();
  }

  try { setDesktopNavCollapsed(localStorage.getItem('lroc-admin-nav-collapsed') === '1'); } catch (err) { updateDesktopNavToggle(); }
  desktopNavToggle?.addEventListener('click', () => setDesktopNavCollapsed(!editorShell?.classList.contains('admin-nav-collapsed')));

  function updateMobilePublishState() {
    if (!editorIsDirty && editorBaseline) {
      try {
        editorIsDirty = currentEditorSnapshot() !== editorBaseline;
      } catch (err) {}
    }
    const hasChanges = editorIsDirty;
    if (mobilePublishBtn) {
      const showPublish = hasChanges && isMobileEditor() && !!currentEditorKey;
      mobilePublishBtn.classList.toggle('hidden', !showPublish);
      mobilePublishBtn.disabled = !showPublish;
    }
    if (editorSubtitle) {
      const showSubtitle = !!currentEditorKey && !!editorSubtitle.textContent.trim();
      editorSubtitle.classList.toggle('hidden', !showSubtitle);
    }
    if (desktopPublishBtn) desktopPublishBtn.disabled = false;
    if (desktopSaveBtn) desktopSaveBtn.disabled = false;
  }

  function showEditorPane(key) {
    currentEditorKey = key;
    document.querySelectorAll('[data-editor-target]').forEach(b => b.classList.toggle('active', b.dataset.editorTarget === key));
    document.querySelectorAll('[data-editor-pane]').forEach(p => p.classList.toggle('hidden', p.dataset.editorPane !== key));
    if (editorSubtitle) {
      const source = document.querySelector(`[data-editor-target="${key}"]`);
      editorSubtitle.textContent = source?.dataset?.editorLabel || source?.textContent?.trim() || '';
      editorSubtitle.classList.toggle('hidden', !editorSubtitle.textContent.trim());
    }
    if (isMobileEditor()) {
      mobileMenu?.classList.add('hidden');
      editorShell?.classList.add('editor-mobile-detail');
      mobileToolbar?.classList.remove('hidden');
    }
    updateMobilePublishState();
  }

  function showEditorMenu() {
    if (!isMobileEditor()) return;
    currentEditorKey = '';
    mobileMenu?.classList.remove('hidden');
    editorShell?.classList.remove('editor-mobile-detail');
    mobileToolbar?.classList.remove('hidden');
    if (editorSubtitle) {
      editorSubtitle.textContent = '';
      editorSubtitle.classList.add('hidden');
    }
    document.querySelectorAll('[data-editor-pane]').forEach(p => p.classList.add('hidden'));
    document.querySelectorAll('[data-editor-target]').forEach(b => b.classList.remove('active'));
    updateMobilePublishState();
  }

  document.querySelectorAll('[data-editor-target]').forEach(btn => {
    btn.addEventListener('click', () => showEditorPane(btn.dataset.editorTarget));
  });

  mobileBackBtn?.addEventListener('click', () => { if (currentEditorKey) showEditorMenu(); else window.location.href = 'index.html'; });

  const updateEditorUiMode = () => {
    if (isMobileEditor()) {
      if (currentEditorKey) showEditorPane(currentEditorKey);
      else showEditorMenu();
    } else {
      mobileMenu?.classList.remove('hidden');
      editorShell?.classList.remove('editor-mobile-detail');
      mobileToolbar?.classList.add('hidden');
      updateDesktopNavToggle();
      showEditorPane(currentEditorKey || 'site');
    }
  };

  document.querySelectorAll('.editor-pane input[name], .editor-pane textarea[name], .editor-pane select[id], .editor-pane input[id]').forEach(el => {
    const markDirty = () => { editorIsDirty = true; updateMobilePublishState(); };
    el.addEventListener('input', markDirty);
    el.addEventListener('change', markDirty);
  });
  editorBaseline = currentEditorSnapshot();
  editorIsDirty = false;
  updateMobilePublishState();
  window.addEventListener('resize', updateEditorUiMode);
  desktopSaveBtn?.addEventListener('click', () => {
    const formData = collectFormData();
    const next = applyFormToContent(formData, getDraftContent(base));
    saveDraftContent(next);
    alert('Draft content saved in this browser. Export the JSON when you are ready to publish it to S3.');
  });
  const runPublish = async (button) => {
    const formData = collectFormData();
    const next = applyFormToContent(formData, getDraftContent(base));
    saveDraftContent(next);
    if (!memberApiBaseUrl()) {
      alert('Publish is not configured because the member API base URL is missing.');
      return;
    }
    const originalLabel = button.textContent;
    button.disabled = true;
    button.textContent = 'Publishing…';
    try {
      const data = await memberApiFetch('/admin/content/publish', {
        method: 'POST',
        body: JSON.stringify({ content: next })
      });
      resetDraftContent();
      window.__lrocBaseContent = structuredClone(next);
      rememberPublishedContent(next);
      editorBaseline = JSON.stringify(next);
      editorIsDirty = false;
      updateMobilePublishState();
      alert(`Published content.json to the live site${data.published_at ? ` at ${data.published_at}` : ''}.`);
      window.location.reload();
    } catch (err) {
      alert(`Could not publish content.json: ${err.message}`);
    } finally {
      button.disabled = false;
      button.textContent = originalLabel;
    }
  };

  desktopPublishBtn?.addEventListener('click', () => runPublish(desktopPublishBtn));
  mobilePublishBtn?.addEventListener('click', () => runPublish(mobilePublishBtn));



  document.getElementById('exportContentBtn').addEventListener('click', () => {
    const formData = collectFormData();
    const next = applyFormToContent(formData, getDraftContent(base));
    saveDraftContent(next);
    const payload = JSON.stringify(next, null, 2);
    try {
      const blob = new Blob([payload], {type:'application/json'});
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'content.json';
      a.style.display = 'none';
      document.body.appendChild(a);
      a.click();
      setTimeout(() => {
        URL.revokeObjectURL(url);
        a.remove();
      }, 1000);
    } catch (err) {
      const dataUrl = 'data:application/json;charset=utf-8,' + encodeURIComponent(payload);
      const a = document.createElement('a');
      a.href = dataUrl;
      a.download = 'content.json';
      a.style.display = 'none';
      document.body.appendChild(a);
      a.click();
      a.remove();
    }
  });
  const importContentFileInput = document.getElementById('importContentFile');
  importContentFileInput.addEventListener('change', async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const text = await file.text();
    try {
      const data = JSON.parse(text);
      saveDraftContent(data);
      alert('Draft content imported. Refresh or open the site pages to preview it.');
      location.reload();
    } catch {
      alert('That file could not be read as valid JSON.');
    }
  });
  installWebsiteUploadDropZone({
    input: importContentFileInput,
    zone: document.getElementById('importContentDropZone'),
    accept: 'application/json,.json',
    label: 'JSON file'
  });
  document.getElementById('resetContentBtn').addEventListener('click', () => {
    if (!confirm('Discard the browser draft and go back to the published content.json values?')) return;
    resetDraftContent();
    location.reload();
  });

  wireMembershipAdmin().catch(err => console.error('Could not wire membership admin.', err));
  wireEventPdfManager(base).catch(err => console.error('Could not wire event PDF manager.', err));
  wireAdminEmailPage().catch(err => console.error('Could not wire admin email.', err));
  wireRolesPositionsAdmin().catch(err => console.error('Could not wire roles and positions.', err));
  wireVehicleDataAdmin().catch(err => console.error('Could not wire vehicle data admin.', err));
  wireLandRoverPartsAdmin().catch(err => console.error('Could not wire Land Rover parts admin.', err));
  wireEventDataAdmin().catch(err => console.error('Could not wire event data admin.', err));
  Promise.resolve(wireExpoMicrositeAdmin()).catch(err => console.error('Could not wire Expo microsite admin.', err));
  wireTripsAdmin().catch(err => console.error('Could not wire trips/events admin.', err));
  Promise.resolve(wireTripGuidesAdmin()).catch(err => console.error('Could not wire 4WD trips admin.', err));
}

function buildEditorContentSnapshot(base) {
  const formData = collectFormData();
  const next = applyFormToContent(formData, getDraftContent(base));
  saveDraftContent(next);
  return next;
}

async function publishEditorContentNow(content) {
  const data = await memberApiFetch('/admin/content/publish', {
    method: 'POST',
    body: JSON.stringify({ content })
  });
  resetDraftContent();
  window.__lrocBaseContent = structuredClone(content);
  rememberPublishedContent(content);
  return data;
}

function eventPdfLabel(row) {
  return String(row?.details_pdf?.button_label || 'View Info').trim() || 'View Info';
}

function eventPdfHeading(row, idx) {
  return row?.event || row?.details || `Calendar event ${idx + 1}`;
}

function eventPdfMeta(row) {
  return [row?.date || '', row?.location || ''].filter(Boolean).join(' • ');
}

function renderEventPdfManagerRows(rows) {
  if (!rows.length) {
    return '<div class="notice"><strong>No calendar events yet.</strong><div style="margin-top:8px">Add a calendar row above and it will appear here for PDF attachment.</div></div>';
  }
  return rows.map((row, idx) => {
    const pdf = row?.details_pdf || null;
    const uploader = pdf ? (pdf.uploaded_by_name || pdf.uploaded_by || '') : '';
    return `
      <article class="card card-pad small-radius event-pdf-admin-card" data-row-index="${idx}">
        <div style="display:flex;justify-content:space-between;gap:16px;align-items:start;flex-wrap:wrap">
          <div style="flex:1 1 280px">
            <div class="doc-tag">Calendar event ${idx + 1}</div>
            <h3 style="margin:10px 0 6px">${escapeHtml(eventPdfHeading(row, idx))}</h3>
            <div class="muted">${escapeHtml(eventPdfMeta(row) || 'Add a date/location in the calendar rows above.')}</div>
            <div class="muted" style="margin-top:8px">${escapeHtml(row?.details || '')}</div>
          </div>
          <div>${pdf ? '<span class="doc-tag">PDF attached</span>' : '<span class="portal-tag">No PDF attached</span>'}</div>
        </div>
        <div class="form-grid compact-grid" style="margin-top:16px">
          <div class="field">
            <label>Button label</label>
            <input class="event-pdf-label" type="text" value="${escapeHtml(eventPdfLabel(row))}" placeholder="View Info">
          </div>
          <div class="field">
            <label>PDF file</label>
            <input class="event-pdf-file" type="file" accept="application/pdf,.pdf">
            <div class="website-upload-dropzone event-pdf-dropzone" tabindex="0">
              <strong>Website only:</strong> drag a PDF here, or paste a copied PDF file while this box is focused.<br>
              <span data-upload-drop-status>No PDF selected yet.</span>
            </div>
          </div>
          ${pdf ? `
            <div class="notice" style="padding:14px">
              <strong>Current file:</strong> ${escapeHtml(pdf.filename || pdf.title || 'Attached PDF')}
              <div class="muted" style="margin-top:6px">${escapeHtml(pdf.title || 'Event information PDF')}</div>
              <div class="muted" style="margin-top:4px">Uploaded ${escapeHtml(formatIsoDate(pdf.uploaded_at) || 'recently')}${uploader ? ` • by ${escapeHtml(uploader)}` : ''}</div>
            </div>` : '<div class="muted">No PDF is attached to this event yet.</div>'}
          <div class="auth-actions">
            <button class="button event-pdf-upload-btn" type="button">${pdf ? 'Replace PDF' : 'Upload PDF'}</button>
            ${pdf ? '<button class="button secondary event-pdf-save-label-btn" type="button">Save label</button><button class="button ghost event-pdf-remove-btn" type="button">Remove PDF</button>' : ''}
          </div>
          <div class="muted event-pdf-row-notice">${pdf ? 'You can replace the PDF, update the button label, or remove the attachment.' : 'Upload a PDF to add a View Info popup to this event.'}</div>
        </div>
      </article>`;
  }).join('');
}

async function wireEventPdfManager(base) {
  const container = document.getElementById('eventPdfManager');
  const notice = document.getElementById('eventPdfManagerNotice');
  const calendarInput = document.querySelector('textarea[name="pages.events.calendarRows"]');
  if (!container || !notice || !window.lrocAuth?.canAccessAdmin?.()) return;

  const render = () => {
    const snapshot = buildEditorContentSnapshot(base);
    const rows = Array.isArray(snapshot.pages?.events?.calendarRows) ? snapshot.pages.events.calendarRows : [];
    container.innerHTML = renderEventPdfManagerRows(rows);
    container.querySelectorAll('.event-pdf-file').forEach(input => {
      installWebsiteUploadDropZone({
        input,
        zone: input.closest('.field')?.querySelector('.event-pdf-dropzone'),
        accept: 'application/pdf,.pdf',
        label: 'PDF'
      });
    });

    container.querySelectorAll('.event-pdf-upload-btn').forEach(btn => {
      btn.addEventListener('click', async () => {
        const card = btn.closest('[data-row-index]');
        const idx = Number(card?.dataset.rowIndex || '-1');
        const fileInput = card?.querySelector('.event-pdf-file');
        const labelInput = card?.querySelector('.event-pdf-label');
        const rowNotice = card?.querySelector('.event-pdf-row-notice');
        const file = fileInput?.files?.[0];
        if (!Number.isInteger(idx) || idx < 0) return;
        if (!file) { if (rowNotice) rowNotice.textContent = 'Choose a PDF file first.'; return; }
        if ((file.type && file.type !== 'application/pdf') || !file.name.toLowerCase().endsWith('.pdf')) {
          if (rowNotice) rowNotice.textContent = 'Only PDF files are supported.';
          return;
        }
        const original = btn.textContent;
        btn.disabled = true;
        btn.textContent = 'Uploading…';
        if (rowNotice) rowNotice.textContent = 'Requesting a secure upload link…';
        try {
          const snapshot = buildEditorContentSnapshot(base);
          const row = snapshot.pages?.events?.calendarRows?.[idx];
          if (!row) throw new Error('That calendar event could not be found.');
          const oldKey = String(row.details_pdf?.key || '');
          const title = eventPdfHeading(row, idx);
          const prep = await memberApiFetch('/admin/events/info-upload-url', {
            method: 'POST',
            body: JSON.stringify({ title, filename: file.name, content_type: file.type || 'application/pdf', visibility })
          });
          if (rowNotice) rowNotice.textContent = 'Uploading PDF…';
          const putResp = await fetch(prep.upload_url, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/pdf' },
            body: file
          });
          if (!putResp.ok) throw new Error(`Upload failed with ${putResp.status}`);
          row.details_pdf = {
            title: prep.title || title,
            filename: prep.filename || file.name,
            key: prep.key,
            url: prep.public_url,
            uploaded_at: prep.uploaded_at || new Date().toISOString(),
            uploaded_by: prep.uploaded_by || '',
            uploaded_by_name: prep.uploaded_by_name || '',
            button_label: String(labelInput?.value || '').trim() || 'View Info'
          };
          if (rowNotice) rowNotice.textContent = 'Publishing the updated Events page…';
          await publishEditorContentNow(snapshot);
          if (oldKey && oldKey !== prep.key) {
            try {
              await memberApiFetch('/admin/events/info-delete', {
                method: 'POST',
                body: JSON.stringify({ key: oldKey })
              });
            } catch {}
          }
          if (rowNotice) rowNotice.textContent = 'Event info PDF attached and published.';
          render();
        } catch (err) {
          btn.disabled = false;
          btn.textContent = original;
          if (rowNotice) rowNotice.textContent = `Could not attach the PDF: ${err.message}`;
        }
      });
    });

    container.querySelectorAll('.event-pdf-save-label-btn').forEach(btn => {
      btn.addEventListener('click', async () => {
        const card = btn.closest('[data-row-index]');
        const idx = Number(card?.dataset.rowIndex || '-1');
        const labelInput = card?.querySelector('.event-pdf-label');
        const rowNotice = card?.querySelector('.event-pdf-row-notice');
        if (!Number.isInteger(idx) || idx < 0) return;
        const original = btn.textContent;
        btn.disabled = true;
        btn.textContent = 'Saving…';
        if (rowNotice) rowNotice.textContent = 'Saving button label…';
        try {
          const snapshot = buildEditorContentSnapshot(base);
          const row = snapshot.pages?.events?.calendarRows?.[idx];
          if (!row?.details_pdf) throw new Error('This event does not have a PDF attached yet.');
          row.details_pdf.button_label = String(labelInput?.value || '').trim() || 'View Info';
          await publishEditorContentNow(snapshot);
          if (rowNotice) rowNotice.textContent = 'Button label saved.';
          render();
        } catch (err) {
          btn.disabled = false;
          btn.textContent = original;
          if (rowNotice) rowNotice.textContent = `Could not save the label: ${err.message}`;
        }
      });
    });

    container.querySelectorAll('.event-pdf-remove-btn').forEach(btn => {
      btn.addEventListener('click', async () => {
        const card = btn.closest('[data-row-index]');
        const idx = Number(card?.dataset.rowIndex || '-1');
        const rowNotice = card?.querySelector('.event-pdf-row-notice');
        if (!Number.isInteger(idx) || idx < 0) return;
        const snapshot = buildEditorContentSnapshot(base);
        const row = snapshot.pages?.events?.calendarRows?.[idx];
        const title = eventPdfHeading(row, idx);
        const oldKey = String(row?.details_pdf?.key || '');
        if (!oldKey) { if (rowNotice) rowNotice.textContent = 'There is no PDF attached to remove.'; return; }
        if (!window.confirm(`Remove the event info PDF for ${title}?`)) return;
        const original = btn.textContent;
        btn.disabled = true;
        btn.textContent = 'Removing…';
        if (rowNotice) rowNotice.textContent = 'Removing the event info PDF…';
        try {
          delete row.details_pdf;
          await publishEditorContentNow(snapshot);
          try {
            await memberApiFetch('/admin/events/info-delete', {
              method: 'POST',
              body: JSON.stringify({ key: oldKey })
            });
          } catch {}
          if (rowNotice) rowNotice.textContent = 'Event info PDF removed.';
          render();
        } catch (err) {
          btn.disabled = false;
          btn.textContent = original;
          if (rowNotice) rowNotice.textContent = `Could not remove the PDF: ${err.message}`;
        }
      });
    });
  };

  calendarInput?.addEventListener('input', render);
  calendarInput?.addEventListener('change', render);
  render();
}
