  magazineApplySourceDocumentLayoutFromPage = async function(page = {}) {
    if (!magazineState.selectedIssueId) throw new Error('Open an issue first.');
    const current = magazineInteriorPreviewPageFromEditor(page);
    const settings0 = mag310SettingsFromEditor(current, mag310ContentForPage(current) || {});
    const contentId = settings0.contentItemId || mag310PrimaryContentIdForPage(current) || mag310PrimaryContentIdForPage(page);
    if (!contentId) throw new Error('Choose the imported article/document content item on the starting page first.');
    const item = magazineContentById(contentId);
    if (!item) throw new Error('Content item was not found.');
    const body = magazineContentBodyWithoutRepeatedTitle(item) || magazineContentSourcePages(item).map(p => p.bodyMarkdown || '').filter(Boolean).join('\n\n');
    if (!body.trim() && !magazineContentSourcePages(item).length) throw new Error('This content has no extractable source plan yet. Use Extract/refresh source first.');
    const issue = magazineState.selectedIssue || {};
    const lastInterior = Math.max(2, Number(issue.pageCount || 0) - 1);
    const startPage = Number(current.pageNumber || page.pageNumber || 0);
    if (!startPage || startPage >= lastInterior) throw new Error('Source layout import needs an interior starting page before the back cover.');
    if (current.locked) throw new Error('Unlock the starting page before applying source document placement. Locked pages are skipped and left untouched.');
    const settings = { ...settings0, startPage };
    const compositionPages = mag310BuildCompositionPages(item, settings);
    if (!compositionPages.length) throw new Error('No document pages could be built from this content.');
    settings.pageCount = compositionPages.length;
    const pages = mag310Pages();
    const assigned = [];
    const skipped = [];
    let n = startPage;
    for (let i = 0; i < compositionPages.length && n <= lastInterior; i += 1) {
      while (n <= lastInterior) {
        const existing = n === startPage ? current : (pages.find(p => Number(p.pageNumber || 0) === n) || { pageNumber: n });
        if (existing.locked || ['front_cover','back_cover_ad'].includes(String(existing.pageType || ''))) { skipped.push(n); n += 1; continue; }
        break;
      }
      if (n > lastInterior) break;
      const existingPage = n === startPage ? current : (pages.find(p => Number(p.pageNumber || 0) === n) || { pageNumber: n, layoutSlots: [] });
      const slots = mag310SourceLayoutSlotsForPage(item, compositionPages[i], i, settings, existingPage);
      const payload = {
        issueId: magazineState.selectedIssueId,
        pageNumber: n,
        pageType: magazineSourceLayoutPageTypeForContent(item),
        templateId: compositionPages[i]?.isPdfPage || compositionPages[i]?.sourcePageKind === 'pdf_page' ? 'source_document_camera_page' : (slots.some(s => s.slotType === 'image' && s.assetId) ? 'source_document_image_page' : 'source_document_text_page'),
        locked: false,
        notes: `Document composition page ${i + 1} of ${compositionPages.length} from ${item.sourceFileName || item.title || 'content'}.`,
        layoutSlots: slots,
        contentSlots: [],
        resetPage: true
      };
      const data = await memberApiFetch('/member/magazine/flatplan/page', { method: 'POST', body: JSON.stringify(payload) });
      magazineState.selectedFlatplan = data.flatplan || magazineState.selectedFlatplan;
      assigned.push(n);
      n += 1;
    }
    if (!assigned.length) throw new Error('No unlocked interior pages were available for the source document.');
    await memberApiFetch('/member/magazine/content', { method: 'POST', body: JSON.stringify({
      ...item,
      issueId: magazineState.selectedIssueId,
      assignedPageNumbers: assigned,
      placementStatus: assigned.length < compositionPages.length ? 'partially_placed' : 'placed',
      publicationStatus: 'in_issue',
      preferredPageCount: compositionPages.length,
      sourcePageCount: compositionPages.length,
      sourceLayoutStatus: 'composition_applied',
      documentColumns: settings.columns,
      articleFontSize: settings.fontSize,
      articleLineHeight: settings.lineHeight,
      documentImagePolicy: settings.imagePolicy
    }) });
    await magazineLoadContent(magazineState.selectedIssueId);
    magazineRenderFlatplan();
    magazineShowPagePreview(assigned[0]);
    const remaining = compositionPages.length - assigned.length;
    showToast(`Applied document composition to page${assigned.length === 1 ? '' : 's'} ${assigned.join(', ')}.${skipped.length ? ` Skipped locked/fixed ${skipped.join(', ')}.` : ''}${remaining > 0 ? ` ${remaining} page(s) still need unlocked space.` : ''}`);
  };

